@dataclass(frozen=True)
class CouncilProposal:
    name: str
    scores: dict[str, float]
    next_action: str

    @property
    def average(self) -> float:
        return float(sum(self.scores.values()) / max(1, len(self.scores)))

    @property
    def minimum(self) -> float:
        return float(min(self.scores.values())) if self.scores else 0.0


