def run_c001_representation_error_audit(args: argparse.Namespace, train_bundle, eval_bundle, floor_delta: np.ndarray, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/C001_representation_error_audit"
    out.mkdir(parents=True, exist_ok=True)
    eval_meta = eval_bundle.metadata.reset_index(drop=True)
    pred_endpoint = eval_bundle.source + floor_delta
    target = eval_bundle.target
    source = eval_bundle.source
    teacher_delta = eval_bundle.delta
    floor_error = pred_endpoint - target
    action_rows: list[dict[str, Any]] = []
    for action_id, indices in eval_meta.groupby("perturbation_id").indices.items():
        idx = np.asarray(indices, dtype=int)
        source_online = eval_bundle.arrays["source_z_bio_online"][idx].astype(np.float64)
        target_online = eval_bundle.arrays["target_z_bio_online"][idx].astype(np.float64)
        source_teacher = eval_bundle.arrays["source_z_bio_teacher"][idx].astype(np.float64)
        target_teacher = eval_bundle.arrays["target_z_bio_teacher"][idx].astype(np.float64)
        ztech_delta = eval_bundle.arrays["target_z_tech_teacher"][idx].astype(np.float64) - eval_bundle.arrays["source_z_tech_teacher"][idx].astype(np.float64)
        metrics = bundle_transition_metrics(_subset_bundle(eval_bundle, idx, f"action_{action_id}"), floor_delta[idx])
        action_rows.append(
            {
                "perturbation_id": str(action_id),
                "rows": int(idx.size),
                "transition_improvement": metrics["transition_source_cosine_improvement"],
                "delta_cosine": metrics["delta_cosine"],
                "recall_at_1": metrics["transition_to_target_recall@1"],
                "floor_error_norm": float(np.linalg.norm(floor_error[idx], axis=1).mean()),
                "teacher_delta_norm": float(np.linalg.norm(teacher_delta[idx], axis=1).mean()),
                "source_online_teacher_cosine": float(_row_cosine_numpy(source_online, source_teacher).mean()),
                "target_online_teacher_cosine": float(_row_cosine_numpy(target_online, target_teacher).mean()),
                "ztech_delta_norm": float(np.linalg.norm(ztech_delta, axis=1).mean()),
                "floor_error_vs_teacher_delta_cosine": float(_row_cosine_numpy(floor_error[idx], teacher_delta[idx]).mean()),
                "floor_error_vs_ztech_delta_abs_corr": _safe_abs_corr(np.linalg.norm(floor_error[idx], axis=1), np.linalg.norm(ztech_delta, axis=1)),
            }
        )
    action_frame = pd.DataFrame(action_rows).sort_values("transition_improvement")
    action_frame.to_csv(out / "action_representation_error.tsv", sep="\t", index=False)
    global_metrics = {
        "source_online_teacher_cosine": float(_row_cosine_numpy(eval_bundle.arrays["source_z_bio_online"].astype(np.float64), eval_bundle.arrays["source_z_bio_teacher"].astype(np.float64)).mean()),
        "target_online_teacher_cosine": float(_row_cosine_numpy(eval_bundle.arrays["target_z_bio_online"].astype(np.float64), eval_bundle.arrays["target_z_bio_teacher"].astype(np.float64)).mean()),
        "source_teacher_effective_rank": effective_rank(source),
        "target_teacher_effective_rank": effective_rank(target),
        "teacher_delta_effective_rank": effective_rank(teacher_delta),
        "floor_error_effective_rank": effective_rank(floor_error),
        "floor_error_norm_mean": float(np.linalg.norm(floor_error, axis=1).mean()),
        "teacher_delta_norm_mean": float(np.linalg.norm(teacher_delta, axis=1).mean()),
        "ztech_delta_norm_mean": float(
            np.linalg.norm(eval_bundle.arrays["target_z_tech_teacher"].astype(np.float64) - eval_bundle.arrays["source_z_tech_teacher"].astype(np.float64), axis=1).mean()
        ),
    }
    lowest = action_frame.iloc[0].to_dict() if not action_frame.empty else {}
    highest = action_frame.iloc[-1].to_dict() if not action_frame.empty else {}
    summary = {
        "diagnostic_label": "C001_REPRESENTATION_ERROR_AUDIT_COMPLETED",
        "global_metrics": global_metrics,
        "lowest_transition_action": str(lowest.get("perturbation_id", "")),
        "highest_transition_action": str(highest.get("perturbation_id", "")),
        "lowest_action_floor_error_norm": float(lowest.get("floor_error_norm", 0.0)),
        "highest_action_floor_error_norm": float(highest.get("floor_error_norm", 0.0)),
        "rows": action_rows,
    }
    write_json(out / "metrics_eval.json", summary)
    append_journal(
        args.output_root,
        "C001_REPRESENTATION_ERROR_AUDIT",
        "Family C diagnostic",
        "Audited online/teacher consistency, latent rank, floor-error direction, and z_tech coupling by held-out action.",
    )
    return {
        "experiment_id": "C001",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "representation_error_audit",
        "status_label": "C001_REPRESENTATION_ERROR_AUDIT_COMPLETED",
        "transition_improvement": f"{floor_metrics['transition_source_cosine_improvement']:.6f}",
        "delta_cosine": f"{floor_metrics['delta_cosine']:.6f}",
        "recall_at_1": f"{floor_metrics['transition_to_target_recall@1']:.6f}",
        "median_rank": f"{floor_metrics.get('transition_to_target_median_rank', 0.0):.6f}",
        "delta_rank": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "magnitude_ratio": f"{floor_metrics['delta_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{global_metrics['target_teacher_effective_rank']:.6f}",
        "effective_rank_target": f"{global_metrics['target_teacher_effective_rank']:.6f}",
        "collapse_flag": str(global_metrics["target_teacher_effective_rank"] < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": "0.000000",
        "floor_gap_recall": "0.000000",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": "0.000000",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": f"Representation error audit; lowest_transition_action={summary['lowest_transition_action']}.",
        "artifact_dir": str(out),
    }


def run_c002_delta_manifold_support(args: argparse.Namespace, train_bundle, eval_bundle, floor_delta: np.ndarray, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/C002_delta_manifold_support"
    out.mkdir(parents=True, exist_ok=True)
    train_meta = train_bundle.metadata.reset_index(drop=True)
    eval_meta = eval_bundle.metadata.reset_index(drop=True)
    train_delta_means: dict[str, np.ndarray] = {}
    for action_id, indices in train_meta.groupby("perturbation_id").indices.items():
        idx = np.asarray(indices, dtype=int)
        train_delta_means[str(action_id)] = train_bundle.delta[idx].mean(axis=0)
    rows: list[dict[str, Any]] = []
    for action_id, indices in eval_meta.groupby("perturbation_id").indices.items():
        idx = np.asarray(indices, dtype=int)
        eval_delta_mean = eval_bundle.delta[idx].mean(axis=0)
        distances = {key: float(np.linalg.norm(eval_delta_mean - value)) for key, value in train_delta_means.items()}
        cosines = {key: float(_vector_cosine(eval_delta_mean, value)) for key, value in train_delta_means.items()}
        nearest_by_l2 = min(distances, key=distances.get)
        nearest_by_cos = max(cosines, key=cosines.get)
        sample = _subset_bundle(eval_bundle, idx, f"delta_support_{action_id}")
        metrics = bundle_transition_metrics(sample, floor_delta[idx])
        train_neighbor = train_delta_means[nearest_by_l2]
        rows.append(
            {
                "eval_perturbation_id": str(action_id),
                "rows": int(idx.size),
                "nearest_train_action_by_l2": nearest_by_l2,
                "nearest_train_delta_l2": distances[nearest_by_l2],
                "nearest_train_action_by_cosine": nearest_by_cos,
                "nearest_train_delta_cosine": cosines[nearest_by_cos],
                "eval_delta_norm": float(np.linalg.norm(eval_delta_mean)),
                "nearest_train_delta_norm": float(np.linalg.norm(train_neighbor)),
                "transition_improvement": metrics["transition_source_cosine_improvement"],
                "delta_cosine": metrics["delta_cosine"],
                "recall_at_1": metrics["transition_to_target_recall@1"],
            }
        )
    frame = pd.DataFrame(rows).sort_values("transition_improvement")
    frame.to_csv(out / "delta_manifold_support.tsv", sep="\t", index=False)
    corr_l2 = float(frame[["nearest_train_delta_l2", "transition_improvement"]].corr().iloc[0, 1]) if len(frame) > 1 else 0.0
    corr_cos = float(frame[["nearest_train_delta_cosine", "transition_improvement"]].corr().iloc[0, 1]) if len(frame) > 1 else 0.0
    if not np.isfinite(corr_l2):
        corr_l2 = 0.0
    if not np.isfinite(corr_cos):
        corr_cos = 0.0
    summary = {
        "diagnostic_label": "C002_LATENT_DELTA_MANIFOLD_SUPPORT_AUDIT_COMPLETED",
        "distance_transition_corr": corr_l2,
        "cosine_transition_corr": corr_cos,
        "lowest_transition_action": str(frame.iloc[0]["eval_perturbation_id"]) if not frame.empty else "",
        "rows": rows,
    }
    write_json(out / "metrics_eval.json", summary)
    append_journal(
        args.output_root,
        "C002_LATENT_DELTA_MANIFOLD_SUPPORT_AUDIT",
        "Family C diagnostic",
        "Compared held-out action response deltas to train action delta manifolds using only train delta support as the reference.",
    )
    return {
        "experiment_id": "C002",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "latent_delta_manifold_support_audit",
        "status_label": "C002_LATENT_DELTA_MANIFOLD_SUPPORT_AUDIT_COMPLETED",
        "transition_improvement": f"{floor_metrics['transition_source_cosine_improvement']:.6f}",
        "delta_cosine": f"{floor_metrics['delta_cosine']:.6f}",
        "recall_at_1": f"{floor_metrics['transition_to_target_recall@1']:.6f}",
        "median_rank": f"{floor_metrics.get('transition_to_target_median_rank', 0.0):.6f}",
        "delta_rank": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "magnitude_ratio": f"{floor_metrics['delta_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": "0.000000",
        "floor_gap_recall": "0.000000",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{corr_l2:.6f}",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": f"Delta manifold support audit; lowest_transition_action={summary['lowest_transition_action']}.",
        "artifact_dir": str(out),
    }


def run_c003_train_only_delta_support(args: argparse.Namespace, train_bundle, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/C003_train_only_delta_support"
    out.mkdir(parents=True, exist_ok=True)
    metadata = train_bundle.metadata.reset_index(drop=True)
    rows: list[dict[str, Any]] = []
    all_indices = np.arange(train_bundle.source.shape[0])
    for action_id, indices in metadata.groupby("perturbation_id").indices.items():
        heldout = np.asarray(indices, dtype=int)
        fit_indices = np.setdiff1d(all_indices, heldout)
        fit_bundle = _subset_bundle(train_bundle, fit_indices, "fit")
        heldout_bundle = _subset_bundle(train_bundle, heldout, "heldout")
        fit_meta = fit_bundle.metadata.reset_index(drop=True)
        delta_means = {
            str(train_action): fit_bundle.delta[np.asarray(train_indices, dtype=int)].mean(axis=0)
            for train_action, train_indices in fit_meta.groupby("perturbation_id").indices.items()
        }
        heldout_delta_mean = heldout_bundle.delta.mean(axis=0)
        distances = {key: float(np.linalg.norm(heldout_delta_mean - value)) for key, value in delta_means.items()}
        cosines = {key: float(_vector_cosine(heldout_delta_mean, value)) for key, value in delta_means.items()}
        nearest_l2 = min(distances, key=distances.get)
        nearest_cos = max(cosines, key=cosines.get)
        ridge = fit_ridge_numpy(bundle_features(fit_bundle), fit_bundle.delta, alpha=1.0e-2)
        pred_delta = predict_ridge_numpy(ridge, bundle_features(heldout_bundle))
        metrics = bundle_transition_metrics(heldout_bundle, pred_delta)
        rows.append(
            {
                "left_out_perturbation_id": str(action_id),
                "rows": int(heldout.size),
                "nearest_train_action_by_l2": nearest_l2,
                "nearest_train_delta_l2": distances[nearest_l2],
                "nearest_train_action_by_cosine": nearest_cos,
                "nearest_train_delta_cosine": cosines[nearest_cos],
                "heldout_delta_norm": float(np.linalg.norm(heldout_delta_mean)),
                "transition_improvement": metrics["transition_source_cosine_improvement"],
                "delta_cosine": metrics["delta_cosine"],
                "recall_at_1": metrics["transition_to_target_recall@1"],
            }
        )
    frame = pd.DataFrame(rows).sort_values("transition_improvement")
    frame.to_csv(out / "train_only_delta_support.tsv", sep="\t", index=False)
    corr_cos = float(frame[["nearest_train_delta_cosine", "transition_improvement"]].corr().iloc[0, 1]) if len(frame) > 1 else 0.0
    corr_l2 = float(frame[["nearest_train_delta_l2", "transition_improvement"]].corr().iloc[0, 1]) if len(frame) > 1 else 0.0
    if not np.isfinite(corr_cos):
        corr_cos = 0.0
    if not np.isfinite(corr_l2):
        corr_l2 = 0.0
    summary = {
        "diagnostic_label": "C003_TRAIN_ONLY_DELTA_SUPPORT_AUDIT_COMPLETED",
        "cosine_transition_corr": corr_cos,
        "distance_transition_corr": corr_l2,
        "negative_action_groups": int((frame["transition_improvement"] <= 0.0).sum()) if not frame.empty else 0,
        "rows": rows,
    }
    write_json(out / "metrics_eval.json", summary)
    append_journal(
        args.output_root,
        "C003_TRAIN_ONLY_DELTA_SUPPORT_AUDIT",
        "Family C diagnostic",
        "Checked whether train-only leave-action-out floor failures align with weak latent delta support from remaining train actions.",
    )
    return {
        "experiment_id": "C003",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "train_only_delta_support_audit",
        "status_label": "C003_TRAIN_ONLY_DELTA_SUPPORT_AUDIT_COMPLETED",
        "transition_improvement": f"{floor_metrics['transition_source_cosine_improvement']:.6f}",
        "delta_cosine": f"{floor_metrics['delta_cosine']:.6f}",
        "recall_at_1": f"{floor_metrics['transition_to_target_recall@1']:.6f}",
        "median_rank": f"{floor_metrics.get('transition_to_target_median_rank', 0.0):.6f}",
        "delta_rank": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "magnitude_ratio": f"{floor_metrics['delta_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": "0.000000",
        "floor_gap_recall": "0.000000",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{corr_cos:.6f}",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": f"Train-only delta support audit; negative_action_groups={summary['negative_action_groups']}.",
        "artifact_dir": str(out),
    }


def run_e001_action_prior_sufficiency(args: argparse.Namespace, train_bundle, eval_bundle, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/E001_action_prior_sufficiency"
    out.mkdir(parents=True, exist_ok=True)
    train_meta = train_bundle.metadata.reset_index(drop=True)
    all_indices = np.arange(train_bundle.source.shape[0])
    loao_rows: list[dict[str, Any]] = []
    for action_id, indices in train_meta.groupby("perturbation_id").indices.items():
        heldout = np.asarray(indices, dtype=int)
        fit_indices = np.setdiff1d(all_indices, heldout)
        fit_bundle = _subset_bundle(train_bundle, fit_indices, "fit")
        heldout_bundle = _subset_bundle(train_bundle, heldout, "heldout")
        for baseline_name, fit_x, heldout_x in _baseline_feature_sets(fit_bundle, heldout_bundle):
            ridge = fit_ridge_numpy(fit_x, fit_bundle.delta, alpha=1.0e-2)
            pred_delta = predict_ridge_numpy(ridge, heldout_x)
            metrics = bundle_transition_metrics(heldout_bundle, pred_delta)
            loao_rows.append(
                {
                    "left_out_perturbation_id": str(action_id),
                    "baseline": baseline_name,
                    "rows": int(heldout.size),
                    "transition_improvement": metrics["transition_source_cosine_improvement"],
                    "delta_cosine": metrics["delta_cosine"],
                    "recall_at_1": metrics["transition_to_target_recall@1"],
                    "median_rank": metrics["transition_to_target_median_rank"],
                }
            )
    loao_frame = pd.DataFrame(loao_rows)
    loao_frame.to_csv(out / "train_only_leave_action_out_baselines.tsv", sep="\t", index=False)
    heldout_rows: list[dict[str, Any]] = []
    for baseline_name, train_x, eval_x in _baseline_feature_sets(train_bundle, eval_bundle):
        ridge = fit_ridge_numpy(train_x, train_bundle.delta, alpha=1.0e-2)
        pred_delta = predict_ridge_numpy(ridge, eval_x)
        metrics = bundle_transition_metrics(eval_bundle, pred_delta)
        heldout_rows.append(
            {
                "baseline": baseline_name,
                "transition_improvement": metrics["transition_source_cosine_improvement"],
                "delta_cosine": metrics["delta_cosine"],
                "recall_at_1": metrics["transition_to_target_recall@1"],
                "median_rank": metrics["transition_to_target_median_rank"],
                "delta_rank": metrics["delta_prediction_effective_rank"],
                "magnitude_ratio": metrics["delta_magnitude_ratio"],
            }
        )
    heldout_frame = pd.DataFrame(heldout_rows).sort_values("transition_improvement", ascending=False)
    heldout_frame.to_csv(out / "heldout_baselines.tsv", sep="\t", index=False)
    loao_summary = (
        loao_frame.groupby("baseline", as_index=False)
        .agg(
            mean_transition_improvement=("transition_improvement", "mean"),
            min_transition_improvement=("transition_improvement", "min"),
            negative_action_groups=("transition_improvement", lambda values: int((values <= 0.0).sum())),
            mean_delta_cosine=("delta_cosine", "mean"),
            mean_recall_at_1=("recall_at_1", "mean"),
        )
        .sort_values("mean_transition_improvement", ascending=False)
    )
    loao_summary.to_csv(out / "train_only_leave_action_out_summary.tsv", sep="\t", index=False)
    best_heldout = heldout_frame.iloc[0].to_dict() if not heldout_frame.empty else {}
    summary = {
        "diagnostic_label": "E001_ACTION_PRIOR_SUFFICIENCY_AUDIT_COMPLETED",
        "best_heldout_baseline": str(best_heldout.get("baseline", "")),
        "best_heldout_transition": float(best_heldout.get("transition_improvement", 0.0)),
        "loao_summary": loao_summary.to_dict("records"),
        "heldout_rows": heldout_rows,
    }
    write_json(out / "metrics_eval.json", summary)
    append_journal(
        args.output_root,
        "E001_ACTION_PRIOR_SUFFICIENCY_AUDIT",
        "Family E diagnostic",
        "Compared source-only, action-only, and source+action ridge floors under train-only leave-action-out and held-out scoring.",
    )
    return {
        "experiment_id": "E001",
        "phase": "PostPhase8Council",
        "family": "Program and graph action priors",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "action_prior_sufficiency_audit",
        "status_label": "E001_ACTION_PRIOR_SUFFICIENCY_AUDIT_COMPLETED",
        "transition_improvement": f"{float(best_heldout.get('transition_improvement', floor_metrics['transition_source_cosine_improvement'])):.6f}",
        "delta_cosine": f"{float(best_heldout.get('delta_cosine', floor_metrics['delta_cosine'])):.6f}",
        "recall_at_1": f"{float(best_heldout.get('recall_at_1', floor_metrics['transition_to_target_recall@1'])):.6f}",
        "median_rank": f"{float(best_heldout.get('median_rank', floor_metrics.get('transition_to_target_median_rank', 0.0))):.6f}",
        "delta_rank": f"{float(best_heldout.get('delta_rank', floor_metrics['delta_prediction_effective_rank'])):.6f}",
        "magnitude_ratio": f"{float(best_heldout.get('magnitude_ratio', floor_metrics['delta_magnitude_ratio'])):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": f"{float(best_heldout.get('transition_improvement', 0.0)) - floor_metrics['transition_source_cosine_improvement']:.6f}",
        "floor_gap_recall": f"{float(best_heldout.get('recall_at_1', 0.0)) - floor_metrics['transition_to_target_recall@1']:.6f}",
        "floor_gap_delta_cosine": f"{float(best_heldout.get('delta_cosine', 0.0)) - floor_metrics['delta_cosine']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": "0.000000",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": f"Action prior sufficiency audit; best_heldout_baseline={summary['best_heldout_baseline']}.",
        "artifact_dir": str(out),
    }


def run_e002_source_action_blend(args: argparse.Namespace, train_bundle, eval_bundle, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/E002_source_action_blend"
    out.mkdir(parents=True, exist_ok=True)
    alphas = np.asarray([0.0, 0.05, 0.1, 0.2, 0.35, 0.5, 0.75, 1.0], dtype=np.float64)
    train_meta = train_bundle.metadata.reset_index(drop=True)
    all_indices = np.arange(train_bundle.source.shape[0])
    fold_rows: list[dict[str, Any]] = []
    for action_id, indices in train_meta.groupby("perturbation_id").indices.items():
        heldout = np.asarray(indices, dtype=int)
        fit_indices = np.setdiff1d(all_indices, heldout)
        fit_bundle = _subset_bundle(train_bundle, fit_indices, "fit")
        heldout_bundle = _subset_bundle(train_bundle, heldout, "heldout")
        source_ridge = fit_ridge_numpy(fit_bundle.source, fit_bundle.delta, alpha=1.0e-2)
        full_ridge = fit_ridge_numpy(bundle_features(fit_bundle), fit_bundle.delta, alpha=1.0e-2)
        source_delta = predict_ridge_numpy(source_ridge, heldout_bundle.source)
        full_delta = predict_ridge_numpy(full_ridge, bundle_features(heldout_bundle))
        full_metrics = bundle_transition_metrics(heldout_bundle, full_delta)
        for alpha in alphas:
            pred_delta = (1.0 - float(alpha)) * full_delta + float(alpha) * source_delta
            metrics = bundle_transition_metrics(heldout_bundle, pred_delta)
            fold_rows.append(
                {
                    "left_out_perturbation_id": str(action_id),
                    "alpha_source_only": float(alpha),
                    "transition_gap_vs_full": metrics["transition_source_cosine_improvement"] - full_metrics["transition_source_cosine_improvement"],
                    "recall_gap_vs_full": metrics["transition_to_target_recall@1"] - full_metrics["transition_to_target_recall@1"],
                    "delta_cosine_gap_vs_full": metrics["delta_cosine"] - full_metrics["delta_cosine"],
                    "transition_improvement": metrics["transition_source_cosine_improvement"],
                    "recall_at_1": metrics["transition_to_target_recall@1"],
                    "delta_cosine": metrics["delta_cosine"],
                }
            )
    fold_frame = pd.DataFrame(fold_rows)
    fold_frame.to_csv(out / "train_only_blend_folds.tsv", sep="\t", index=False)
    summary_rows = (
        fold_frame.groupby("alpha_source_only", as_index=False)
        .agg(
            mean_transition_gap=("transition_gap_vs_full", "mean"),
            min_transition_gap=("transition_gap_vs_full", "min"),
            mean_recall_gap=("recall_gap_vs_full", "mean"),
            min_recall_gap=("recall_gap_vs_full", "min"),
            mean_delta_cosine_gap=("delta_cosine_gap_vs_full", "mean"),
            min_delta_cosine_gap=("delta_cosine_gap_vs_full", "min"),
        )
        .sort_values("alpha_source_only")
    )
    summary_rows.to_csv(out / "train_only_blend_summary.tsv", sep="\t", index=False)
    passing = summary_rows[
        (summary_rows["mean_transition_gap"] >= 0.0001)
        & (summary_rows["min_recall_gap"] >= -0.05)
        & (summary_rows["mean_delta_cosine_gap"] >= 0.0)
    ]
    if passing.empty:
        selected_alpha = 0.0
        decision = "E002_BLEND_REJECTED_KEEP_FULL_FLOOR"
    else:
        selected_alpha = float(passing.sort_values(["mean_transition_gap", "mean_recall_gap"], ascending=False).iloc[0]["alpha_source_only"])
        decision = "E002_BLEND_SELECTED_DIAGNOSTIC_ONLY"
    source_ridge = fit_ridge_numpy(train_bundle.source, train_bundle.delta, alpha=1.0e-2)
    full_ridge = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
    source_eval_delta = predict_ridge_numpy(source_ridge, eval_bundle.source)
    full_eval_delta = predict_ridge_numpy(full_ridge, bundle_features(eval_bundle))
    eval_delta = (1.0 - selected_alpha) * full_eval_delta + selected_alpha * source_eval_delta
    eval_metrics = bundle_transition_metrics(eval_bundle, eval_delta)
    summary = {
        "diagnostic_label": decision,
        "selected_alpha_source_only": selected_alpha,
        "eval_metrics": eval_metrics,
        "train_only_summary": summary_rows.to_dict("records"),
    }
    write_json(out / "metrics_eval.json", summary)
    append_journal(
        args.output_root,
        "E002_TRAIN_ONLY_SOURCE_ACTION_BLEND_AUDIT",
        "Family E diagnostic",
        f"Train-only calibrated source/action floor blend selected alpha={selected_alpha:.2f}; decision={decision}.",
    )
    return {
        "experiment_id": "E002",
        "phase": "PostPhase8Council",
        "family": "Program and graph action priors",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "source_action_blend_audit",
        "status_label": decision,
        "transition_improvement": f"{eval_metrics['transition_source_cosine_improvement']:.6f}",
        "delta_cosine": f"{eval_metrics['delta_cosine']:.6f}",
        "recall_at_1": f"{eval_metrics['transition_to_target_recall@1']:.6f}",
        "median_rank": f"{eval_metrics.get('transition_to_target_median_rank', 0.0):.6f}",
        "delta_rank": f"{eval_metrics['delta_prediction_effective_rank']:.6f}",
        "magnitude_ratio": f"{eval_metrics['delta_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{eval_metrics['delta_prediction_effective_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": f"{eval_metrics['transition_source_cosine_improvement'] - floor_metrics['transition_source_cosine_improvement']:.6f}",
        "floor_gap_recall": f"{eval_metrics['transition_to_target_recall@1'] - floor_metrics['transition_to_target_recall@1']:.6f}",
        "floor_gap_delta_cosine": f"{eval_metrics['delta_cosine'] - floor_metrics['delta_cosine']:.6f}",
        "selected_residual_scale": f"{selected_alpha:.6f}",
        "calibration_lcb_transition_gap": "0.000000",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": f"Source/action blend diagnostic; alpha_source_only={selected_alpha:.2f}; no promotion.",
        "artifact_dir": str(out),
    }


def run_d001_prototype_transition(args: argparse.Namespace, train_bundle, eval_bundle, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/D001_prototype_transition"
    out.mkdir(parents=True, exist_ok=True)
    prototype_count = 6
    centers = _kmeans_centers(train_bundle.source, prototype_count, seed=0, steps=25)
    train_proto = _assign_centers(train_bundle.source, centers)
    eval_proto = _assign_centers(eval_bundle.source, centers)
    train_features = np.concatenate((np.eye(prototype_count)[train_proto], train_bundle.action), axis=1)
    eval_features = np.concatenate((np.eye(prototype_count)[eval_proto], eval_bundle.action), axis=1)
    ridge = fit_ridge_numpy(train_features, train_bundle.delta, alpha=1.0e-2)
    pred_delta = predict_ridge_numpy(ridge, eval_features)
    eval_metrics = bundle_transition_metrics(eval_bundle, pred_delta)
    action_rows: list[dict[str, Any]] = []
    eval_meta = eval_bundle.metadata.reset_index(drop=True)
    for action_id, indices in eval_meta.groupby("perturbation_id").indices.items():
        idx = np.asarray(indices, dtype=int)
        sample = _subset_bundle(eval_bundle, idx, f"proto_{action_id}")
        metrics = bundle_transition_metrics(sample, pred_delta[idx])
        action_rows.append(
            {
                "perturbation_id": str(action_id),
                "rows": int(idx.size),
                "transition_improvement": metrics["transition_source_cosine_improvement"],
                "delta_cosine": metrics["delta_cosine"],
                "recall_at_1": metrics["transition_to_target_recall@1"],
                "median_rank": metrics["transition_to_target_median_rank"],
            }
        )
    pd.DataFrame(action_rows).sort_values("transition_improvement").to_csv(out / "action_prototype_transition.tsv", sep="\t", index=False)
    coverage = pd.Series(eval_proto).value_counts().sort_index().to_dict()
    summary = {
        "diagnostic_label": "D001_PROTOTYPE_TRANSITION_DIAGNOSTIC_COMPLETED",
        "prototype_count": prototype_count,
        "eval_prototype_coverage": {str(key): int(value) for key, value in coverage.items()},
        "eval_metrics": eval_metrics,
        "action_rows": action_rows,
    }
    write_json(out / "metrics_eval.json", summary)
    append_journal(
        args.output_root,
        "D001_PROTOTYPE_TRANSITION_DIAGNOSTIC",
        "Family D diagnostic",
        "Fit a train-only source-prototype plus action ridge transition to test whether population/prototype state helps the held-out failure mode.",
    )
    return {
        "experiment_id": "D001",
        "phase": "PostPhase8Council",
        "family": "Population transport JEPA",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "prototype_transition_diagnostic",
        "status_label": "D001_PROTOTYPE_TRANSITION_DIAGNOSTIC_COMPLETED",
        "transition_improvement": f"{eval_metrics['transition_source_cosine_improvement']:.6f}",
        "delta_cosine": f"{eval_metrics['delta_cosine']:.6f}",
        "recall_at_1": f"{eval_metrics['transition_to_target_recall@1']:.6f}",
        "median_rank": f"{eval_metrics.get('transition_to_target_median_rank', 0.0):.6f}",
        "delta_rank": f"{eval_metrics['delta_prediction_effective_rank']:.6f}",
        "magnitude_ratio": f"{eval_metrics['delta_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{eval_metrics['delta_prediction_effective_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": str(eval_metrics["delta_prediction_effective_rank"] < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{eval_metrics['transition_source_cosine_improvement'] - floor_metrics['transition_source_cosine_improvement']:.6f}",
        "floor_gap_recall": f"{eval_metrics['transition_to_target_recall@1'] - floor_metrics['transition_to_target_recall@1']:.6f}",
        "floor_gap_delta_cosine": f"{eval_metrics['delta_cosine'] - floor_metrics['delta_cosine']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": "0.000000",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Prototype transition diagnostic; no model promotion.",
        "artifact_dir": str(out),
    }


