def _source_space_values(bundle, space: str) -> np.ndarray:
    if space == "z_bio_teacher":
        return bundle.source
    if space == "z_tech_teacher":
        tech = bundle.arrays.get("source_z_tech_teacher")
        if tech is None or tech.size == 0:
            return np.zeros((bundle.source.shape[0], 0), dtype=np.float64)
        return tech.astype(np.float64)
    if space == "z_bio_plus_z_tech":
        tech = _source_space_values(bundle, "z_tech_teacher")
        if tech.size == 0:
            return bundle.source
        return np.concatenate((_l2_normalize_np(bundle.source), _l2_normalize_np(tech)), axis=1)
    if space == "z_bio_online":
        online = bundle.arrays.get("source_z_bio_online")
        if online is None or online.size == 0:
            return bundle.source
        return online.astype(np.float64)
    raise ValueError(f"Unknown source latent space: {space}")


def _source_space_purity_frame(bundle, *, space: str) -> pd.DataFrame:
    metadata = bundle.metadata.reset_index(drop=True)
    actions = sorted(int(value) for value in metadata["perturbation_id"].unique())
    fractions = np.asarray([1.0 / 3.0, 0.5, 2.0 / 3.0, 1.0], dtype=np.float64)
    source_values_all = _source_space_values(bundle, space)
    rows: list[dict[str, Any]] = []
    for heldout_actions in combinations(actions, 3):
        heldout_set = set(heldout_actions)
        heldout_mask = metadata["perturbation_id"].isin(heldout_set).to_numpy()
        idx = np.flatnonzero(heldout_mask)
        local_meta = metadata.iloc[idx].reset_index(drop=True)
        values = source_values_all[idx]
        if values.size == 0:
            continue
        cell = local_meta["cell_line_id"].to_numpy() if "cell_line_id" in local_meta.columns else np.zeros(len(local_meta), dtype=int)
        batch = local_meta["batch_id"].to_numpy() if "batch_id" in local_meta.columns else np.zeros(len(local_meta), dtype=int)
        pert = local_meta["perturbation_id"].to_numpy()
        scores = _l2_normalize_np(values) @ _l2_normalize_np(values).T
        order = np.argsort(-scores, axis=1, kind="mergesort")
        same_cell = cell[:, None] == cell[None, :]
        same_batch = batch[:, None] == batch[None, :]
        same_pert = pert[:, None] == pert[None, :]
        n = values.shape[0]
        for fraction in fractions:
            k = max(1, min(n, int(np.ceil(float(fraction) * n))))
            mask = np.zeros((n, n), dtype=bool)
            for row_idx in range(n):
                mask[row_idx, order[row_idx, :k]] = True
            same_cell_total = np.maximum(same_cell.sum(axis=1), 1)
            rows.append(
                {
                    "latent_space": space,
                    "heldout_perturbation_ids": ",".join(str(value) for value in heldout_actions),
                    "source_neighborhood_fraction": float(fraction),
                    "source_neighborhood_k": int(k),
                    "same_cell_line_purity": float(same_cell[mask].mean()) if mask.any() else 0.0,
                    "same_cell_line_coverage": float(((mask & same_cell).sum(axis=1) / same_cell_total).mean()),
                    "same_batch_purity": float(same_batch[mask].mean()) if mask.any() else 0.0,
                    "same_perturbation_purity": float(same_pert[mask].mean()) if mask.any() else 0.0,
                    "top1_same_cell_line": float(np.mean(cell[order[:, 0]] == cell)),
                }
            )
    return pd.DataFrame(rows)


def _source_space_purity_summary(bundle) -> pd.DataFrame:
    frames = [_source_space_purity_frame(bundle, space=space) for space in ("z_bio_teacher", "z_tech_teacher", "z_bio_plus_z_tech", "z_bio_online")]
    frame = pd.concat([item for item in frames if not item.empty], ignore_index=True) if any(not item.empty for item in frames) else pd.DataFrame()
    if frame.empty:
        return pd.DataFrame()
    return (
        frame.groupby(["latent_space", "source_neighborhood_fraction"], as_index=False)
        .agg(
            mean_same_cell_line_purity=("same_cell_line_purity", "mean"),
            min_same_cell_line_purity=("same_cell_line_purity", "min"),
            mean_same_cell_line_coverage=("same_cell_line_coverage", "mean"),
            mean_same_batch_purity=("same_batch_purity", "mean"),
            mean_same_perturbation_purity=("same_perturbation_purity", "mean"),
            mean_top1_same_cell_line=("top1_same_cell_line", "mean"),
        )
        .sort_values(["source_neighborhood_fraction", "mean_same_cell_line_purity"], ascending=[True, False])
    )


def run_c012_source_state_latent_space(args: argparse.Namespace, train_bundle, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/C012_source_state_latent_space"
    out.mkdir(parents=True, exist_ok=True)
    current_summary = _source_space_purity_summary(train_bundle)
    current_summary.to_csv(out / "current_seed_source_space_purity_summary.tsv", sep="\t", index=False)
    fresh_summary = pd.DataFrame()
    fresh_cache = args.output_root / "experiments/G001_fresh_synthetic_seed_cache/seed1_latent_cache"
    if (fresh_cache / f"{args.dataset}_train_latents.npz").exists():
        fresh_train = load_latent_bundle(fresh_cache / f"{args.dataset}_train_latents", "fresh_seed1_train")
        fresh_summary = _source_space_purity_summary(fresh_train)
        fresh_summary.to_csv(out / "fresh_seed_source_space_purity_summary.tsv", sep="\t", index=False)
    top_third = current_summary[np.isclose(current_summary["source_neighborhood_fraction"], 1.0 / 3.0)] if not current_summary.empty else pd.DataFrame()
    best = top_third.sort_values("mean_same_cell_line_purity", ascending=False).iloc[0] if not top_third.empty else pd.Series(dtype=float)
    bio_row = top_third[top_third["latent_space"] == "z_bio_teacher"].iloc[0] if not top_third[top_third["latent_space"] == "z_bio_teacher"].empty else pd.Series(dtype=float)
    best_space = str(best.get("latent_space", "none"))
    best_purity = float(best.get("mean_same_cell_line_purity", 0.0))
    bio_purity = float(bio_row.get("mean_same_cell_line_purity", 0.0))
    best_gain = best_purity - bio_purity
    if best_space != "z_bio_teacher" and best_gain > 0.05:
        decision = "C012_SOURCE_STATE_SIGNAL_STRONGER_OUTSIDE_Z_BIO"
    elif bio_purity < 0.85:
        decision = "C012_SOURCE_STATE_WEAK_IN_ALL_AVAILABLE_SOURCE_SPACES"
    else:
        decision = "C012_Z_BIO_SOURCE_STATE_PURITY_SUFFICIENT_DIAGNOSTIC"
    summary = {
        "diagnostic_label": decision,
        "best_top_third_space": best_space,
        "best_top_third_same_cell_line_purity": best_purity,
        "z_bio_top_third_same_cell_line_purity": bio_purity,
        "best_minus_z_bio_purity_gain": best_gain,
        "current_summary": current_summary.to_dict("records") if not current_summary.empty else [],
        "fresh_summary": fresh_summary.to_dict("records") if not fresh_summary.empty else [],
    }
    write_json(out / "metrics_eval.json", summary)
    report = f"""# C012 Source-State Latent-Space Audit

## Decision
`{decision}`

## Evidence
- Best top-third latent space: `{best_space}`.
- Best top-third same-cell-line purity: `{best_purity:.6f}`.
- z_bio top-third same-cell-line purity: `{bio_purity:.6f}`.
- Best-minus-z_bio purity gain: `{best_gain:.6f}`.

## Interpretation
This audit checks whether source-state/cell-line structure is better represented in z_tech or joint source latents than in z_bio. It does not use these metadata fields as model inputs or promotion criteria.
"""
    (out / "source_state_latent_space_report.md").write_text(report, encoding="utf-8")
    append_journal(
        args.output_root,
        "C012_SOURCE_STATE_LATENT_SPACE_AUDIT",
        "Representation repair diagnostic",
        f"Best top-third source-state purity={best_purity:.4f} in {best_space}; z_bio purity={bio_purity:.4f}; decision={decision}.",
    )
    return {
        "experiment_id": "C012",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "source_state_latent_space_audit",
        "status_label": decision,
        "transition_improvement": f"{floor_metrics['transition_source_cosine_improvement']:.6f}",
        "delta_cosine": f"{floor_metrics['delta_cosine']:.6f}",
        "recall_at_1": f"{best_purity:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "magnitude_ratio": f"{floor_metrics['delta_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": "0.000000",
        "floor_gap_recall": f"{best_purity - bio_purity:.6f}",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{best_gain:.6f}",
        "calibration_lcb_recall_gap": f"{bio_purity:.6f}",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Source-state latent-space allocation audit; diagnostic only.",
        "artifact_dir": str(out),
    }


