def _pairwise_source_state_gap(values: np.ndarray, labels: np.ndarray) -> float:
    values = np.asarray(values, dtype=np.float64)
    labels = np.asarray(labels)
    if values.shape[0] < 2:
        return 0.0
    sim = _l2_normalize_np(values) @ _l2_normalize_np(values).T
    same = labels[:, None] == labels[None, :]
    offdiag = ~np.eye(sim.shape[0], dtype=bool)
    same_mask = same & offdiag
    diff_mask = (~same) & offdiag
    if not same_mask.any() or not diff_mask.any():
        return 0.0
    return float(sim[same_mask].mean() - sim[diff_mask].mean())


def _source_geometry_space_metrics(bundle, *, space: str, label_prefix: str) -> dict[str, Any]:
    values = _source_space_values(bundle, space)
    metadata = bundle.metadata.reset_index(drop=True)
    cell = metadata["cell_line_id"].to_numpy() if "cell_line_id" in metadata.columns else np.zeros(values.shape[0], dtype=int)
    batch = metadata["batch_id"].to_numpy() if "batch_id" in metadata.columns else np.zeros(values.shape[0], dtype=int)
    perturbation = metadata["perturbation_id"].to_numpy() if "perturbation_id" in metadata.columns else np.zeros(values.shape[0], dtype=int)
    summary = _source_space_purity_summary(bundle)
    top_third = summary[(summary["latent_space"] == space) & np.isclose(summary["source_neighborhood_fraction"], 1.0 / 3.0)] if not summary.empty else pd.DataFrame()
    purity = float(top_third["mean_same_cell_line_purity"].iloc[0]) if not top_third.empty else 0.0
    coverage = float(top_third["mean_same_cell_line_coverage"].iloc[0]) if not top_third.empty else 0.0
    return {
        "label": label_prefix,
        "latent_space": space,
        "effective_rank": effective_rank(values),
        "mean_norm": float(np.linalg.norm(values, axis=1).mean()) if values.size else 0.0,
        "std_norm": float(np.linalg.norm(values, axis=1).std()) if values.size else 0.0,
        "cell_line_eta_squared": _eta_squared(values, cell),
        "batch_eta_squared": _eta_squared(values, batch),
        "perturbation_eta_squared": _eta_squared(values, perturbation),
        "cell_line_centroid_accuracy": _nearest_centroid_accuracy(values, cell),
        "batch_centroid_accuracy": _nearest_centroid_accuracy(values, batch),
        "perturbation_centroid_accuracy": _nearest_centroid_accuracy(values, perturbation),
        "same_cell_pairwise_cosine_gap": _pairwise_source_state_gap(values, cell),
        "top_third_same_cell_line_purity": purity,
        "top_third_same_cell_line_coverage": coverage,
    }


def _online_teacher_alignment_metrics(bundle, *, label_prefix: str) -> dict[str, Any]:
    online = _source_space_values(bundle, "z_bio_online")
    teacher = _source_space_values(bundle, "z_bio_teacher")
    metadata = bundle.metadata.reset_index(drop=True)
    cell = metadata["cell_line_id"].to_numpy() if "cell_line_id" in metadata.columns else np.zeros(online.shape[0], dtype=int)
    residual = online - teacher if online.shape == teacher.shape else np.zeros_like(online)
    return {
        "label": label_prefix,
        "row_cosine_mean": float(_row_cosine_numpy(online, teacher).mean()) if online.shape == teacher.shape else 0.0,
        "row_cosine_min": float(_row_cosine_numpy(online, teacher).min()) if online.shape == teacher.shape else 0.0,
        "residual_mean_norm": float(np.linalg.norm(residual, axis=1).mean()) if residual.size else 0.0,
        "residual_cell_line_eta_squared": _eta_squared(residual, cell) if residual.size else 0.0,
        "residual_cell_line_centroid_accuracy": _nearest_centroid_accuracy(residual, cell) if residual.size else 0.0,
        "residual_same_cell_pairwise_cosine_gap": _pairwise_source_state_gap(residual, cell) if residual.size else 0.0,
    }


def _online_teacher_geometry_payload(bundle, *, label_prefix: str) -> dict[str, Any]:
    spaces = [
        _source_geometry_space_metrics(bundle, space="z_bio_teacher", label_prefix=label_prefix),
        _source_geometry_space_metrics(bundle, space="z_bio_online", label_prefix=label_prefix),
        _source_geometry_space_metrics(bundle, space="z_tech_teacher", label_prefix=label_prefix),
        _source_geometry_space_metrics(bundle, space="z_bio_plus_z_tech", label_prefix=label_prefix),
    ]
    alignment = _online_teacher_alignment_metrics(bundle, label_prefix=label_prefix)
    return {"spaces": spaces, "alignment": alignment}


def run_c014_online_teacher_source_geometry(args: argparse.Namespace, train_bundle, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/C014_online_teacher_source_geometry"
    out.mkdir(parents=True, exist_ok=True)
    current_payload = _online_teacher_geometry_payload(train_bundle, label_prefix="current_seed")
    current_spaces = pd.DataFrame(current_payload["spaces"])
    current_spaces.to_csv(out / "current_seed_source_geometry_by_space.tsv", sep="\t", index=False)
    pd.DataFrame([current_payload["alignment"]]).to_csv(out / "current_seed_online_teacher_alignment.tsv", sep="\t", index=False)
    fresh_payload: dict[str, Any] = {"spaces": [], "alignment": {}}
    fresh_cache = args.output_root / "experiments/G001_fresh_synthetic_seed_cache/seed1_latent_cache"
    if (fresh_cache / f"{args.dataset}_train_latents.npz").exists():
        fresh_train = load_latent_bundle(fresh_cache / f"{args.dataset}_train_latents", "fresh_seed1_train")
        fresh_payload = _online_teacher_geometry_payload(fresh_train, label_prefix="fresh_seed1")
        pd.DataFrame(fresh_payload["spaces"]).to_csv(out / "fresh_seed_source_geometry_by_space.tsv", sep="\t", index=False)
        pd.DataFrame([fresh_payload["alignment"]]).to_csv(out / "fresh_seed_online_teacher_alignment.tsv", sep="\t", index=False)
    def _metric(space: str, key: str) -> float:
        row = current_spaces[current_spaces["latent_space"] == space]
        return float(row[key].iloc[0]) if not row.empty else 0.0

    online_purity = _metric("z_bio_online", "top_third_same_cell_line_purity")
    teacher_purity = _metric("z_bio_teacher", "top_third_same_cell_line_purity")
    online_eta = _metric("z_bio_online", "cell_line_eta_squared")
    teacher_eta = _metric("z_bio_teacher", "cell_line_eta_squared")
    online_gap = _metric("z_bio_online", "same_cell_pairwise_cosine_gap")
    teacher_gap = _metric("z_bio_teacher", "same_cell_pairwise_cosine_gap")
    row_cosine = float(current_payload["alignment"].get("row_cosine_mean", 0.0))
    residual_eta = float(current_payload["alignment"].get("residual_cell_line_eta_squared", 0.0))
    purity_gain = online_purity - teacher_purity
    eta_gain = online_eta - teacher_eta
    if purity_gain > 0.10 and eta_gain > 0.05 and residual_eta > 0.05:
        decision = "C014_TEACHER_TARGET_ATTENUATES_SOURCE_STATE_STRUCTURE"
    elif purity_gain > 0.10:
        decision = "C014_ONLINE_SOURCE_STATE_STRUCTURE_STRONGER_THAN_TEACHER"
    else:
        decision = "C014_ONLINE_TEACHER_SOURCE_GEOMETRY_AUDIT_COMPLETED"
    summary = {
        "diagnostic_label": decision,
        "current_seed": current_payload,
        "fresh_seed": fresh_payload,
        "online_minus_teacher_top_third_purity_gain": purity_gain,
        "online_minus_teacher_cell_line_eta_gain": eta_gain,
        "online_minus_teacher_pairwise_gap_gain": online_gap - teacher_gap,
        "online_teacher_row_cosine_mean": row_cosine,
        "online_minus_teacher_residual_cell_line_eta": residual_eta,
    }
    write_json(out / "metrics_eval.json", summary)
    report = f"""# C014 Online-Teacher Source Geometry Audit

## Decision
`{decision}`

## Evidence
- online top-third same-cell-line purity: `{online_purity:.6f}`.
- teacher top-third same-cell-line purity: `{teacher_purity:.6f}`.
- online-minus-teacher purity gain: `{purity_gain:.6f}`.
- online cell-line eta^2: `{online_eta:.6f}`.
- teacher cell-line eta^2: `{teacher_eta:.6f}`.
- online-teacher row cosine mean: `{row_cosine:.6f}`.
- online-minus-teacher residual cell-line eta^2: `{residual_eta:.6f}`.

## Interpretation
This audit tests whether the teacher target representation attenuates source-state structure relative to the online/context representation. It is diagnostic only and does not use source metadata as a model input.
"""
    (out / "online_teacher_source_geometry_report.md").write_text(report, encoding="utf-8")
    append_journal(
        args.output_root,
        "C014_ONLINE_TEACHER_SOURCE_GEOMETRY_AUDIT",
        "Representation repair diagnostic",
        f"Online-vs-teacher purity gain={purity_gain:.4f}, eta gain={eta_gain:.4f}, residual eta={residual_eta:.4f}; decision={decision}.",
    )
    return {
        "experiment_id": "C014",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "online_teacher_source_geometry_audit",
        "status_label": decision,
        "transition_improvement": f"{floor_metrics['transition_source_cosine_improvement']:.6f}",
        "delta_cosine": f"{floor_metrics['delta_cosine']:.6f}",
        "recall_at_1": f"{online_purity:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "magnitude_ratio": f"{floor_metrics['delta_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": "0.000000",
        "floor_gap_recall": f"{purity_gain:.6f}",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{eta_gain:.6f}",
        "calibration_lcb_recall_gap": f"{residual_eta:.6f}",
        "action_negative_gap": f"{row_cosine:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Online-vs-teacher source-state geometry audit; diagnostic only.",
        "artifact_dir": str(out),
    }


def _load_metric_json(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8")) if path.exists() else {}


def run_c015_source_state_preservation_decision(args: argparse.Namespace, floor_metrics: dict[str, float]) -> dict[str, Any]:
    out = args.output_root / "experiments/C015_source_state_preservation_decision"
    out.mkdir(parents=True, exist_ok=True)
    c009 = _load_metric_json(args.output_root / "experiments/C009_nested_source_state_retrieval/metrics_eval.json")
    c010 = _load_metric_json(args.output_root / "experiments/C010_source_latent_neighborhood_retrieval/metrics_eval.json")
    c013 = _load_metric_json(args.output_root / "experiments/C013_online_source_neighborhood_retrieval/metrics_eval.json")
    c014 = _load_metric_json(args.output_root / "experiments/C014_online_teacher_source_geometry/metrics_eval.json")
    floor_recall = floor_metrics["transition_to_target_recall@1"]

    def _nested_recall(payload: dict[str, Any], seed_key: str) -> float:
        return float(payload.get(seed_key, {}).get("selected_condition_recall_at_1", 0.0))

    current_exact = _nested_recall(c009, "current_seed")
    fresh_exact = _nested_recall(c009, "fresh_seed")
    current_teacher_proxy = _nested_recall(c010, "current_seed")
    fresh_teacher_proxy = _nested_recall(c010, "fresh_seed")
    current_online_proxy = _nested_recall(c013, "current_seed")
    fresh_online_proxy = _nested_recall(c013, "fresh_seed")
    online_teacher_purity_gain = float(c014.get("online_minus_teacher_top_third_purity_gain", 0.0))
    online_teacher_eta_gain = float(c014.get("online_minus_teacher_cell_line_eta_gain", 0.0))
    residual_eta = float(c014.get("online_minus_teacher_residual_cell_line_eta", 0.0))
    current_calibrated_headroom = current_exact - current_online_proxy
    fresh_calibrated_headroom = fresh_exact - fresh_online_proxy
    current_floor_gap = current_online_proxy - floor_recall
    fresh_floor_gap = fresh_online_proxy - floor_recall
    rows = [
        {"metric": "current_exact_source_state_nested_recall", "value": current_exact, "floor_gap": current_exact - floor_recall},
        {"metric": "fresh_exact_source_state_nested_recall", "value": fresh_exact, "floor_gap": fresh_exact - floor_recall},
        {"metric": "current_teacher_source_neighborhood_recall", "value": current_teacher_proxy, "floor_gap": current_teacher_proxy - floor_recall},
        {"metric": "fresh_teacher_source_neighborhood_recall", "value": fresh_teacher_proxy, "floor_gap": fresh_teacher_proxy - floor_recall},
        {"metric": "current_online_source_neighborhood_recall", "value": current_online_proxy, "floor_gap": current_floor_gap},
        {"metric": "fresh_online_source_neighborhood_recall", "value": fresh_online_proxy, "floor_gap": fresh_floor_gap},
        {"metric": "online_minus_teacher_purity_gain", "value": online_teacher_purity_gain, "floor_gap": 0.0},
        {"metric": "online_minus_teacher_cell_line_eta_gain", "value": online_teacher_eta_gain, "floor_gap": 0.0},
        {"metric": "online_minus_teacher_residual_cell_line_eta", "value": residual_eta, "floor_gap": 0.0},
    ]
    pd.DataFrame(rows).to_csv(out / "source_state_preservation_decision_table.tsv", sep="\t", index=False)
    if current_online_proxy >= floor_recall and fresh_online_proxy >= floor_recall:
        decision = "C015_REOPEN_SOURCE_STATE_PRESERVATION_CANDIDATE_APPROVED"
    elif current_exact >= floor_recall and current_online_proxy > current_teacher_proxy + 0.04 and fresh_online_proxy > fresh_teacher_proxy:
        decision = "C015_SOURCE_STATE_PRESERVATION_PROMISING_BUT_NEEDS_FRESH_SUPPORT"
    else:
        decision = "C015_DO_NOT_REOPEN_TRAINING_SOURCE_STATE_PRESERVATION_INSUFFICIENT"
    summary = {
        "diagnostic_label": decision,
        "protected_condition_recall_floor": float(floor_recall),
        "current_exact_source_state_nested_recall": current_exact,
        "fresh_exact_source_state_nested_recall": fresh_exact,
        "current_teacher_source_neighborhood_recall": current_teacher_proxy,
        "fresh_teacher_source_neighborhood_recall": fresh_teacher_proxy,
        "current_online_source_neighborhood_recall": current_online_proxy,
        "fresh_online_source_neighborhood_recall": fresh_online_proxy,
        "current_online_floor_gap": current_floor_gap,
        "fresh_online_floor_gap": fresh_floor_gap,
        "current_exact_minus_online_headroom": current_calibrated_headroom,
        "fresh_exact_minus_online_headroom": fresh_calibrated_headroom,
        "online_minus_teacher_purity_gain": online_teacher_purity_gain,
        "online_minus_teacher_cell_line_eta_gain": online_teacher_eta_gain,
        "online_minus_teacher_residual_cell_line_eta": residual_eta,
    }
    write_json(out / "metrics_eval.json", summary)
    report = f"""# C015 Source-State Preservation Decision Audit

## Decision
`{decision}`

## Evidence
- Protected condition recall floor: `{floor_recall:.6f}`.
- Current exact source-state nested recall: `{current_exact:.6f}`.
- Fresh exact source-state nested recall: `{fresh_exact:.6f}`.
- Current teacher-source neighborhood recall: `{current_teacher_proxy:.6f}`.
- Current online-source neighborhood recall: `{current_online_proxy:.6f}`.
- Fresh online-source neighborhood recall: `{fresh_online_proxy:.6f}`.
- Online-minus-teacher source-state purity gain: `{online_teacher_purity_gain:.6f}`.
- Online-minus-teacher residual cell-line eta^2: `{residual_eta:.6f}`.

## Interpretation
Teacher target attenuation is real, but nested online-source-neighborhood retrieval remains below the protected floor and does not generalize to the fresh synthetic seed. This audit decides whether to reopen training now or continue with lower-compute diagnostics.
"""
    (out / "source_state_preservation_decision_report.md").write_text(report, encoding="utf-8")
    append_journal(
        args.output_root,
        "C015_SOURCE_STATE_PRESERVATION_DECISION_AUDIT",
        "Representation repair diagnostic",
        f"Current online recall={current_online_proxy:.4f}, fresh online recall={fresh_online_proxy:.4f}, floor={floor_recall:.4f}; decision={decision}.",
    )
    return {
        "experiment_id": "C015",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "source_state_preservation_decision_audit",
        "status_label": decision,
        "transition_improvement": f"{floor_metrics['transition_source_cosine_improvement']:.6f}",
        "delta_cosine": f"{floor_metrics['delta_cosine']:.6f}",
        "recall_at_1": f"{current_online_proxy:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "magnitude_ratio": f"{floor_metrics['delta_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{floor_metrics['delta_prediction_effective_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": "0.000000",
        "floor_gap_recall": f"{current_floor_gap:.6f}",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{current_calibrated_headroom:.6f}",
        "calibration_lcb_recall_gap": f"{fresh_floor_gap:.6f}",
        "action_negative_gap": f"{online_teacher_purity_gain:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Source-state preservation decision audit; diagnostic only, no training launched.",
        "artifact_dir": str(out),
    }


def _low_compute_subprocess_env() -> dict[str, str]:
    env = os.environ.copy()
    for key in ("OMP_NUM_THREADS", "MKL_NUM_THREADS", "OPENBLAS_NUM_THREADS", "NUMEXPR_NUM_THREADS"):
        env.setdefault(key, "2")
    return env


def _ensure_g002_seed_cache(args: argparse.Namespace, out: Path, seed: int) -> tuple[Path, dict[str, Any]]:
    g001_cache = args.output_root / "experiments/G001_fresh_synthetic_seed_cache/seed1_latent_cache"
    if seed == 1 and (g001_cache / f"{args.dataset}_train_latents.npz").exists():
        return g001_cache, {"cache_status": "reused_g001_seed1_cache", "returncode": 0}
    cache_dir = out / f"seed{seed}_latent_cache"
    train_npz = cache_dir / f"{args.dataset}_train_latents.npz"
    eval_npz = cache_dir / f"{args.dataset}_{args.eval_split}_latents.npz"
    if train_npz.exists() and eval_npz.exists():
        return cache_dir, {"cache_status": "reused_existing_g002_cache", "returncode": 0}
    command = [
        sys.executable,
        "scripts/cache_bioflow_teacher_latents.py",
        "--dataset",
        args.dataset,
        "--eval-split",
        args.eval_split,
        "--seed",
        str(seed),
        "--device",
        "cpu",
        "--batch-size",
        "8",
        "--bag-size",
        "4",
        "--output-dir",
        str(cache_dir),
    ]
    (out / f"cache_command_seed{seed}.txt").write_text(" ".join(command) + "\n", encoding="utf-8")
    proc = subprocess.run(command, text=True, capture_output=True, env=_low_compute_subprocess_env())
    (out / f"cache_stdout_seed{seed}.txt").write_text(proc.stdout, encoding="utf-8")
    (out / f"cache_stderr_seed{seed}.txt").write_text(proc.stderr, encoding="utf-8")
    return cache_dir, {"cache_status": "generated" if proc.returncode == 0 else "blocked", "returncode": proc.returncode}


def _g002_load_or_generate_seed_bundle(
    args: argparse.Namespace,
    out: Path,
    seed: int,
    current_train,
    current_eval,
    current_floor: dict[str, float],
) -> tuple[Any | None, dict[str, float], dict[str, Any]]:
    if seed == 0:
        return current_train, current_floor, {"cache_status": "current_phase4_cache", "returncode": 0}
    cache_dir, cache_status = _ensure_g002_seed_cache(args, out, seed)
    if int(cache_status.get("returncode", 1)) != 0:
        return None, {}, {**cache_status, "cache_dir": str(cache_dir)}
    train_path = cache_dir / f"{args.dataset}_train_latents"
    eval_path = cache_dir / f"{args.dataset}_{args.eval_split}_latents"
    if not train_path.with_suffix(".npz").exists() or not eval_path.with_suffix(".npz").exists():
        return None, {}, {**cache_status, "cache_status": "missing_cache_files", "cache_dir": str(cache_dir)}
    train_bundle = load_latent_bundle(train_path, f"g002_seed{seed}_train")
    eval_bundle = load_latent_bundle(eval_path, f"g002_seed{seed}_eval")
    fit = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
    pred_delta = predict_ridge_numpy(fit, bundle_features(eval_bundle))
    floor = bundle_transition_metrics(eval_bundle, pred_delta)
    return train_bundle, floor, {**cache_status, "cache_dir": str(cache_dir)}


def _geometry_metric(payload: dict[str, Any], space: str, key: str) -> float:
    for row in payload.get("spaces", []):
        if row.get("latent_space") == space:
            return float(row.get(key, 0.0))
    return 0.0


def _nanmean(values: list[float]) -> float:
    clean = [float(value) for value in values if np.isfinite(float(value))]
    return float(np.mean(clean)) if clean else 0.0


def run_g002_multi_seed_source_state_stability(
    args: argparse.Namespace,
    train_bundle,
    eval_bundle,
    protected_floor_metrics: dict[str, float],
) -> dict[str, Any]:
    out = args.output_root / "experiments/G002_multi_seed_source_state_stability"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3]
    floor_recall = float(protected_floor_metrics["transition_to_target_recall@1"])
    seed_rows: list[dict[str, Any]] = []
    for seed in seeds:
        bundle, seed_floor, cache_status = _g002_load_or_generate_seed_bundle(
            args,
            out,
            seed,
            train_bundle,
            eval_bundle,
            protected_floor_metrics,
        )
        if bundle is None:
            seed_rows.append(
                {
                    "seed": seed,
                    **cache_status,
                    "diagnostic_status": "blocked",
                    "floor_recall_at_1": 0.0,
                    "exact_source_state_recall_at_1": 0.0,
                    "teacher_source_neighborhood_recall_at_1": 0.0,
                    "online_source_neighborhood_recall_at_1": 0.0,
                    "online_floor_gap": -floor_recall,
                }
            )
            continue
        seed_dir = out / f"seed{seed}_diagnostics"
        seed_dir.mkdir(parents=True, exist_ok=True)
        _, exact_selected, exact_outer, exact_metrics = _nested_source_state_calibration(bundle, prefix=f"g002_seed{seed}_exact")
        _, teacher_selected, teacher_outer, teacher_metrics = _nested_source_neighborhood_calibration(
            bundle,
            prefix=f"g002_seed{seed}_teacher",
            source_space="z_bio_teacher",
        )
        _, online_selected, online_outer, online_metrics = _nested_source_neighborhood_calibration(
            bundle,
            prefix=f"g002_seed{seed}_online",
            source_space="z_bio_online",
        )
        geometry = _online_teacher_geometry_payload(bundle, label_prefix=f"g002_seed{seed}")
        exact_selected.to_csv(seed_dir / "exact_source_state_selected_rules.tsv", sep="\t", index=False)
        exact_outer.to_csv(seed_dir / "exact_source_state_outer_folds.tsv", sep="\t", index=False)
        teacher_selected.to_csv(seed_dir / "teacher_source_neighborhood_selected_rules.tsv", sep="\t", index=False)
        teacher_outer.to_csv(seed_dir / "teacher_source_neighborhood_outer_folds.tsv", sep="\t", index=False)
        online_selected.to_csv(seed_dir / "online_source_neighborhood_selected_rules.tsv", sep="\t", index=False)
        online_outer.to_csv(seed_dir / "online_source_neighborhood_outer_folds.tsv", sep="\t", index=False)
        pd.DataFrame(geometry["spaces"]).to_csv(seed_dir / "source_geometry_by_space.tsv", sep="\t", index=False)
        pd.DataFrame([geometry["alignment"]]).to_csv(seed_dir / "online_teacher_alignment.tsv", sep="\t", index=False)
        online_recall = float(online_metrics["selected_condition_recall_at_1"])
        teacher_recall = float(teacher_metrics["selected_condition_recall_at_1"])
        exact_recall = float(exact_metrics["selected_condition_recall_at_1"])
        online_purity = _geometry_metric(geometry, "z_bio_online", "top_third_same_cell_line_purity")
        teacher_purity = _geometry_metric(geometry, "z_bio_teacher", "top_third_same_cell_line_purity")
        online_eta = _geometry_metric(geometry, "z_bio_online", "cell_line_eta_squared")
        teacher_eta = _geometry_metric(geometry, "z_bio_teacher", "cell_line_eta_squared")
        seed_rows.append(
            {
                "seed": seed,
                **cache_status,
                "diagnostic_status": "completed",
                "floor_transition_improvement": float(seed_floor.get("transition_source_cosine_improvement", 0.0)),
                "floor_delta_cosine": float(seed_floor.get("delta_cosine", 0.0)),
                "floor_recall_at_1": float(seed_floor.get("transition_to_target_recall@1", 0.0)),
                "floor_delta_rank": float(seed_floor.get("delta_prediction_effective_rank", 0.0)),
                "floor_magnitude_ratio": float(seed_floor.get("delta_magnitude_ratio", 0.0)),
                "exact_source_state_recall_at_1": exact_recall,
                "teacher_source_neighborhood_recall_at_1": teacher_recall,
                "online_source_neighborhood_recall_at_1": online_recall,
                "exact_floor_gap": exact_recall - floor_recall,
                "teacher_floor_gap": teacher_recall - floor_recall,
                "online_floor_gap": online_recall - floor_recall,
                "online_minus_teacher_recall": online_recall - teacher_recall,
                "online_top_third_same_cell_line_purity": online_purity,
                "teacher_top_third_same_cell_line_purity": teacher_purity,
                "online_minus_teacher_purity_gain": online_purity - teacher_purity,
                "online_cell_line_eta_squared": online_eta,
                "teacher_cell_line_eta_squared": teacher_eta,
                "online_minus_teacher_eta_gain": online_eta - teacher_eta,
                "exact_selected_delta_weight_mean": float(exact_metrics["selected_delta_score_weight_mean"]),
                "teacher_selected_fraction_mean": float(teacher_metrics["selected_source_neighborhood_fraction_mean"]),
                "online_selected_fraction_mean": float(online_metrics["selected_source_neighborhood_fraction_mean"]),
                "online_selected_delta_weight_mean": float(online_metrics["selected_delta_score_weight_mean"]),
            }
        )
    seed_frame = pd.DataFrame(seed_rows)
    seed_frame.to_csv(out / "multi_seed_source_state_stability.tsv", sep="\t", index=False)
    valid = seed_frame[seed_frame["diagnostic_status"] == "completed"].copy() if not seed_frame.empty else pd.DataFrame()
    online_pass_fraction = float((valid["online_source_neighborhood_recall_at_1"] >= floor_recall).mean()) if not valid.empty else 0.0
    exact_pass_fraction = float((valid["exact_source_state_recall_at_1"] >= floor_recall).mean()) if not valid.empty else 0.0
    online_beats_teacher_fraction = float((valid["online_minus_teacher_recall"] > 0.0).mean()) if not valid.empty else 0.0
    mean_online_gap = float(valid["online_floor_gap"].mean()) if not valid.empty else -floor_recall
    min_online_gap = float(valid["online_floor_gap"].min()) if not valid.empty else -floor_recall
    mean_exact_gap = float(valid["exact_floor_gap"].mean()) if not valid.empty else -floor_recall
    if online_pass_fraction >= 0.75 and min_online_gap >= -0.01:
        decision = "G002_REOPEN_SOURCE_STATE_PRESERVATION_WITH_MULTI_SEED_SUPPORT"
    elif exact_pass_fraction >= 0.50 and online_beats_teacher_fraction >= 0.50:
        decision = "G002_EXACT_SOURCE_STATE_SIGNAL_EXISTS_BUT_LEARNABLE_PROXY_UNSTABLE"
    else:
        decision = "G002_MULTI_SEED_SOURCE_STATE_SIGNAL_UNSTABLE_NO_TRAINING_REOPEN"
    summary = {
        "diagnostic_label": decision,
        "protected_condition_recall_floor": floor_recall,
        "seeds": seeds,
        "completed_seed_count": int(len(valid)),
        "online_pass_fraction": online_pass_fraction,
        "exact_pass_fraction": exact_pass_fraction,
        "online_beats_teacher_fraction": online_beats_teacher_fraction,
        "mean_online_floor_gap": mean_online_gap,
        "min_online_floor_gap": min_online_gap,
        "mean_exact_floor_gap": mean_exact_gap,
        "seed_rows": seed_rows,
        "constraint": "condition labels and source-state metadata are used only for diagnostic scoring; no exact key or metadata field is used as a model input or train/eval fit target",
    }
    write_json(out / "metrics_eval.json", summary)
    table = "\n".join(
        "| {seed} | {floor_recall_at_1:.6f} | {exact_source_state_recall_at_1:.6f} | {teacher_source_neighborhood_recall_at_1:.6f} | {online_source_neighborhood_recall_at_1:.6f} | {online_floor_gap:.6f} |".format(
            **{key: row.get(key, 0.0) for key in row.keys()}
        )
        for row in seed_rows
    )
    report = f"""# G002 Multi-Seed Source-State Stability Audit

## Decision
`{decision}`

## Evidence
Protected condition recall floor: `{floor_recall:.6f}`.

| seed | floor recall@1 | exact source-state recall@1 | teacher-neighborhood recall@1 | online-neighborhood recall@1 | online floor gap |
| ---: | ---: | ---: | ---: | ---: | ---: |
{table}

## Interpretation
C015 did not approve source-state preservation training. G002 tests whether that decision was seed-specific by repeating the same train-only nested source-state and source-neighborhood diagnostics on additional tiny synthetic latent caches. The result is diagnostic only: source-state metadata and condition labels are used only to score retrieval geometry, not as model inputs or as a promotion path.
"""
    (out / "multi_seed_source_state_stability_report.md").write_text(report, encoding="utf-8")
    append_journal(
        args.output_root,
        "G002_MULTI_SEED_SOURCE_STATE_STABILITY_AUDIT",
        "Fresh synthetic seed geometry diagnostic",
        f"Completed {len(valid)} seeds; online pass fraction={online_pass_fraction:.3f}, mean online floor gap={mean_online_gap:.4f}; decision={decision}.",
    )
    mean_floor_transition = _nanmean(valid["floor_transition_improvement"].tolist()) if not valid.empty else 0.0
    mean_floor_delta = _nanmean(valid["floor_delta_cosine"].tolist()) if not valid.empty else 0.0
    mean_online_recall = _nanmean(valid["online_source_neighborhood_recall_at_1"].tolist()) if not valid.empty else 0.0
    mean_floor_rank = _nanmean(valid["floor_delta_rank"].tolist()) if not valid.empty else 0.0
    mean_floor_mag = _nanmean(valid["floor_magnitude_ratio"].tolist()) if not valid.empty else 0.0
    return {
        "experiment_id": "G002",
        "phase": "PostPhase8Council",
        "family": "Fresh synthetic seed geometry",
        "tier": "Diagnostic",
        "seed": 0,
        "dataset": args.dataset,
        "eval_split": args.eval_split,
        "mode": "multi_seed_source_state_stability_audit",
        "status_label": decision,
        "transition_improvement": f"{mean_floor_transition:.6f}",
        "delta_cosine": f"{mean_floor_delta:.6f}",
        "recall_at_1": f"{mean_online_recall:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{mean_floor_rank:.6f}",
        "magnitude_ratio": f"{mean_floor_mag:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{mean_floor_rank:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": str(mean_floor_rank < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{mean_floor_transition - protected_floor_metrics['transition_source_cosine_improvement']:.6f}",
        "floor_gap_recall": f"{mean_online_recall - floor_recall:.6f}",
        "floor_gap_delta_cosine": f"{mean_floor_delta - protected_floor_metrics['delta_cosine']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{min_online_gap:.6f}",
        "calibration_lcb_recall_gap": f"{mean_online_gap:.6f}",
        "action_negative_gap": f"{online_beats_teacher_fraction:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": f"Multi-seed source-state stability audit; completed_seeds={len(valid)}; no model promotion.",
        "artifact_dir": str(out),
    }


def _cached_seed_candidates(args: argparse.Namespace, seed: int) -> list[Path]:
    candidates: list[Path] = []
    if seed == 0:
        candidates.append(PHASE4_CACHE)
    if seed == 1:
        candidates.append(args.output_root / "experiments/G001_fresh_synthetic_seed_cache/seed1_latent_cache")
    candidates.extend(
        [
            args.output_root / f"experiments/G002_multi_seed_source_state_stability/seed{seed}_latent_cache",
            args.output_root / f"experiments/G002_multi_seed_fresh_cache_replication/seed{seed}_latent_cache",
        ]
    )
    return candidates


def _find_seed_cache(args: argparse.Namespace, seed: int) -> Path | None:
    for candidate in _cached_seed_candidates(args, seed):
        train_npz = candidate / f"{args.dataset}_train_latents.npz"
        eval_npz = candidate / f"{args.dataset}_{args.eval_split}_latents.npz"
        if train_npz.exists() and eval_npz.exists():
            return candidate
    return None


def _load_registry_seed_bundle(
    args: argparse.Namespace,
    out: Path,
    seed: int,
    current_train,
    current_eval,
) -> tuple[Any | None, Any | None, dict[str, Any]]:
    if seed == 0:
        return current_train, current_eval, {"cache_status": "current_phase4_cache", "cache_dir": str(PHASE4_CACHE)}
    cache = _find_seed_cache(args, seed)
    if cache is None:
        cache, status = _ensure_g002_seed_cache(args, out, seed)
        if int(status.get("returncode", 1)) != 0:
            return None, None, {**status, "cache_dir": str(cache)}
    train_path = cache / f"{args.dataset}_train_latents"
    eval_path = cache / f"{args.dataset}_{args.eval_split}_latents"
    if not train_path.with_suffix(".npz").exists() or not eval_path.with_suffix(".npz").exists():
        return None, None, {"cache_status": "missing_cache_files", "cache_dir": str(cache)}
    return (
        load_latent_bundle(train_path, f"f013_seed{seed}_train"),
        load_latent_bundle(eval_path, f"f013_seed{seed}_eval"),
        {"cache_status": "loaded", "cache_dir": str(cache)},
    )


def _action_mean_delta(train_bundle, eval_bundle) -> np.ndarray:
    train_meta = train_bundle.metadata.reset_index(drop=True)
    eval_meta = eval_bundle.metadata.reset_index(drop=True)
    global_mean = train_bundle.delta.mean(axis=0, keepdims=True)
    means: dict[str, np.ndarray] = {}
    if "perturbation_id" in train_meta.columns:
        for value, indices in train_meta.groupby("perturbation_id").indices.items():
            means[str(value)] = train_bundle.delta[np.asarray(indices, dtype=int)].mean(axis=0, keepdims=True)
    rows: list[np.ndarray] = []
    for value in eval_meta.get("perturbation_id", pd.Series([""] * eval_bundle.source.shape[0])).astype(str).tolist():
        rows.append(means.get(value, global_mean))
    return np.concatenate(rows, axis=0) if rows else np.zeros_like(eval_bundle.delta)


def _registry_baseline_delta(train_bundle, eval_bundle, baseline: str, seed: int) -> np.ndarray:
    if baseline == "source_as_target":
        return np.zeros_like(eval_bundle.delta)
    if baseline == "mean_delta":
        return np.repeat(train_bundle.delta.mean(axis=0, keepdims=True), eval_bundle.delta.shape[0], axis=0)
    if baseline == "action_mean_delta":
        return _action_mean_delta(train_bundle, eval_bundle)
    if baseline == "source_only_ridge":
        fit = fit_ridge_numpy(train_bundle.source, train_bundle.delta, alpha=1.0e-2)
        return predict_ridge_numpy(fit, eval_bundle.source)
    if baseline == "action_only_ridge":
        if train_bundle.action.shape[1] == 0:
            return np.repeat(train_bundle.delta.mean(axis=0, keepdims=True), eval_bundle.delta.shape[0], axis=0)
        fit = fit_ridge_numpy(train_bundle.action, train_bundle.delta, alpha=1.0e-2)
        return predict_ridge_numpy(fit, eval_bundle.action)
    if baseline == "action_ridge_floor":
        fit = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
        return predict_ridge_numpy(fit, bundle_features(eval_bundle))
    if baseline == "seed_randomized_full_ridge_null":
        rng = np.random.default_rng(int(seed) + 913)
        shuffled = train_bundle.delta[rng.permutation(train_bundle.delta.shape[0])]
        fit = fit_ridge_numpy(bundle_features(train_bundle), shuffled, alpha=1.0e-2)
        return predict_ridge_numpy(fit, bundle_features(eval_bundle))
    raise ValueError(f"Unknown registry baseline: {baseline}")


def _extra_label_retrieval_metrics(eval_bundle, pred_delta: np.ndarray) -> dict[str, float]:
    pred_endpoint = eval_bundle.source + pred_delta
    pred = _l2_normalize_np(pred_endpoint)
    target = _l2_normalize_np(eval_bundle.target)
    metadata = eval_bundle.metadata.reset_index(drop=True)
    metrics: dict[str, float] = {}
    for label_col, prefix in (
        ("perturbation_id", "transition_to_target_perturbation"),
        ("cell_line_id", "transition_to_target_cell_line"),
    ):
        if label_col not in metadata.columns:
            continue
        metrics.update(
            directional_retrieval_metrics(
                pred,
                target,
                metadata,
                metadata,
                label_col=label_col,
                ks=(1, 5, 10),
                prefix=prefix,
                stratify_by=(),
            )
        )
    return metrics


def run_f013_multiseed_baseline_registry(
    args: argparse.Namespace,
    train_bundle,
    eval_bundle,
    protected_floor_metrics: dict[str, float],
) -> dict[str, Any]:
    out = args.output_root / "experiments/F013_multiseed_baseline_registry"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    baselines = [
        "source_as_target",
        "mean_delta",
        "action_mean_delta",
        "source_only_ridge",
        "action_only_ridge",
        "action_ridge_floor",
        "seed_randomized_full_ridge_null",
    ]
    rows: list[dict[str, Any]] = []
    cache_rows: list[dict[str, Any]] = []
    for seed in seeds:
        seed_train, seed_eval, cache_status = _load_registry_seed_bundle(args, out, seed, train_bundle, eval_bundle)
        cache_rows.append({"seed": seed, **cache_status})
        if seed_train is None or seed_eval is None:
            rows.append({"seed": seed, "baseline": "cache_blocked", "status": "blocked", **cache_status})
            continue
        for baseline in baselines:
            pred_delta = _registry_baseline_delta(seed_train, seed_eval, baseline, seed)
            metrics = bundle_transition_metrics(seed_eval, pred_delta)
            metrics.update(_extra_label_retrieval_metrics(seed_eval, pred_delta))
            rows.append(
                {
                    "seed": seed,
                    "benchmark": "synthetic_genetic_anchor_lite_multiseed_v1",
                    "baseline": baseline,
                    "status": "completed",
                    "cache_dir": cache_status.get("cache_dir", ""),
                    "transition_improvement": metrics["transition_source_cosine_improvement"],
                    "absolute_target_cosine": metrics["absolute_target_cosine"],
                    "delta_cosine": metrics["delta_cosine"],
                    "condition_recall_at_1": metrics.get("transition_to_target_recall@1", 0.0),
                    "condition_recall_at_5": metrics.get("transition_to_target_recall@5", 0.0),
                    "condition_median_rank": metrics.get("transition_to_target_median_rank", 0.0),
                    "perturbation_recall_at_1": metrics.get("transition_to_target_perturbation_recall@1", 0.0),
                    "perturbation_recall_at_5": metrics.get("transition_to_target_perturbation_recall@5", 0.0),
                    "cell_line_recall_at_1": metrics.get("transition_to_target_cell_line_recall@1", 0.0),
                    "cell_line_recall_at_5": metrics.get("transition_to_target_cell_line_recall@5", 0.0),
                    "delta_prediction_effective_rank": metrics["delta_prediction_effective_rank"],
                    "delta_teacher_effective_rank": metrics["delta_teacher_effective_rank"],
                    "delta_magnitude_ratio": metrics["delta_magnitude_ratio"],
                    "source_improvement_hinge_violation_fraction": metrics["source_improvement_hinge_violation_fraction"],
                }
            )
    frame = pd.DataFrame(rows)
    frame.to_csv(out / "step0_baselines_by_seed.tsv", sep="\t", index=False)
    pd.DataFrame(cache_rows).to_csv(out / "seed_cache_sources.tsv", sep="\t", index=False)
    completed = frame[frame["status"] == "completed"].copy() if "status" in frame.columns else pd.DataFrame()
    summary = (
        completed.groupby("baseline", as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_transition_improvement=("transition_improvement", "mean"),
            std_transition_improvement=("transition_improvement", "std"),
            min_transition_improvement=("transition_improvement", "min"),
            mean_delta_cosine=("delta_cosine", "mean"),
            std_delta_cosine=("delta_cosine", "std"),
            mean_condition_recall_at_1=("condition_recall_at_1", "mean"),
            std_condition_recall_at_1=("condition_recall_at_1", "std"),
            min_condition_recall_at_1=("condition_recall_at_1", "min"),
            mean_perturbation_recall_at_1=("perturbation_recall_at_1", "mean"),
            mean_cell_line_recall_at_1=("cell_line_recall_at_1", "mean"),
            mean_delta_rank=("delta_prediction_effective_rank", "mean"),
            mean_magnitude_ratio=("delta_magnitude_ratio", "mean"),
        )
        .sort_values(["mean_transition_improvement", "mean_delta_cosine"], ascending=False)
        if not completed.empty
        else pd.DataFrame()
    )
    summary.to_csv(out / "step0_baseline_summary.tsv", sep="\t", index=False)
    action_floor = summary[summary["baseline"] == "action_ridge_floor"].iloc[0].to_dict() if not summary.empty and (summary["baseline"] == "action_ridge_floor").any() else {}
    registry_complete = not summary.empty and int(action_floor.get("seed_count", 0)) == len(seeds)
    decision = "F013_MULTISEED_STEP0_REGISTRY_COMPLETE_ARCHITECTURE_STILL_LOCKED" if registry_complete else "F013_MULTISEED_STEP0_REGISTRY_INCOMPLETE_BLOCKS_ARCHITECTURE"
    summary_payload = {
        "diagnostic_label": decision,
        "benchmark_name": "synthetic_genetic_anchor_lite_multiseed_v1",
        "architecture_search_allowed": False,
        "seed_count_required": len(seeds),
        "registry_complete": registry_complete,
        "protected_old_seed0_floor": protected_floor_metrics,
        "action_ridge_floor_summary": action_floor,
        "baseline_summary": summary.to_dict("records") if not summary.empty else [],
        "cache_sources": cache_rows,
        "leakage_controls": "all baselines fit on each seed train split only; eval rows are scoring-only; no condition_key/biological_key/exact target-key features are used as model inputs",
    }
    write_json(out / "metrics_eval.json", summary_payload)
    baseline_rows = "\n".join(
        f"| {row['baseline']} | {int(row['seed_count'])} | {row['mean_transition_improvement']:.6f} | {row['mean_delta_cosine']:.6f} | {row['mean_condition_recall_at_1']:.6f} | {row['mean_perturbation_recall_at_1']:.6f} | {row['mean_cell_line_recall_at_1']:.6f} |"
        for row in summary.to_dict("records")
    )
    registry_text = f"""# Synthetic Genetic Anchor Lite Multiseed v1 Baseline Registry

## Decision
`{decision}`

## Scope
This is a new named Step 0 registry for `synthetic_genetic_anchor_lite_multiseed_v1`. It does not alter the locked seed0 benchmark, the protected model of record, or any promotion gate.

## Leakage Contract
- Fit data: each seed's train split only.
- Eval data: scoring only.
- Forbidden model inputs: `condition_key`, `biological_key`, exact target-key one-hot features, eval/test target means, pooled train+test statistics, and PLS raw-linear heads as candidate path.
- Metadata labels are used only for retrieval reporting.

## Baseline Summary
| baseline | seeds | mean transition improvement | mean delta cosine | mean condition recall@1 | mean perturbation recall@1 | mean cell-line recall@1 |
| --- | ---: | ---: | ---: | ---: | ---: | ---: |
{baseline_rows}

## Interpretation
The old seed0 condition-recall floor remains locked for historical comparison, but future architecture should not be optimized against that single-seed threshold until a separate amendment defines new multi-seed Tier 1/Tier 2/Tier 3 gates from this registry.
"""
    (out / "BASELINE_REGISTRY_SYNTHETIC_GENETIC_ANCHOR_LITE_MULTISEED_V1.md").write_text(registry_text, encoding="utf-8")
    (args.output_root / "BASELINE_REGISTRY_MULTISEED_V1.md").write_text(registry_text, encoding="utf-8")
    append_journal(
        args.output_root,
        "F013_MULTISEED_STEP0_BASELINE_REGISTRY",
        "Metric/data redesign diagnostic",
        f"Built Step 0 registry for synthetic_genetic_anchor_lite_multiseed_v1 across {len(seeds)} seeds; decision={decision}.",
    )
    return {
        "experiment_id": "F013",
        "phase": "PostPhase8Council",
        "family": "Metric and data redesign",
        "tier": "Step0",
        "seed": "0,1,2,3,4",
        "dataset": "synthetic_genetic_anchor_lite_multiseed_v1",
        "eval_split": args.eval_split,
        "mode": "multiseed_step0_baseline_registry",
        "status_label": decision,
        "transition_improvement": f"{float(action_floor.get('mean_transition_improvement', 0.0)):.6f}",
        "delta_cosine": f"{float(action_floor.get('mean_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(action_floor.get('mean_condition_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(action_floor.get('mean_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(action_floor.get('mean_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(action_floor.get('mean_delta_rank', 0.0)):.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": "0.000000",
        "floor_gap_recall": "0.000000",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": "0.000000",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Multiseed Step 0 baseline registry; architecture remains locked pending future gate amendment.",
        "artifact_dir": str(out),
    }


def _active_multiseed_gates(args: argparse.Namespace) -> dict[str, float]:
    f014 = _load_metric_json(args.output_root / "experiments/F014_multiseed_benchmark_activation/metrics_eval.json")
    if f014:
        return {
            "primary_transition_gate": float(f014["primary_transition_gate"]),
            "primary_delta_cosine_gate": float(f014["primary_delta_cosine_gate"]),
            "secondary_recall_gate": float(f014["secondary_recall_gate"]),
        }
    f013 = _load_metric_json(args.output_root / "experiments/F013_multiseed_baseline_registry/metrics_eval.json")
    floor = f013.get("action_ridge_floor_summary", {})
    return {
        "primary_transition_gate": max(0.0, float(floor.get("mean_transition_improvement", 0.0)) - float(floor.get("std_transition_improvement", 0.0))),
        "primary_delta_cosine_gate": max(0.0, float(floor.get("mean_delta_cosine", 0.0)) - float(floor.get("std_delta_cosine", 0.0))),
        "secondary_recall_gate": max(0.0, float(floor.get("mean_condition_recall_at_1", 0.0)) - float(floor.get("std_condition_recall_at_1", 0.0))),
    }


def _bgwm003_train_args(args: argparse.Namespace, output_dir: Path, seed: int, cache: Path) -> argparse.Namespace:
    ns = train_args(args, output_dir, seed, calibration_mode="crossfit", steps=50, save_checkpoint=False)
    ns.latent_cache_path = cache
    ns.dataset = args.dataset
    ns.device = args.device if not str(args.device).startswith("cuda") or _cuda_available() else "cpu"
    return ns


def run_bgwm003_multiseed_v1_action_adaln_sanity(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/BGWM003_multiseed_v1_action_adaln_sanity"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    gates = _active_multiseed_gates(args)
    rows: list[dict[str, Any]] = []
    blocked: list[dict[str, Any]] = []
    for seed in seeds:
        cache = _find_seed_cache(args, seed)
        if cache is None:
            cache, status = _ensure_g002_seed_cache(args, out, seed)
            if int(status.get("returncode", 1)) != 0:
                blocked.append({"seed": seed, **status, "cache_dir": str(cache)})
                continue
        seed_out = out / f"seed{seed}"
        metrics = run_train(_bgwm003_train_args(args, seed_out, seed, cache))
        row = {
            "seed": seed,
            "cache_dir": str(cache),
            "decision_label": str(metrics.get("decision_label", "")),
            "transition_improvement": float(metrics["transition_improvement"]),
            "delta_cosine": float(metrics["delta_cosine"]),
            "recall_at_1": float(metrics["recall_at_1"]),
            "delta_rank": float(metrics["delta_rank"]),
            "magnitude_ratio": float(metrics["magnitude_ratio"]),
            "floor_transition_improvement": float(metrics["floor_transition_improvement"]),
            "floor_delta_cosine": float(metrics["floor_delta_cosine"]),
            "floor_recall_at_1": float(metrics["floor_recall_at_1"]),
            "floor_gap_transition": float(metrics.get("floor_gap_transition", 0.0)),
            "floor_gap_delta_cosine": float(metrics.get("floor_gap_delta_cosine", 0.0)),
            "floor_gap_recall": float(metrics.get("floor_gap_recall", 0.0)),
            "residual_scale": float(metrics.get("residual_scale", 0.0)),
            "cv_lcb_transition_gap": float(metrics.get("cv_lcb_transition_gap", 0.0)),
            "cv_lcb_delta_cosine_gap": float(metrics.get("cv_lcb_delta_cosine_gap", 0.0)),
            "cv_lcb_recall_gap": float(metrics.get("cv_lcb_recall_gap", 0.0)),
            "action_negative_gap": float(metrics.get("action_negative_gap", 0.0)),
            "artifact_dir": str(seed_out),
        }
        rows.append(row)
    frame = pd.DataFrame(rows)
    if not frame.empty:
        frame.to_csv(out / "bgwm003_by_seed.tsv", sep="\t", index=False)
    if blocked:
        pd.DataFrame(blocked).to_csv(out / "blocked_seed_caches.tsv", sep="\t", index=False)
    mean_metrics = {
        "mean_transition_improvement": float(frame["transition_improvement"].mean()) if not frame.empty else 0.0,
        "mean_delta_cosine": float(frame["delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_recall_at_1": float(frame["recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_delta_rank": float(frame["delta_rank"].mean()) if not frame.empty else 0.0,
        "mean_magnitude_ratio": float(frame["magnitude_ratio"].mean()) if not frame.empty else 0.0,
        "mean_floor_gap_transition": float(frame["floor_gap_transition"].mean()) if not frame.empty else 0.0,
        "mean_floor_gap_delta_cosine": float(frame["floor_gap_delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_floor_gap_recall": float(frame["floor_gap_recall"].mean()) if not frame.empty else 0.0,
        "mean_residual_scale": float(frame["residual_scale"].mean()) if not frame.empty else 0.0,
        "nonzero_residual_seed_count": int((frame["residual_scale"] > 0.0).sum()) if not frame.empty else 0,
        "completed_seed_count": int(len(frame)),
    }
    passes_mean_gates = (
        mean_metrics["completed_seed_count"] == len(seeds)
        and mean_metrics["mean_transition_improvement"] >= gates["primary_transition_gate"]
        and mean_metrics["mean_delta_cosine"] >= gates["primary_delta_cosine_gate"]
        and mean_metrics["mean_recall_at_1"] >= gates["secondary_recall_gate"]
    )
    if blocked:
        decision = "BGWM003_BLOCKED_CACHE_OR_TRAINING_INCOMPLETE"
    elif not passes_mean_gates:
        decision = "BGWM003_FAIL_MULTISEED_V1_ACTIVE_GATES"
    elif mean_metrics["nonzero_residual_seed_count"] == 0:
        decision = "BGWM003_PASS_FLOOR_PRESERVING_SANITY_ZERO_RESIDUAL"
    elif mean_metrics["mean_floor_gap_transition"] > 0.0 and mean_metrics["mean_floor_gap_delta_cosine"] >= 0.0:
        decision = "BGWM003_NONZERO_RESIDUAL_SELECTED_MULTISEED_V1_DIAGNOSTIC"
    else:
        decision = "BGWM003_PASS_GATES_BUT_RESIDUAL_DOES_NOT_BEAT_FLOOR"
    summary = {
        "diagnostic_label": decision,
        "benchmark_name": "synthetic_genetic_anchor_lite_multiseed_v1",
        "gates": gates,
        **mean_metrics,
        "model_promoted": False,
        "tier": "Tier1 sanity",
        "seed_rows": rows,
        "blocked_seeds": blocked,
        "identity": "frozen-latent Action-AdaLN + RoPE residual sanity; not a full JEPA promotion path",
        "leakage_controls": "per-seed train split only for floor/residual fitting; eval rows scoring-only; no condition_key/biological_key/exact target-key features as model inputs",
    }
    write_json(out / "metrics_eval.json", summary)
    table = "\n".join(
        f"| {row['seed']} | {row['transition_improvement']:.6f} | {row['delta_cosine']:.6f} | {row['recall_at_1']:.6f} | {row['residual_scale']:.3f} | {row['floor_gap_transition']:.6f} | {row['decision_label']} |"
        for row in rows
    )
    report = f"""# BGWM003 Multiseed v1 Action-AdaLN Sanity

## Decision
`{decision}`

## Active Gates
- transition improvement >= `{gates['primary_transition_gate']:.6f}`
- delta cosine >= `{gates['primary_delta_cosine_gate']:.6f}`
- secondary condition recall@1 >= `{gates['secondary_recall_gate']:.6f}`

## Seed Results
| seed | transition improvement | delta cosine | recall@1 | residual scale | floor-gap transition | train decision |
| ---: | ---: | ---: | ---: | ---: | ---: | --- |
{table}

## Interpretation
This is a low-compute Tier 1 sanity run for the activated multi-seed benchmark. It verifies whether the existing floor-preserving Action-AdaLN + RoPE residual path can run across seeds without regressing the new gates. It cannot promote the model of record and is not a full cross-modal JEPA validation.
"""
    (out / "BGWM003_MULTISEED_V1_ACTION_ADALN_SANITY.md").write_text(report, encoding="utf-8")
    append_journal(
        args.output_root,
        "BGWM003_MULTISEED_V1_ACTION_ADALN_SANITY",
        "Phase 8 v3 Tier 1 sanity",
        f"Ran Action-AdaLN floor-preserving residual sanity across {len(rows)} seeds; mean transition={mean_metrics['mean_transition_improvement']:.4f}, mean delta={mean_metrics['mean_delta_cosine']:.4f}, mean recall={mean_metrics['mean_recall_at_1']:.4f}; decision={decision}.",
    )
    return {
        "experiment_id": "BGWM003",
        "phase": "Phase8v3",
        "family": "action_adaln_rope_residual",
        "tier": "Tier1",
        "seed": "0,1,2,3,4",
        "dataset": "synthetic_genetic_anchor_lite_multiseed_v1",
        "eval_split": args.eval_split,
        "mode": "multiseed_v1_action_adaln_sanity",
        "status_label": decision,
        "transition_improvement": f"{mean_metrics['mean_transition_improvement']:.6f}",
        "delta_cosine": f"{mean_metrics['mean_delta_cosine']:.6f}",
        "recall_at_1": f"{mean_metrics['mean_recall_at_1']:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{mean_metrics['mean_delta_rank']:.6f}",
        "magnitude_ratio": f"{mean_metrics['mean_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{mean_metrics['mean_delta_rank']:.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": str(mean_metrics["mean_delta_rank"] < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{mean_metrics['mean_floor_gap_transition']:.6f}",
        "floor_gap_recall": f"{mean_metrics['mean_floor_gap_recall']:.6f}",
        "floor_gap_delta_cosine": f"{mean_metrics['mean_floor_gap_delta_cosine']:.6f}",
        "selected_residual_scale": f"{mean_metrics['mean_residual_scale']:.6f}",
        "calibration_lcb_transition_gap": f"{gates['primary_transition_gate']:.6f}",
        "calibration_lcb_recall_gap": f"{gates['secondary_recall_gate']:.6f}",
        "action_negative_gap": f"{float(frame['action_negative_gap'].mean()) if not frame.empty else 0.0:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Multiseed v1 Action-AdaLN sanity; no model promotion.",
        "artifact_dir": str(out),
    }


