def _load_multiseed_bundles(args: argparse.Namespace, out: Path, seeds: list[int]) -> dict[int, tuple[Any, Any]]:
    bundles: dict[int, tuple[Any, Any]] = {}
    current_train = load_latent_bundle(PHASE4_CACHE / f"{args.dataset}_train_latents", "f015_seed0_train")
    current_eval = load_latent_bundle(PHASE4_CACHE / f"{args.dataset}_{args.eval_split}_latents", "f015_seed0_eval")
    for seed in seeds:
        train_bundle, eval_bundle, _ = _load_registry_seed_bundle(args, out, seed, current_train, current_eval)
        if train_bundle is None or eval_bundle is None:
            continue
        bundles[seed] = (train_bundle, eval_bundle)
    return bundles


def _concat_arrays(items: list[np.ndarray]) -> np.ndarray:
    if not items:
        return np.empty((0, 0), dtype=np.float64)
    return np.concatenate([np.asarray(item, dtype=np.float64) for item in items], axis=0)


def _pooled_fit_inputs(bundles: dict[int, tuple[Any, Any]], seeds: list[int]) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
    sources = [bundles[seed][0].source for seed in seeds if seed in bundles]
    actions = [bundles[seed][0].action for seed in seeds if seed in bundles]
    deltas = [bundles[seed][0].delta for seed in seeds if seed in bundles]
    return _concat_arrays(sources), _concat_arrays(actions), _concat_arrays(deltas)


def _centered_pooled_fit(bundles: dict[int, tuple[Any, Any]], seeds: list[int]) -> tuple[Any, dict[int, np.ndarray], dict[int, np.ndarray]]:
    centered_features: list[np.ndarray] = []
    centered_deltas: list[np.ndarray] = []
    source_means: dict[int, np.ndarray] = {}
    delta_means: dict[int, np.ndarray] = {}
    for seed in seeds:
        if seed not in bundles:
            continue
        train_bundle = bundles[seed][0]
        source_mean = train_bundle.source.mean(axis=0, keepdims=True)
        delta_mean = train_bundle.delta.mean(axis=0, keepdims=True)
        source_means[seed] = source_mean
        delta_means[seed] = delta_mean
        centered_features.append(np.concatenate((train_bundle.source - source_mean, train_bundle.action), axis=1))
        centered_deltas.append(train_bundle.delta - delta_mean)
    fit = fit_ridge_numpy(_concat_arrays(centered_features), _concat_arrays(centered_deltas), alpha=1.0e-2)
    return fit, source_means, delta_means


def run_f015_multi_environment_transition_audit(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F015_multi_environment_transition_audit"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    gates = _active_multiseed_gates(args)
    bundles = _load_multiseed_bundles(args, out, seeds)
    available = [seed for seed in seeds if seed in bundles]
    source_all, action_all, delta_all = _pooled_fit_inputs(bundles, available)
    rows: list[dict[str, Any]] = []
    if available:
        pooled_full = fit_ridge_numpy(np.concatenate((source_all, action_all), axis=1), delta_all, alpha=1.0e-2)
        pooled_source = fit_ridge_numpy(source_all, delta_all, alpha=1.0e-2)
        if action_all.shape[1] > 0:
            pooled_action = fit_ridge_numpy(action_all, delta_all, alpha=1.0e-2)
        else:
            pooled_action = None
        centered_fit, source_means, delta_means = _centered_pooled_fit(bundles, available)
    else:
        pooled_full = pooled_source = pooled_action = centered_fit = None
        source_means = {}
        delta_means = {}
    for seed in available:
        train_bundle, eval_bundle = bundles[seed]
        baselines: list[tuple[str, np.ndarray]] = []
        per_seed_fit = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
        baselines.append(("per_seed_action_ridge_floor", predict_ridge_numpy(per_seed_fit, bundle_features(eval_bundle))))
        baselines.append(("pooled_full_ridge", predict_ridge_numpy(pooled_full, bundle_features(eval_bundle))))
        baselines.append(("pooled_source_only_ridge", predict_ridge_numpy(pooled_source, eval_bundle.source)))
        if pooled_action is not None:
            baselines.append(("pooled_action_only_ridge", predict_ridge_numpy(pooled_action, eval_bundle.action)))
        centered_features = np.concatenate((eval_bundle.source - source_means[seed], eval_bundle.action), axis=1)
        baselines.append(("pooled_environment_centered_ridge", predict_ridge_numpy(centered_fit, centered_features) + delta_means[seed]))
        other_seeds = [other for other in available if other != seed]
        if other_seeds:
            other_source, other_action, other_delta = _pooled_fit_inputs(bundles, other_seeds)
            loso_fit = fit_ridge_numpy(np.concatenate((other_source, other_action), axis=1), other_delta, alpha=1.0e-2)
            baselines.append(("leave_one_seed_out_full_ridge", predict_ridge_numpy(loso_fit, bundle_features(eval_bundle))))
        for baseline, pred_delta in baselines:
            metrics = bundle_transition_metrics(eval_bundle, pred_delta)
            rows.append(
                {
                    "seed": seed,
                    "baseline": baseline,
                    "transition_improvement": metrics["transition_source_cosine_improvement"],
                    "delta_cosine": metrics["delta_cosine"],
                    "condition_recall_at_1": metrics["transition_to_target_recall@1"],
                    "condition_median_rank": metrics["transition_to_target_median_rank"],
                    "delta_rank": metrics["delta_prediction_effective_rank"],
                    "magnitude_ratio": metrics["delta_magnitude_ratio"],
                    "source_improvement_hinge_violation_fraction": metrics["source_improvement_hinge_violation_fraction"],
                }
            )
    frame = pd.DataFrame(rows)
    frame.to_csv(out / "environment_transition_by_seed.tsv", sep="\t", index=False)
    summary = (
        frame.groupby("baseline", as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_transition_improvement=("transition_improvement", "mean"),
            min_transition_improvement=("transition_improvement", "min"),
            mean_delta_cosine=("delta_cosine", "mean"),
            mean_condition_recall_at_1=("condition_recall_at_1", "mean"),
            min_condition_recall_at_1=("condition_recall_at_1", "min"),
            mean_delta_rank=("delta_rank", "mean"),
            mean_magnitude_ratio=("magnitude_ratio", "mean"),
        )
        .sort_values(["mean_transition_improvement", "mean_delta_cosine"], ascending=False)
        if not frame.empty
        else pd.DataFrame()
    )
    summary.to_csv(out / "environment_transition_summary.tsv", sep="\t", index=False)
    floor_row = summary[summary["baseline"] == "per_seed_action_ridge_floor"].iloc[0].to_dict() if not summary.empty and (summary["baseline"] == "per_seed_action_ridge_floor").any() else {}
    candidates = summary[summary["baseline"] != "per_seed_action_ridge_floor"].copy() if not summary.empty else pd.DataFrame()
    if not candidates.empty:
        candidates["transition_gap_vs_per_seed_floor"] = candidates["mean_transition_improvement"] - float(floor_row.get("mean_transition_improvement", 0.0))
        candidates["delta_gap_vs_per_seed_floor"] = candidates["mean_delta_cosine"] - float(floor_row.get("mean_delta_cosine", 0.0))
        candidates["recall_gap_vs_per_seed_floor"] = candidates["mean_condition_recall_at_1"] - float(floor_row.get("mean_condition_recall_at_1", 0.0))
        best = candidates.sort_values(["transition_gap_vs_per_seed_floor", "delta_gap_vs_per_seed_floor"], ascending=False).iloc[0].to_dict()
    else:
        best = {}
    best_transition_gap = float(best.get("transition_gap_vs_per_seed_floor", 0.0))
    best_delta_gap = float(best.get("delta_gap_vs_per_seed_floor", 0.0))
    best_recall = float(best.get("mean_condition_recall_at_1", 0.0))
    if best_transition_gap > 0.001 and best_delta_gap >= -0.01 and best_recall >= gates["secondary_recall_gate"]:
        decision = "F015_POOLED_ENVIRONMENT_TRANSITION_HAS_HEADROOM"
    elif float(best.get("mean_transition_improvement", -1.0)) >= gates["primary_transition_gate"] and float(best.get("mean_delta_cosine", -1.0)) >= gates["primary_delta_cosine_gate"]:
        decision = "F015_POOLED_ENVIRONMENT_TRANSITION_PASSES_GATES_BELOW_PER_SEED_FLOOR"
    else:
        decision = "F015_PER_SEED_ACTION_RIDGE_REMAINS_ENVIRONMENT_FLOOR_LIMIT"
    payload = {
        "diagnostic_label": decision,
        "benchmark_name": "synthetic_genetic_anchor_lite_multiseed_v1",
        "gates": gates,
        "available_seeds": available,
        "per_seed_floor_summary": floor_row,
        "best_non_floor_baseline": best,
        "baseline_summary": summary.to_dict("records") if not summary.empty else [],
        "model_promoted": False,
        "leakage_controls": "all pooled/environment baselines use train splits only; eval rows are scoring-only; seed/environment labels are diagnostic grouping variables, not promoted biological shortcuts",
    }
    write_json(out / "metrics_eval.json", payload)
    table = "\n".join(
        f"| {row['baseline']} | {int(row['seed_count'])} | {row['mean_transition_improvement']:.6f} | {row['mean_delta_cosine']:.6f} | {row['mean_condition_recall_at_1']:.6f} | {row['mean_delta_rank']:.6f} |"
        for row in summary.to_dict("records")
    )
    report = f"""# F015 Multi-Environment Transition Audit

## Decision
`{decision}`

## Baseline Summary
| baseline | seeds | mean transition improvement | mean delta cosine | mean condition recall@1 | mean delta rank |
| --- | ---: | ---: | ---: | ---: | ---: |
{table}

## Interpretation
This diagnostic tests whether multi-seed/environment pooling or train-only environment centering gives transition headroom beyond the per-seed action-ridge floor. It is not a JEPA candidate and cannot promote the model of record.
"""
    (out / "F015_MULTI_ENVIRONMENT_TRANSITION_AUDIT.md").write_text(report, encoding="utf-8")
    append_journal(
        args.output_root,
        "F015_MULTI_ENVIRONMENT_TRANSITION_AUDIT",
        "Metric/data redesign diagnostic",
        f"Best non-floor baseline={best.get('baseline', 'none')} transition gap={best_transition_gap:.4f}, delta gap={best_delta_gap:.4f}; decision={decision}.",
    )
    return {
        "experiment_id": "F015",
        "phase": "PostPhase8Council",
        "family": "Metric and data redesign",
        "tier": "Diagnostic",
        "seed": "0,1,2,3,4",
        "dataset": "synthetic_genetic_anchor_lite_multiseed_v1",
        "eval_split": args.eval_split,
        "mode": "multi_environment_transition_audit",
        "status_label": decision,
        "transition_improvement": f"{float(best.get('mean_transition_improvement', 0.0)):.6f}",
        "delta_cosine": f"{float(best.get('mean_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(best.get('mean_condition_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(best.get('mean_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(best.get('mean_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(best.get('mean_delta_rank', 0.0)):.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": str(float(best.get("mean_delta_rank", 0.0)) < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{best_transition_gap:.6f}",
        "floor_gap_recall": f"{float(best.get('recall_gap_vs_per_seed_floor', 0.0)):.6f}",
        "floor_gap_delta_cosine": f"{best_delta_gap:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{gates['primary_transition_gate']:.6f}",
        "calibration_lcb_recall_gap": f"{gates['secondary_recall_gate']:.6f}",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Multi-environment transition diagnostic; no model promotion.",
        "artifact_dir": str(out),
    }


