def _risk_feature_matrix(payloads: list[dict[str, Any]], feature_names: list[str]) -> tuple[np.ndarray, np.ndarray, list[int]]:
    xs: list[np.ndarray] = []
    ys: list[np.ndarray] = []
    payload_indices: list[int] = []
    for payload_index, payload in enumerate(payloads):
        features = [np.asarray(payload["features"][name], dtype=np.float64).reshape(-1, 1) for name in feature_names]
        x = np.concatenate(features, axis=1) if features else np.empty((payload["bundle"].source.shape[0], 0), dtype=np.float64)
        xs.append(x)
        ys.append(np.asarray(payload["oracle_safe_mask"], dtype=np.float64))
        payload_indices.extend([payload_index] * x.shape[0])
    if not xs:
        return np.empty((0, 0), dtype=np.float64), np.empty((0,), dtype=np.float64), []
    return np.concatenate(xs, axis=0), np.concatenate(ys, axis=0), payload_indices


def _fit_linear_risk_score(x: np.ndarray, y: np.ndarray, *, alpha: float = 1.0e-2) -> dict[str, np.ndarray]:
    x = np.asarray(x, dtype=np.float64)
    y = np.asarray(y, dtype=np.float64).reshape(-1, 1)
    if x.shape[0] == 0:
        return {"mean": np.zeros((1, x.shape[1])), "scale": np.ones((1, x.shape[1])), "coef": np.zeros((x.shape[1] + 1, 1))}
    mean = x.mean(axis=0, keepdims=True)
    scale = x.std(axis=0, keepdims=True)
    scale = np.where(scale < 1.0e-8, 1.0, scale)
    xn = (x - mean) / scale
    design = np.concatenate((np.ones((xn.shape[0], 1), dtype=np.float64), xn), axis=1)
    eye = np.eye(design.shape[1], dtype=np.float64)
    eye[0, 0] = 0.0
    coef = np.linalg.solve(design.T @ design + float(alpha) * eye, design.T @ y)
    return {"mean": mean, "scale": scale, "coef": coef}


def _predict_linear_risk_score(model: dict[str, np.ndarray], x: np.ndarray) -> np.ndarray:
    x = np.asarray(x, dtype=np.float64)
    xn = (x - model["mean"]) / model["scale"]
    design = np.concatenate((np.ones((xn.shape[0], 1), dtype=np.float64), xn), axis=1)
    return (design @ model["coef"]).reshape(-1)


def _payload_feature_matrix(payload: dict[str, Any], feature_names: list[str]) -> np.ndarray:
    features = [np.asarray(payload["features"][name], dtype=np.float64).reshape(-1, 1) for name in feature_names]
    return np.concatenate(features, axis=1) if features else np.empty((payload["bundle"].source.shape[0], 0), dtype=np.float64)


def _calibrate_learned_risk_gate(payloads: list[dict[str, Any]]) -> tuple[pd.DataFrame, dict[str, Any], list[str]]:
    if not payloads:
        return pd.DataFrame(), {"candidate": "floor_fallback", "alpha": 0.0, "threshold": 0.0, "selection_label": "F020_NO_PAYLOADS_FLOOR_FALLBACK"}, []
    feature_names = sorted(payloads[0]["features"].keys())
    rows: list[dict[str, Any]] = []
    groups = sorted({(str(payload["candidate"]), float(payload["alpha"])) for payload in payloads})
    for candidate, alpha in groups:
        group_payloads = [payload for payload in payloads if payload["candidate"] == candidate and float(payload["alpha"]) == float(alpha)]
        if len(group_payloads) < 2:
            continue
        scores_by_payload: list[np.ndarray] = []
        for payload_index, payload in enumerate(group_payloads):
            train_payloads = [item for index, item in enumerate(group_payloads) if index != payload_index]
            x_train, y_train, _ = _risk_feature_matrix(train_payloads, feature_names)
            model = _fit_linear_risk_score(x_train, y_train)
            scores_by_payload.append(_predict_linear_risk_score(model, _payload_feature_matrix(payload, feature_names)))
        score_values = np.concatenate(scores_by_payload)
        thresholds = np.unique(np.quantile(score_values, [0.25, 0.35, 0.5, 0.65, 0.75, 0.85, 0.9]))
        for threshold in thresholds:
            fold_rows: list[dict[str, float]] = []
            for payload, scores in zip(group_payloads, scores_by_payload, strict=True):
                mask = scores >= float(threshold)
                pred_delta = payload["floor_pred"].copy()
                pred_delta[mask] = payload["blend_pred"][mask]
                metrics = bundle_transition_metrics(payload["bundle"], pred_delta)
                floor_metrics = payload["floor_metrics"]
                fold_rows.append(
                    {
                        "active_fraction": float(np.mean(mask)),
                        "safe_active_fraction": float(np.mean(mask & payload["oracle_safe_mask"])),
                        "unsafe_active_fraction": float(np.mean(mask & ~payload["oracle_safe_mask"])),
                        "transition_gap": metrics["transition_source_cosine_improvement"] - floor_metrics["transition_source_cosine_improvement"],
                        "delta_cosine_gap": metrics["delta_cosine"] - floor_metrics["delta_cosine"],
                        "recall_gap": metrics["transition_to_target_recall@1"] - floor_metrics["transition_to_target_recall@1"],
                    }
                )
            frame = pd.DataFrame(fold_rows)
            rows.append(
                {
                    "candidate": candidate,
                    "alpha": float(alpha),
                    "threshold": float(threshold),
                    "payload_count": int(len(group_payloads)),
                    "mean_active_fraction": float(frame["active_fraction"].mean()),
                    "mean_safe_active_fraction": float(frame["safe_active_fraction"].mean()),
                    "mean_unsafe_active_fraction": float(frame["unsafe_active_fraction"].mean()),
                    "mean_transition_gap": float(frame["transition_gap"].mean()),
                    "min_transition_gap": float(frame["transition_gap"].min()),
                    "mean_delta_cosine_gap": float(frame["delta_cosine_gap"].mean()),
                    "min_delta_cosine_gap": float(frame["delta_cosine_gap"].min()),
                    "mean_recall_gap": float(frame["recall_gap"].mean()),
                    "min_recall_gap": float(frame["recall_gap"].min()),
                }
            )
    summary = pd.DataFrame(rows)
    if summary.empty:
        return summary, {"candidate": "floor_fallback", "alpha": 0.0, "threshold": 0.0, "selection_label": "F020_NO_OOF_RULES_FLOOR_FALLBACK"}, feature_names
    passing = summary[
        (summary["mean_active_fraction"] >= 0.05)
        & (summary["mean_transition_gap"] > 0.0)
        & (summary["min_transition_gap"] >= 0.0)
        & (summary["mean_delta_cosine_gap"] >= 0.0)
        & (summary["min_delta_cosine_gap"] >= 0.0)
        & (summary["mean_recall_gap"] >= 0.0)
        & (summary["min_recall_gap"] >= 0.0)
    ].copy()
    if passing.empty:
        return summary, {
            "candidate": "floor_fallback",
            "alpha": 0.0,
            "threshold": 0.0,
            "mean_transition_gap": 0.0,
            "mean_delta_cosine_gap": 0.0,
            "mean_recall_gap": 0.0,
            "selection_label": "F020_OOF_LEARNED_RISK_SELECTS_FLOOR_FALLBACK",
        }, feature_names
    row = passing.sort_values(
        ["mean_transition_gap", "mean_delta_cosine_gap", "mean_recall_gap", "mean_active_fraction"],
        ascending=False,
    ).iloc[0].to_dict()
    return summary, {**row, "selection_label": "F020_OOF_LEARNED_RISK_SELECTS_NONZERO_RULE"}, feature_names


def _evaluate_learned_risk_gate(
    bundles: dict[int, tuple[Any, Any]],
    seeds: list[int],
    selected: dict[str, Any],
    train_payloads: list[dict[str, Any]],
    feature_names: list[str],
) -> tuple[pd.DataFrame, pd.DataFrame]:
    candidate = str(selected.get("candidate", "floor_fallback"))
    alpha = float(selected.get("alpha", 0.0))
    threshold = float(selected.get("threshold", 0.0))
    rows: list[dict[str, Any]] = []
    if candidate == "floor_fallback" or alpha == 0.0:
        model = None
    else:
        group_payloads = [payload for payload in train_payloads if payload["candidate"] == candidate and float(payload["alpha"]) == alpha]
        x_train, y_train, _ = _risk_feature_matrix(group_payloads, feature_names)
        model = _fit_linear_risk_score(x_train, y_train)
    train_bundles = {seed: bundles[seed][0] for seed in seeds if seed in bundles}
    fit_seeds = [seed for seed in seeds if seed in train_bundles]
    models = _fit_environment_blend_models(train_bundles, fit_seeds) if fit_seeds else {}
    reference_source, reference_action, reference_delta = _pooled_train_arrays_from_bundles(train_bundles, fit_seeds)
    for seed in fit_seeds:
        train_bundle, eval_bundle = bundles[seed]
        floor_fit = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
        floor_pred = predict_ridge_numpy(floor_fit, bundle_features(eval_bundle))
        if model is None:
            blend_pred = floor_pred
            mask = np.zeros(eval_bundle.source.shape[0], dtype=bool)
        else:
            candidate_pred = _predict_environment_blend_candidate(models, candidate, seed, eval_bundle)
            blend_pred = floor_pred + alpha * (candidate_pred - floor_pred)
            features = _risk_proxy_features(eval_bundle, floor_pred, blend_pred, reference_source, reference_delta, reference_action)
            scores = _predict_linear_risk_score(model, np.concatenate([features[name].reshape(-1, 1) for name in feature_names], axis=1))
            mask = scores >= threshold
        pred_delta = floor_pred.copy()
        pred_delta[mask] = blend_pred[mask]
        metrics = bundle_transition_metrics(eval_bundle, pred_delta)
        floor_metrics = bundle_transition_metrics(eval_bundle, floor_pred)
        rows.append(
            {
                "seed": seed,
                "active_fraction": float(np.mean(mask)),
                "transition_improvement": metrics["transition_source_cosine_improvement"],
                "delta_cosine": metrics["delta_cosine"],
                "condition_recall_at_1": metrics["transition_to_target_recall@1"],
                "condition_median_rank": metrics["transition_to_target_median_rank"],
                "delta_rank": metrics["delta_prediction_effective_rank"],
                "magnitude_ratio": metrics["delta_magnitude_ratio"],
                "floor_transition_improvement": floor_metrics["transition_source_cosine_improvement"],
                "floor_delta_cosine": floor_metrics["delta_cosine"],
                "floor_condition_recall_at_1": floor_metrics["transition_to_target_recall@1"],
                "transition_gap_vs_per_seed_floor": metrics["transition_source_cosine_improvement"] - floor_metrics["transition_source_cosine_improvement"],
                "delta_cosine_gap_vs_per_seed_floor": metrics["delta_cosine"] - floor_metrics["delta_cosine"],
                "recall_gap_vs_per_seed_floor": metrics["transition_to_target_recall@1"] - floor_metrics["transition_to_target_recall@1"],
            }
        )
    frame = pd.DataFrame(rows)
    if frame.empty:
        return frame, pd.DataFrame()
    summary = frame.groupby(lambda _: 0).agg(
        seed_count=("seed", "nunique"),
        mean_active_fraction=("active_fraction", "mean"),
        mean_transition_improvement=("transition_improvement", "mean"),
        min_transition_improvement=("transition_improvement", "min"),
        mean_delta_cosine=("delta_cosine", "mean"),
        min_delta_cosine=("delta_cosine", "min"),
        mean_condition_recall_at_1=("condition_recall_at_1", "mean"),
        min_condition_recall_at_1=("condition_recall_at_1", "min"),
        mean_delta_rank=("delta_rank", "mean"),
        mean_magnitude_ratio=("magnitude_ratio", "mean"),
        mean_transition_gap=("transition_gap_vs_per_seed_floor", "mean"),
        min_transition_gap=("transition_gap_vs_per_seed_floor", "min"),
        mean_delta_cosine_gap=("delta_cosine_gap_vs_per_seed_floor", "mean"),
        min_delta_cosine_gap=("delta_cosine_gap_vs_per_seed_floor", "min"),
        mean_recall_gap=("recall_gap_vs_per_seed_floor", "mean"),
        min_recall_gap=("recall_gap_vs_per_seed_floor", "min"),
    ).reset_index(drop=True)
    summary.insert(0, "candidate", candidate)
    summary.insert(1, "alpha", alpha)
    summary.insert(2, "threshold", threshold)
    return frame, summary


def run_f020_learned_environment_risk_gate(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F020_learned_environment_risk_gate"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    gates = _active_multiseed_gates(args)
    bundles = _load_multiseed_bundles(args, out, seeds)
    available = [seed for seed in seeds if seed in bundles]
    candidates = ["pooled_source_only_ridge", "pooled_full_ridge", "pooled_environment_centered_ridge"]
    alphas = np.asarray([0.2, 0.35, 0.5, 0.75, 1.0], dtype=np.float64)
    train_payloads = _environment_risk_payloads(bundles, available, candidates, alphas)
    calibration_summary, selected, feature_names = _calibrate_learned_risk_gate(train_payloads)
    eval_frame, eval_summary = _evaluate_learned_risk_gate(bundles, available, selected, train_payloads, feature_names)
    calibration_summary.to_csv(out / "learned_risk_oof_calibration_summary.tsv", sep="\t", index=False)
    eval_frame.to_csv(out / "learned_risk_heldout_by_seed.tsv", sep="\t", index=False)
    eval_summary.to_csv(out / "learned_risk_heldout_summary.tsv", sep="\t", index=False)
    eval_row = eval_summary.iloc[0].to_dict() if not eval_summary.empty else {}
    selected_nonzero = str(selected.get("candidate", "floor_fallback")) != "floor_fallback" and float(selected.get("alpha", 0.0)) > 0.0
    heldout_preserves_floor = (
        float(eval_row.get("mean_transition_gap", -1.0)) >= 0.0
        and float(eval_row.get("min_transition_gap", -1.0)) >= 0.0
        and float(eval_row.get("mean_recall_gap", -1.0)) >= 0.0
        and float(eval_row.get("min_recall_gap", -1.0)) >= 0.0
        and float(eval_row.get("mean_delta_cosine_gap", -1.0)) >= 0.0
        and float(eval_row.get("min_delta_cosine_gap", -1.0)) >= 0.0
    )
    heldout_passes_active_gates = (
        float(eval_row.get("mean_transition_improvement", -1.0)) >= gates["primary_transition_gate"]
        and float(eval_row.get("mean_delta_cosine", -1.0)) >= gates["primary_delta_cosine_gate"]
        and float(eval_row.get("mean_condition_recall_at_1", -1.0)) >= gates["secondary_recall_gate"]
    )
    if not selected_nonzero:
        decision = "F020_OOF_LEARNED_RISK_SELECTS_FLOOR_FALLBACK"
    elif heldout_preserves_floor and heldout_passes_active_gates:
        decision = "F020_LEARNED_RISK_NONZERO_PRESERVES_FLOOR_DIAGNOSTIC"
    else:
        decision = "F020_LEARNED_RISK_DISCARDED_HELDOUT_BELOW_FLOOR"
    payload = {
        "diagnostic_label": decision,
        "benchmark_name": "synthetic_genetic_anchor_lite_multiseed_v1",
        "gates": gates,
        "available_seeds": available,
        "feature_names": feature_names,
        "selected_rule": selected,
        "heldout_summary": eval_summary.to_dict("records") if not eval_summary.empty else [],
        "model_promoted": False,
        "leakage_controls": "linear risk model is fit and thresholded on train-only perturbation-fold labels; eval rows are scoring-only",
    }
    write_json(out / "metrics_eval.json", payload)
    top = calibration_summary.sort_values("mean_transition_gap", ascending=False).head(10) if not calibration_summary.empty else pd.DataFrame()
    table = "\n".join(
        f"| {row['candidate']} | {row['alpha']:.3f} | {row['threshold']:.6f} | {row['mean_active_fraction']:.6f} | {row['mean_transition_gap']:.6f} | {row['min_transition_gap']:.6f} | {row['mean_delta_cosine_gap']:.6f} | {row['mean_recall_gap']:.6f} | {row['min_recall_gap']:.6f} |"
        for row in top.to_dict("records")
    )
    seed_table = "\n".join(
        f"| {row['seed']} | {row['active_fraction']:.6f} | {row['transition_improvement']:.6f} | {row['delta_cosine']:.6f} | {row['condition_recall_at_1']:.6f} | {row['transition_gap_vs_per_seed_floor']:.6f} | {row['recall_gap_vs_per_seed_floor']:.6f} |"
        for row in eval_frame.to_dict("records")
    )
    report = f"""# F020 Learned Environment Risk Gate

## Decision
`{decision}`

## Selected Train-Only Learned Rule
- candidate: `{selected.get('candidate', 'floor_fallback')}`
- alpha: `{float(selected.get('alpha', 0.0)):.6f}`
- threshold: `{float(selected.get('threshold', 0.0)):.6f}`
- selection label: `{selected.get('selection_label', '')}`
- features: `{', '.join(feature_names)}`

## Top Out-Of-Fold Calibration Rules
| candidate | alpha | threshold | active fraction | mean transition gap | min transition gap | mean delta gap | mean recall gap | min recall gap |
| --- | ---: | ---: | ---: | ---: | ---: | ---: | ---: | ---: |
{table}

## Held-Out Seed Scoring
| seed | active fraction | transition improvement | delta cosine | condition recall@1 | transition gap vs floor | recall gap vs floor |
| ---: | ---: | ---: | ---: | ---: | ---: | ---: |
{seed_table}

## Interpretation
F020 is the final low-compute test of the environment-blend branch before cooling it: a learned linear risk score is fit only from train perturbation folds and then frozen for held-out scoring. It cannot promote the model of record.
"""
    (out / "F020_LEARNED_ENVIRONMENT_RISK_GATE.md").write_text(report, encoding="utf-8")
    append_journal(
        args.output_root,
        "F020_LEARNED_ENVIRONMENT_RISK_GATE",
        "Metric/data redesign diagnostic",
        f"Selected rule={selected.get('candidate', 'floor_fallback')} alpha={float(selected.get('alpha', 0.0)):.3f}; heldout transition gap={float(eval_row.get('mean_transition_gap', 0.0)):.4f}, min recall gap={float(eval_row.get('min_recall_gap', 0.0)):.4f}; decision={decision}.",
    )
    return {
        "experiment_id": "F020",
        "phase": "PostPhase8Council",
        "family": "Metric and data redesign",
        "tier": "Diagnostic",
        "seed": "0,1,2,3,4",
        "dataset": "synthetic_genetic_anchor_lite_multiseed_v1",
        "eval_split": args.eval_split,
        "mode": "learned_environment_risk_gate",
        "status_label": decision,
        "transition_improvement": f"{float(eval_row.get('mean_transition_improvement', 0.0)):.6f}",
        "delta_cosine": f"{float(eval_row.get('mean_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(eval_row.get('mean_condition_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(eval_row.get('mean_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(eval_row.get('mean_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(eval_row.get('mean_delta_rank', 0.0)):.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": str(float(eval_row.get("mean_delta_rank", 0.0)) < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{float(eval_row.get('mean_transition_gap', 0.0)):.6f}",
        "floor_gap_recall": f"{float(eval_row.get('mean_recall_gap', 0.0)):.6f}",
        "floor_gap_delta_cosine": f"{float(eval_row.get('mean_delta_cosine_gap', 0.0)):.6f}",
        "selected_residual_scale": f"{float(selected.get('alpha', 0.0)):.6f}",
        "calibration_lcb_transition_gap": f"{float(eval_row.get('min_transition_gap', 0.0)):.6f}",
        "calibration_lcb_recall_gap": f"{float(eval_row.get('min_recall_gap', 0.0)):.6f}",
        "action_negative_gap": f"{float(eval_row.get('mean_active_fraction', 0.0)):.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Train-only learned environment risk gate diagnostic; no model promotion.",
        "artifact_dir": str(out),
    }


