def _online_latent_bundle(bundle, name: str):
    arrays = dict(bundle.arrays)
    if "source_z_bio_online" not in arrays or "target_z_bio_online" not in arrays:
        return None
    arrays["source_z_bio_teacher"] = np.asarray(arrays["source_z_bio_online"], dtype=np.float64)
    arrays["target_z_bio_teacher"] = np.asarray(arrays["target_z_bio_online"], dtype=np.float64)
    return type(bundle)(name=name, arrays=arrays, metadata=bundle.metadata.copy())


def run_c016_online_latent_transition_audit(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/C016_online_latent_transition_audit"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    gates = _active_multiseed_gates(args)
    bundles = _load_multiseed_bundles(args, out, seeds)
    available = [seed for seed in seeds if seed in bundles]
    rows: list[dict[str, Any]] = []
    for seed in available:
        train_bundle, eval_bundle = bundles[seed]
        teacher_fit = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
        teacher_delta = predict_ridge_numpy(teacher_fit, bundle_features(eval_bundle))
        teacher_metrics = bundle_transition_metrics(eval_bundle, teacher_delta)
        online_train = _online_latent_bundle(train_bundle, f"c016_seed{seed}_online_train")
        online_eval = _online_latent_bundle(eval_bundle, f"c016_seed{seed}_online_eval")
        if online_train is None or online_eval is None:
            rows.append({"seed": seed, "space": "online_action_ridge", "status": "missing_online_latents"})
            continue
        online_fit = fit_ridge_numpy(bundle_features(online_train), online_train.delta, alpha=1.0e-2)
        online_delta = predict_ridge_numpy(online_fit, bundle_features(online_eval))
        online_metrics = bundle_transition_metrics(online_eval, online_delta)
        rows.extend(
            [
                {
                    "seed": seed,
                    "space": "teacher_action_ridge_floor",
                    "status": "completed",
                    "transition_improvement": teacher_metrics["transition_source_cosine_improvement"],
                    "delta_cosine": teacher_metrics["delta_cosine"],
                    "condition_recall_at_1": teacher_metrics["transition_to_target_recall@1"],
                    "condition_median_rank": teacher_metrics["transition_to_target_median_rank"],
                    "delta_rank": teacher_metrics["delta_prediction_effective_rank"],
                    "magnitude_ratio": teacher_metrics["delta_magnitude_ratio"],
                },
                {
                    "seed": seed,
                    "space": "online_action_ridge_floor",
                    "status": "completed",
                    "transition_improvement": online_metrics["transition_source_cosine_improvement"],
                    "delta_cosine": online_metrics["delta_cosine"],
                    "condition_recall_at_1": online_metrics["transition_to_target_recall@1"],
                    "condition_median_rank": online_metrics["transition_to_target_median_rank"],
                    "delta_rank": online_metrics["delta_prediction_effective_rank"],
                    "magnitude_ratio": online_metrics["delta_magnitude_ratio"],
                    "transition_gap_vs_teacher": online_metrics["transition_source_cosine_improvement"] - teacher_metrics["transition_source_cosine_improvement"],
                    "delta_gap_vs_teacher": online_metrics["delta_cosine"] - teacher_metrics["delta_cosine"],
                    "recall_gap_vs_teacher": online_metrics["transition_to_target_recall@1"] - teacher_metrics["transition_to_target_recall@1"],
                },
            ]
        )
    frame = pd.DataFrame(rows)
    frame.to_csv(out / "online_latent_transition_by_seed.tsv", sep="\t", index=False)
    completed = frame[frame["status"] == "completed"].copy() if "status" in frame.columns else pd.DataFrame()
    summary = (
        completed.groupby("space", as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_transition_improvement=("transition_improvement", "mean"),
            min_transition_improvement=("transition_improvement", "min"),
            mean_delta_cosine=("delta_cosine", "mean"),
            min_delta_cosine=("delta_cosine", "min"),
            mean_condition_recall_at_1=("condition_recall_at_1", "mean"),
            min_condition_recall_at_1=("condition_recall_at_1", "min"),
            mean_delta_rank=("delta_rank", "mean"),
            mean_magnitude_ratio=("magnitude_ratio", "mean"),
        )
        if not completed.empty
        else pd.DataFrame()
    )
    summary.to_csv(out / "online_latent_transition_summary.tsv", sep="\t", index=False)
    teacher = summary[summary["space"] == "teacher_action_ridge_floor"].iloc[0].to_dict() if not summary.empty and (summary["space"] == "teacher_action_ridge_floor").any() else {}
    online = summary[summary["space"] == "online_action_ridge_floor"].iloc[0].to_dict() if not summary.empty and (summary["space"] == "online_action_ridge_floor").any() else {}
    online_passes = (
        int(online.get("seed_count", 0)) == len(seeds)
        and float(online.get("mean_transition_improvement", -1.0)) >= gates["primary_transition_gate"]
        and float(online.get("mean_delta_cosine", -1.0)) >= gates["primary_delta_cosine_gate"]
        and float(online.get("mean_condition_recall_at_1", -1.0)) >= gates["secondary_recall_gate"]
    )
    recall_gain = float(online.get("mean_condition_recall_at_1", 0.0)) - float(teacher.get("mean_condition_recall_at_1", 0.0))
    transition_gain = float(online.get("mean_transition_improvement", 0.0)) - float(teacher.get("mean_transition_improvement", 0.0))
    if online_passes and recall_gain > 0.0:
        decision = "C016_ONLINE_LATENT_REPRESENTATION_HAS_REPAIR_SIGNAL"
    elif online_passes:
        decision = "C016_ONLINE_LATENT_PASSES_ACTIVE_GATES_NO_RECALL_GAIN"
    else:
        decision = "C016_ONLINE_LATENT_REPRESENTATION_NOT_READY"
    payload = {
        "diagnostic_label": decision,
        "gates": gates,
        "teacher_summary": teacher,
        "online_summary": online,
        "online_passes_active_gates": online_passes,
        "online_recall_gain_vs_teacher": recall_gain,
        "online_transition_gain_vs_teacher": transition_gain,
        "model_promoted": False,
        "leakage_controls": "all ridge fits use train splits only; eval rows are scoring-only; online latent arrays are cached encoder outputs, not metadata keys",
    }
    write_json(out / "metrics_eval.json", payload)
    table = "\n".join(
        f"| {row['space']} | {int(row['seed_count'])} | {row['mean_transition_improvement']:.6f} | {row['mean_delta_cosine']:.6f} | {row['mean_condition_recall_at_1']:.6f} | {row['mean_delta_rank']:.6f} |"
        for row in summary.to_dict("records")
    )
    report = f"""# C016 Online Latent Transition Audit

## Decision
`{decision}`

## Active Gates
- transition improvement >= `{gates['primary_transition_gate']:.6f}`
- delta cosine >= `{gates['primary_delta_cosine_gate']:.6f}`
- condition recall@1 >= `{gates['secondary_recall_gate']:.6f}`

## Summary
| space | seeds | mean transition | mean delta cosine | mean recall@1 | mean delta rank |
| --- | ---: | ---: | ---: | ---: | ---: |
{table}

## Interpretation
This audit tests whether the online/source-state-preserving latent space carries a better action-conditioned transition signal than the teacher latent space under the active multiseed gates. It is diagnostic only and cannot promote a model.
"""
    (out / "C016_ONLINE_LATENT_TRANSITION_AUDIT.md").write_text(report, encoding="utf-8")
    append_journal(
        args.output_root,
        "C016_ONLINE_LATENT_TRANSITION_AUDIT",
        "Representation repair diagnostic",
        f"Online passes active gates={online_passes}; recall gain vs teacher={recall_gain:.4f}; transition gain vs teacher={transition_gain:.4f}; decision={decision}.",
    )
    return {
        "experiment_id": "C016",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Diagnostic",
        "seed": "0,1,2,3,4",
        "dataset": "synthetic_genetic_anchor_lite_multiseed_v1",
        "eval_split": args.eval_split,
        "mode": "online_latent_transition_audit",
        "status_label": decision,
        "transition_improvement": f"{float(online.get('mean_transition_improvement', 0.0)):.6f}",
        "delta_cosine": f"{float(online.get('mean_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(online.get('mean_condition_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(online.get('mean_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(online.get('mean_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(online.get('mean_delta_rank', 0.0)):.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": str(float(online.get("mean_delta_rank", 0.0)) < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{transition_gain:.6f}",
        "floor_gap_recall": f"{recall_gain:.6f}",
        "floor_gap_delta_cosine": f"{float(online.get('mean_delta_cosine', 0.0)) - float(teacher.get('mean_delta_cosine', 0.0)):.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{gates['primary_transition_gate']:.6f}",
        "calibration_lcb_recall_gap": f"{gates['secondary_recall_gate']:.6f}",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Online latent representation transition audit; no model promotion.",
        "artifact_dir": str(out),
    }


