def _write_f024_report(path: Path, payload: dict[str, Any], support_summary: pd.DataFrame, metric_summary: pd.DataFrame, combined: pd.DataFrame) -> None:
    support_tsv = support_summary.to_csv(sep="\t", index=False) if not support_summary.empty else "No support summary rows.\n"
    metric_tsv = metric_summary.to_csv(sep="\t", index=False) if not metric_summary.empty else "No metric summary rows.\n"
    combined_tsv = combined.to_csv(sep="\t", index=False) if not combined.empty else "No combined rows.\n"
    path.write_text(
        f"""# F024 Heldout Action Descriptor Support Audit

## Decision
`{payload['diagnostic_label']}`

## Purpose
F023 found that source geometry explains much of the old positive floor, while correct action still has a small but measurable advantage over wrong action. This audit checks whether held-out perturbation descriptors have train support or whether exact held-out action dimensions are unsupported.

## Key Metrics
- mean support fraction: `{payload['mean_support_fraction']:.6f}`
- mean full-minus-wrong transition gain: `{payload['mean_full_minus_wrong_transition']:.6f}`
- mean full-minus-source transition gain: `{payload['mean_full_minus_source_transition']:.6f}`
- fraction of held-out action groups with positive action gain > 0.001: `{payload['positive_action_fraction']:.6f}`

## Support Summary
```tsv
{support_tsv}
```

## Metric Summary
```tsv
{metric_tsv}
```

## Combined Summary
```tsv
{combined_tsv}
```

## Interpretation
This audit uses condition/action labels only to diagnose descriptor coverage and per-action scoring. It does not promote a model and does not use metadata as a candidate input.
""",
        encoding="utf-8",
    )


def run_f025_program_only_action_descriptor_audit(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F025_program_only_action_descriptor_audit"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    gates = _active_multiseed_gates(args)
    bundles = _load_multiseed_bundles(args, out, seeds)
    dataset0 = generate_synthetic_biology_lite(synthetic_lite_config(args.dataset, seed=0))
    gene_dim = int(dataset0.config.num_perturbations)
    rows: list[dict[str, Any]] = []
    for seed in seeds:
        if seed not in bundles:
            rows.append({"seed": seed, "baseline": "all", "status": "missing_bundle"})
            continue
        train_bundle, eval_bundle = bundles[seed]
        supported_cols = np.flatnonzero((np.abs(train_bundle.action) > 1.0e-8).sum(axis=0) > 0)
        program_cols = np.arange(gene_dim, train_bundle.action.shape[1], dtype=int)
        supported_program_cols = np.intersect1d(supported_cols, program_cols)
        feature_sets = {
            "full_action_descriptor": bundle_features(train_bundle),
            "source_only": train_bundle.source,
            "source_plus_supported_action_dims": np.concatenate((train_bundle.source, train_bundle.action[:, supported_cols]), axis=1),
            "source_plus_program_action": np.concatenate((train_bundle.source, train_bundle.action[:, program_cols]), axis=1),
            "source_plus_supported_program_action": np.concatenate((train_bundle.source, train_bundle.action[:, supported_program_cols]), axis=1),
            "program_action_only": train_bundle.action[:, program_cols],
            "supported_program_action_only": train_bundle.action[:, supported_program_cols],
        }
        eval_feature_sets = {
            "full_action_descriptor": bundle_features(eval_bundle),
            "source_only": eval_bundle.source,
            "source_plus_supported_action_dims": np.concatenate((eval_bundle.source, eval_bundle.action[:, supported_cols]), axis=1),
            "source_plus_program_action": np.concatenate((eval_bundle.source, eval_bundle.action[:, program_cols]), axis=1),
            "source_plus_supported_program_action": np.concatenate((eval_bundle.source, eval_bundle.action[:, supported_program_cols]), axis=1),
            "program_action_only": eval_bundle.action[:, program_cols],
            "supported_program_action_only": eval_bundle.action[:, supported_program_cols],
        }
        full_fit = fit_ridge_numpy(feature_sets["full_action_descriptor"], train_bundle.delta, alpha=1.0e-2)
        full_delta = predict_ridge_numpy(full_fit, eval_feature_sets["full_action_descriptor"])
        full_metrics = bundle_transition_metrics(eval_bundle, full_delta)
        for baseline, train_features in feature_sets.items():
            if train_features.shape[1] == 0:
                pred_delta = np.repeat(train_bundle.delta.mean(axis=0, keepdims=True), eval_bundle.delta.shape[0], axis=0)
            else:
                fit = fit_ridge_numpy(train_features, train_bundle.delta, alpha=1.0e-2)
                pred_delta = predict_ridge_numpy(fit, eval_feature_sets[baseline])
            metrics = bundle_transition_metrics(eval_bundle, pred_delta)
            rows.append(
                {
                    "seed": seed,
                    "baseline": baseline,
                    "status": "completed",
                    "feature_dim": int(train_features.shape[1]),
                    "transition_improvement": metrics["transition_source_cosine_improvement"],
                    "delta_cosine": metrics["delta_cosine"],
                    "recall_at_1": metrics["transition_to_target_recall@1"],
                    "effective_rank": metrics["delta_prediction_effective_rank"],
                    "magnitude_ratio": metrics["delta_magnitude_ratio"],
                    "transition_gap_vs_full": metrics["transition_source_cosine_improvement"] - full_metrics["transition_source_cosine_improvement"],
                    "delta_gap_vs_full": metrics["delta_cosine"] - full_metrics["delta_cosine"],
                    "recall_gap_vs_full": metrics["transition_to_target_recall@1"] - full_metrics["transition_to_target_recall@1"],
                }
            )
    frame = pd.DataFrame(rows)
    frame.to_csv(out / "program_only_action_descriptor_by_seed.tsv", sep="\t", index=False)
    completed = frame[frame["status"] == "completed"].copy() if "status" in frame.columns else pd.DataFrame()
    summary = (
        completed.groupby("baseline", as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_feature_dim=("feature_dim", "mean"),
            mean_transition_improvement=("transition_improvement", "mean"),
            min_transition_improvement=("transition_improvement", "min"),
            mean_delta_cosine=("delta_cosine", "mean"),
            min_delta_cosine=("delta_cosine", "min"),
            mean_recall_at_1=("recall_at_1", "mean"),
            min_recall_at_1=("recall_at_1", "min"),
            mean_effective_rank=("effective_rank", "mean"),
            mean_magnitude_ratio=("magnitude_ratio", "mean"),
            mean_transition_gap_vs_full=("transition_gap_vs_full", "mean"),
            mean_delta_gap_vs_full=("delta_gap_vs_full", "mean"),
            mean_recall_gap_vs_full=("recall_gap_vs_full", "mean"),
        )
        if not completed.empty
        else pd.DataFrame()
    )
    if not summary.empty:
        summary = summary.sort_values(["mean_transition_improvement", "mean_delta_cosine"], ascending=False)
    summary.to_csv(out / "program_only_action_descriptor_summary.tsv", sep="\t", index=False)
    full = _summary_row_by_key(summary, "baseline", "full_action_descriptor")
    supported = _summary_row_by_key(summary, "baseline", "source_plus_supported_action_dims")
    program = _summary_row_by_key(summary, "baseline", "source_plus_program_action")
    source = _summary_row_by_key(summary, "baseline", "source_only")
    supported_gap = float(supported.get("mean_transition_improvement", 0.0)) - float(source.get("mean_transition_improvement", 0.0))
    program_gap = float(program.get("mean_transition_improvement", 0.0)) - float(source.get("mean_transition_improvement", 0.0))
    supported_preserves = (
        _summary_passes_gates(supported, gates)
        and float(supported.get("mean_transition_gap_vs_full", -1.0)) >= -0.001
        and float(supported.get("mean_recall_gap_vs_full", -1.0)) >= -0.05
    )
    program_preserves = (
        _summary_passes_gates(program, gates)
        and float(program.get("mean_transition_gap_vs_full", -1.0)) >= -0.001
        and float(program.get("mean_recall_gap_vs_full", -1.0)) >= -0.05
    )
    if supported_preserves or program_preserves:
        decision = "F025_NON_EXACT_PROGRAM_ACTION_DESCRIPTOR_PRESERVES_OLD_FLOOR"
    elif max(supported_gap, program_gap) > 0.001:
        decision = "F025_PROGRAM_ACTION_DESCRIPTOR_HAS_PARTIAL_SIGNAL_BELOW_FLOOR"
    else:
        decision = "F025_PROGRAM_ACTION_DESCRIPTOR_DOES_NOT_REPAIR_SUPPORT_LIMIT"
    payload = {
        "diagnostic_label": decision,
        "gates": gates,
        "full_summary": full,
        "source_only_summary": source,
        "supported_action_summary": supported,
        "program_action_summary": program,
        "supported_minus_source_transition": supported_gap,
        "program_minus_source_transition": program_gap,
        "supported_preserves_floor": supported_preserves,
        "program_preserves_floor": program_preserves,
        "summary": summary.to_dict("records") if not summary.empty else [],
        "model_promoted": False,
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f025_report(out / "F025_PROGRAM_ONLY_ACTION_DESCRIPTOR_AUDIT.md", payload, summary, frame)
    append_journal(
        args.output_root,
        "F025_PROGRAM_ONLY_ACTION_DESCRIPTOR_AUDIT",
        "Program-only action descriptor diagnostic",
        f"Decision={decision}; supported-source transition gap={supported_gap:.6f}; program-source transition gap={program_gap:.6f}.",
    )
    row_metrics = supported if supported else program
    return {
        "experiment_id": "F025",
        "phase": "PostPhase8Council",
        "family": "Program and graph action priors",
        "tier": "Diagnostic",
        "seed": "0,1,2,3,4",
        "dataset": "synthetic_genetic_anchor_lite_multiseed_v1",
        "eval_split": args.eval_split,
        "mode": "program_only_action_descriptor_audit",
        "status_label": decision,
        "transition_improvement": f"{float(row_metrics.get('mean_transition_improvement', 0.0)):.6f}",
        "delta_cosine": f"{float(row_metrics.get('mean_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(row_metrics.get('mean_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(row_metrics.get('mean_effective_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(row_metrics.get('mean_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(row_metrics.get('mean_effective_rank', 0.0)):.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": str(float(row_metrics.get("mean_effective_rank", 0.0)) < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{float(row_metrics.get('mean_transition_gap_vs_full', 0.0)):.6f}",
        "floor_gap_recall": f"{float(row_metrics.get('mean_recall_gap_vs_full', 0.0)):.6f}",
        "floor_gap_delta_cosine": f"{float(row_metrics.get('mean_delta_gap_vs_full', 0.0)):.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{supported_gap:.6f}",
        "calibration_lcb_recall_gap": f"{program_gap:.6f}",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Program-only action descriptor audit; no model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f024_to_f025(args: argparse.Namespace) -> dict[str, Any]:
    f024 = _load_metric_json(args.output_root / "experiments/F024_heldout_action_descriptor_support_audit/metrics_eval.json")
    trigger = str(f024.get("diagnostic_label", "F024_HELDOUT_ACTION_DESCRIPTOR_SUPPORT_LIMITS_ACTION_GENERALIZATION"))
    proposals = [
        CouncilProposal(
            "F025 program-only action descriptor audit",
            {"novelty": 0.66, "feasibility": 0.99, "identity": 0.96, "effect": 0.82, "falsifiability": 0.98, "leakage": 0.95, "compute": 0.99},
            "Test whether non-exact supported program descriptors preserve the old floor before implementing a graph/program action model.",
        ),
        CouncilProposal(
            "Implement graph/program action JEPA immediately",
            {"novelty": 0.86, "feasibility": 0.58, "identity": 0.92, "effect": 0.72, "falsifiability": 0.72, "leakage": 0.80, "compute": 0.54},
            "Defer until program-only descriptors are shown to retain enough floor signal.",
        ),
        CouncilProposal(
            "Discard all action search",
            {"novelty": 0.30, "feasibility": 0.90, "identity": 0.90, "effect": 0.28, "falsifiability": 0.68, "leakage": 0.90, "compute": 0.95},
            "Reject because F024 still showed a measurable correct-action gap for perturbation 10.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "054", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f025_program_action(args.output_root, "054", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "054", trigger, council_path, amendment_path, selected.next_action)
    return run_f025_program_only_action_descriptor_audit(args)


def _write_f025_report(path: Path, payload: dict[str, Any], summary: pd.DataFrame, frame: pd.DataFrame) -> None:
    summary_tsv = summary.to_csv(sep="\t", index=False) if not summary.empty else "No summary rows.\n"
    frame_tsv = frame.to_csv(sep="\t", index=False) if not frame.empty else "No per-seed rows.\n"
    path.write_text(
        f"""# F025 Program-Only Action Descriptor Audit

## Decision
`{payload['diagnostic_label']}`

## Purpose
F024 showed that exact held-out perturbation descriptor dimensions are unsupported, while program-level dimensions are supported. This audit removes unsupported exact-action dimensions and tests whether supported non-exact program descriptors preserve the old floor.

## Key Metrics
- supported-action preserves floor: `{payload['supported_preserves_floor']}`
- program-action preserves floor: `{payload['program_preserves_floor']}`
- supported minus source transition: `{payload['supported_minus_source_transition']:.6f}`
- program minus source transition: `{payload['program_minus_source_transition']:.6f}`

## Summary
```tsv
{summary_tsv}
```

## Per-Seed Rows
```tsv
{frame_tsv}
```

## Interpretation
This is a diagnostic-only descriptor audit. It does not use exact condition keys as candidate model input and cannot promote a model.
""",
        encoding="utf-8",
    )


def run_f026_descriptor_aligned_synthetic_benchmark_audit(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F026_descriptor_aligned_synthetic_benchmark_audit"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    gates = _active_multiseed_gates(args)
    old_benchmark = args.dataset
    new_benchmark = "synth_program_aligned_genetic_lite"
    baselines = [
        "source_as_target",
        "mean_delta",
        "source_only_ridge",
        "source_plus_full_action",
        "source_plus_supported_action_dims",
        "source_plus_program_action",
        "source_plus_supported_program_action",
        "action_only_full",
        "program_action_only",
    ]
    rows: list[dict[str, Any]] = []
    geometry_rows: list[dict[str, Any]] = []
    for seed in seeds:
        for benchmark in (old_benchmark, new_benchmark):
            dataset = generate_synthetic_biology_lite(synthetic_lite_config(benchmark, seed=seed))
            geometry_rows.extend(_f026_direction_geometry_rows(dataset, benchmark, seed))
            representations = {
                "true_synthetic_z_bio": dataset.z_bio.astype(np.float64),
                "clean_rna_train_pca": _train_only_pca_embeddings(dataset.clean_rna, dataset.metadata, dim=24),
                "observed_rna_train_pca": _train_only_pca_embeddings(dataset.expression_values, dataset.metadata, dim=24),
            }
            for representation, embeddings in representations.items():
                train_bundle = _dataset_transition_bundle_from_embeddings(
                    dataset,
                    embeddings,
                    split="train",
                    name=f"f026_{benchmark}_{representation}_seed{seed}_train",
                )
                eval_bundle = _dataset_transition_bundle_from_embeddings(
                    dataset,
                    embeddings,
                    split=args.eval_split,
                    name=f"f026_{benchmark}_{representation}_seed{seed}_eval",
                )
                for baseline in baselines:
                    pred_delta = _f026_baseline_delta(train_bundle, eval_bundle, dataset, baseline)
                    metrics = bundle_transition_metrics(eval_bundle, pred_delta)
                    metrics.update(_extra_label_retrieval_metrics(eval_bundle, pred_delta))
                    rows.append(
                        {
                            "seed": seed,
                            "benchmark": benchmark,
                            "representation": representation,
                            "baseline": baseline,
                            "status": "completed",
                            "transition_improvement": metrics["transition_source_cosine_improvement"],
                            "absolute_target_cosine": metrics["absolute_target_cosine"],
                            "delta_cosine": metrics["delta_cosine"],
                            "condition_recall_at_1": metrics.get("transition_to_target_recall@1", 0.0),
                            "condition_recall_at_5": metrics.get("transition_to_target_recall@5", 0.0),
                            "perturbation_recall_at_1": metrics.get("transition_to_target_perturbation_recall@1", 0.0),
                            "cell_line_recall_at_1": metrics.get("transition_to_target_cell_line_recall@1", 0.0),
                            "delta_prediction_effective_rank": metrics["delta_prediction_effective_rank"],
                            "delta_teacher_effective_rank": metrics["delta_teacher_effective_rank"],
                            "delta_magnitude_ratio": metrics["delta_magnitude_ratio"],
                            "source_improvement_hinge_violation_fraction": metrics["source_improvement_hinge_violation_fraction"],
                        }
                    )
    frame = pd.DataFrame(rows)
    geometry = pd.DataFrame(geometry_rows)
    frame.to_csv(out / "step0_program_aligned_baselines_by_seed.tsv", sep="\t", index=False)
    geometry.to_csv(out / "perturbation_direction_descriptor_geometry.tsv", sep="\t", index=False)
    summary = (
        frame.groupby(["benchmark", "representation", "baseline"], as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_transition_improvement=("transition_improvement", "mean"),
            std_transition_improvement=("transition_improvement", "std"),
            min_transition_improvement=("transition_improvement", "min"),
            mean_delta_cosine=("delta_cosine", "mean"),
            min_delta_cosine=("delta_cosine", "min"),
            mean_condition_recall_at_1=("condition_recall_at_1", "mean"),
            min_condition_recall_at_1=("condition_recall_at_1", "min"),
            mean_perturbation_recall_at_1=("perturbation_recall_at_1", "mean"),
            mean_cell_line_recall_at_1=("cell_line_recall_at_1", "mean"),
            mean_delta_rank=("delta_prediction_effective_rank", "mean"),
            mean_magnitude_ratio=("delta_magnitude_ratio", "mean"),
        )
        .sort_values(["benchmark", "representation", "mean_transition_improvement"], ascending=[True, True, False])
    )
    geometry_summary = (
        geometry.groupby("benchmark", as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_same_program_cosine=("same_program_cosine", "mean"),
            min_same_program_cosine=("same_program_cosine", "min"),
            mean_different_program_cosine=("different_program_cosine", "mean"),
            mean_program_cosine_margin=("program_cosine_margin", "mean"),
        )
        if not geometry.empty
        else pd.DataFrame()
    )
    summary.to_csv(out / "step0_program_aligned_baseline_summary.tsv", sep="\t", index=False)
    geometry_summary.to_csv(out / "perturbation_direction_descriptor_geometry_summary.tsv", sep="\t", index=False)
    new_true_program = _f026_summary_row(summary, new_benchmark, "true_synthetic_z_bio", "source_plus_program_action")
    new_true_supported = _f026_summary_row(summary, new_benchmark, "true_synthetic_z_bio", "source_plus_supported_action_dims")
    new_rna_program = _f026_summary_row(summary, new_benchmark, "observed_rna_train_pca", "source_plus_program_action")
    old_true_program = _f026_summary_row(summary, old_benchmark, "true_synthetic_z_bio", "source_plus_program_action")
    new_geometry = _summary_row_by_key(geometry_summary, "benchmark", new_benchmark)
    old_geometry = _summary_row_by_key(geometry_summary, "benchmark", old_benchmark)
    program_true_passes = _f026_row_passes_gates(new_true_program, gates)
    observed_rna_program_passes = _f026_row_passes_gates(new_rna_program, gates)
    geometry_fixed = bool(
        float(new_geometry.get("mean_program_cosine_margin", -1.0)) > 0.5
        and float(new_geometry.get("min_same_program_cosine", -1.0)) > 0.85
    )
    if program_true_passes and geometry_fixed:
        decision = "F026_DESCRIPTOR_ALIGNED_BENCHMARK_APPROVES_STEP0_REDESIGN"
    elif geometry_fixed:
        decision = "F026_DESCRIPTOR_ALIGNMENT_FIXED_BUT_STEP0_FLOORS_STILL_FAIL"
    else:
        decision = "F026_DESCRIPTOR_ALIGNED_BENCHMARK_REDESIGN_FAILED_GEOMETRY"
    payload = {
        "diagnostic_label": decision,
        "old_benchmark": old_benchmark,
        "new_benchmark": new_benchmark,
        "gates": gates,
        "program_true_passes_gates": program_true_passes,
        "observed_rna_program_passes_gates": observed_rna_program_passes,
        "geometry_fixed": geometry_fixed,
        "old_true_program_summary": old_true_program,
        "new_true_program_summary": new_true_program,
        "new_true_supported_action_summary": new_true_supported,
        "new_observed_rna_program_summary": new_rna_program,
        "old_direction_geometry": old_geometry,
        "new_direction_geometry": new_geometry,
        "baseline_summary": summary.to_dict("records"),
        "geometry_summary": geometry_summary.to_dict("records") if not geometry_summary.empty else [],
        "model_promoted": False,
        "architecture_search_reopen_allowed": bool(program_true_passes and geometry_fixed),
        "leakage_controls": "synthetic train split only for PCA/ridge fitting; eval rows scoring-only; program-action decision uses no condition_key/biological_key/exact target-key one-hot inputs",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f026_report(out / "F026_DESCRIPTOR_ALIGNED_SYNTHETIC_BENCHMARK_AUDIT.md", payload, summary, geometry_summary, frame)
    (out / "BENCHMARK_REDIRECT_DECISION.md").write_text(_f026_redirect_decision_text(payload), encoding="utf-8")
    append_journal(
        args.output_root,
        "F026_DESCRIPTOR_ALIGNED_SYNTHETIC_BENCHMARK_AUDIT",
        "Benchmark/action-target redesign diagnostic",
        f"Decision={decision}; new true-z program transition={float(new_true_program.get('mean_transition_improvement', 0.0)):.6f}; new true-z program recall={float(new_true_program.get('mean_condition_recall_at_1', 0.0)):.6f}.",
    )
    row_metrics = new_true_program
    return {
        "experiment_id": "F026",
        "phase": "PostPhase8Council",
        "family": "Metric and data redesign",
        "tier": "Step0",
        "seed": "0,1,2,3,4",
        "dataset": new_benchmark,
        "eval_split": args.eval_split,
        "mode": "descriptor_aligned_synthetic_benchmark_audit",
        "status_label": decision,
        "transition_improvement": f"{float(row_metrics.get('mean_transition_improvement', 0.0)):.6f}",
        "delta_cosine": f"{float(row_metrics.get('mean_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(row_metrics.get('mean_condition_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(row_metrics.get('mean_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(row_metrics.get('mean_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(row_metrics.get('mean_delta_rank', 0.0)):.6f}",
        "effective_rank_target": "0.000000",
        "collapse_flag": str(float(row_metrics.get("mean_delta_rank", 0.0)) < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{float(row_metrics.get('mean_transition_improvement', 0.0)) - gates['primary_transition_gate']:.6f}",
        "floor_gap_recall": f"{float(row_metrics.get('mean_condition_recall_at_1', 0.0)) - gates['secondary_recall_gate']:.6f}",
        "floor_gap_delta_cosine": f"{float(row_metrics.get('mean_delta_cosine', 0.0)) - gates['primary_delta_cosine_gate']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{float(row_metrics.get('min_transition_improvement', 0.0)):.6f}",
        "calibration_lcb_recall_gap": f"{float(row_metrics.get('min_condition_recall_at_1', 0.0)):.6f}",
        "action_negative_gap": f"{float(new_geometry.get('mean_program_cosine_margin', 0.0)):.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Descriptor-aligned synthetic benchmark Step 0 diagnostic; no model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f025_to_f026(args: argparse.Namespace) -> dict[str, Any]:
    f025 = _load_metric_json(args.output_root / "experiments/F025_program_only_action_descriptor_audit/metrics_eval.json")
    trigger = str(f025.get("diagnostic_label", "F025_PROGRAM_ACTION_DESCRIPTOR_DOES_NOT_REPAIR_SUPPORT_LIMIT"))
    proposals = [
        CouncilProposal(
            "F026 descriptor-aligned synthetic benchmark audit",
            {"novelty": 0.72, "feasibility": 0.99, "identity": 0.96, "effect": 0.86, "falsifiability": 0.99, "leakage": 0.96, "compute": 0.99},
            "Add a named program-aligned synthetic benchmark, document the old random-effect mismatch, and rerun Step 0 floors before any new JEPA training.",
        ),
        CouncilProposal(
            "Train graph/program action JEPA immediately",
            {"novelty": 0.86, "feasibility": 0.50, "identity": 0.92, "effect": 0.54, "falsifiability": 0.70, "leakage": 0.80, "compute": 0.50},
            "Defer because F022/F025 indicate the current synthetic target may not be learnable from non-exact descriptors.",
        ),
        CouncilProposal(
            "Discard synthetic benchmarks and run Norman",
            {"novelty": 0.52, "feasibility": 0.62, "identity": 0.85, "effect": 0.48, "falsifiability": 0.68, "leakage": 0.86, "compute": 0.66},
            "Reject for this step because Norman is RNA-only and cannot validate the cross-modal JEPA loop or action descriptor repair.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "055", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f026_descriptor_aligned_benchmark(args.output_root, "055", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "055", trigger, council_path, amendment_path, selected.next_action)
    return run_f026_descriptor_aligned_synthetic_benchmark_audit(args)


def _dataset_transition_bundle_from_embeddings(dataset, embeddings: np.ndarray, *, split: str, name: str) -> LatentOperatorBundle:
    embeddings = np.asarray(embeddings, dtype=np.float64)
    descriptor_matrix = synthetic_action_descriptor_matrix(dataset)
    frame = dataset.metadata.reset_index(drop=False).rename(columns={"index": "_row_index"})
    target_frame = frame[(frame["split"] == split) & (frame["perturbation_id"] != dataset.config.control_perturbation_id)]
    source_rows: list[np.ndarray] = []
    target_rows: list[np.ndarray] = []
    action_rows: list[np.ndarray] = []
    meta_rows: list[pd.Series] = []
    for _, group in target_frame.groupby("bag_key", sort=True):
        row = group.iloc[0]
        source_mask = (
            (frame["split"] == "train")
            & (frame["perturbation_id"] == dataset.config.control_perturbation_id)
            & (frame["cell_line_id"] == int(row["cell_line_id"]))
            & (frame["batch_id"] == int(row["batch_id"]))
        )
        source_idx = frame.loc[source_mask, "_row_index"].to_numpy(dtype=int)
        if source_idx.size == 0:
            source_mask = (
                (frame["perturbation_id"] == dataset.config.control_perturbation_id)
                & (frame["cell_line_id"] == int(row["cell_line_id"]))
                & (frame["batch_id"] == int(row["batch_id"]))
            )
            source_idx = frame.loc[source_mask, "_row_index"].to_numpy(dtype=int)
        target_idx = group["_row_index"].to_numpy(dtype=int)
        if source_idx.size == 0 or target_idx.size == 0:
            continue
        source_rows.append(embeddings[source_idx].mean(axis=0, keepdims=True))
        target_rows.append(embeddings[target_idx].mean(axis=0, keepdims=True))
        action_rows.append(descriptor_matrix[int(row["perturbation_id"])][None, :])
        meta_rows.append(row.drop(labels=["_row_index"]))
    if not source_rows:
        raise ValueError(f"No transition rows for split={split!r} in {dataset.config.name}")
    metadata = pd.DataFrame(meta_rows).reset_index(drop=True)
    source = np.concatenate(source_rows, axis=0).astype(np.float64)
    target = np.concatenate(target_rows, axis=0).astype(np.float64)
    action = np.concatenate(action_rows, axis=0).astype(np.float64)
    arrays = {
        "source_z_bio_teacher": source,
        "target_z_bio_teacher": target,
        "source_z_bio_online": source,
        "target_z_bio_online": target,
        "action_descriptor": action,
    }
    return LatentOperatorBundle(name=name, arrays=arrays, metadata=metadata)


def _f026_baseline_delta(train_bundle: LatentOperatorBundle, eval_bundle: LatentOperatorBundle, dataset, baseline: str) -> np.ndarray:
    train_features, eval_features = _f026_feature_pair(train_bundle, eval_bundle, dataset, baseline)
    if baseline == "source_as_target":
        return np.zeros_like(eval_bundle.delta)
    if baseline == "mean_delta":
        return np.repeat(train_bundle.delta.mean(axis=0, keepdims=True), eval_bundle.delta.shape[0], axis=0)
    if train_features.shape[1] == 0:
        return np.repeat(train_bundle.delta.mean(axis=0, keepdims=True), eval_bundle.delta.shape[0], axis=0)
    fit = fit_ridge_numpy(train_features, train_bundle.delta, alpha=1.0e-2)
    return predict_ridge_numpy(fit, eval_features)


def _f026_feature_pair(
    train_bundle: LatentOperatorBundle,
    eval_bundle: LatentOperatorBundle,
    dataset,
    baseline: str,
) -> tuple[np.ndarray, np.ndarray]:
    gene_dim = int(dataset.config.num_perturbations)
    program_cols = np.arange(gene_dim, train_bundle.action.shape[1], dtype=int)
    supported_cols = np.flatnonzero((np.abs(train_bundle.action) > 1.0e-8).sum(axis=0) > 0)
    supported_program_cols = np.intersect1d(supported_cols, program_cols)
    if baseline == "source_as_target":
        return train_bundle.source, eval_bundle.source
    if baseline == "mean_delta":
        return np.zeros((train_bundle.source.shape[0], 0), dtype=np.float64), np.zeros((eval_bundle.source.shape[0], 0), dtype=np.float64)
    if baseline == "source_only_ridge":
        return train_bundle.source, eval_bundle.source
    if baseline == "source_plus_full_action":
        return bundle_features(train_bundle), bundle_features(eval_bundle)
    if baseline == "source_plus_supported_action_dims":
        return (
            np.concatenate((train_bundle.source, train_bundle.action[:, supported_cols]), axis=1),
            np.concatenate((eval_bundle.source, eval_bundle.action[:, supported_cols]), axis=1),
        )
    if baseline == "source_plus_program_action":
        return (
            np.concatenate((train_bundle.source, train_bundle.action[:, program_cols]), axis=1),
            np.concatenate((eval_bundle.source, eval_bundle.action[:, program_cols]), axis=1),
        )
    if baseline == "source_plus_supported_program_action":
        return (
            np.concatenate((train_bundle.source, train_bundle.action[:, supported_program_cols]), axis=1),
            np.concatenate((eval_bundle.source, eval_bundle.action[:, supported_program_cols]), axis=1),
        )
    if baseline == "action_only_full":
        return train_bundle.action, eval_bundle.action
    if baseline == "program_action_only":
        return train_bundle.action[:, program_cols], eval_bundle.action[:, program_cols]
    raise ValueError(f"unknown F026 baseline: {baseline}")


def _f026_direction_geometry_rows(dataset, benchmark: str, seed: int) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    train_perturbations = set(dataset.metadata.loc[dataset.metadata["split"] == "train", "perturbation_id"].astype(int).tolist())
    for perturbation_id in dataset.config.heldout_perturbations:
        program_id = int(perturbation_id) % int(dataset.config.num_programs)
        same_program = [
            value
            for value in train_perturbations
            if value != dataset.config.control_perturbation_id and value % dataset.config.num_programs == program_id
        ]
        different_program = [
            value
            for value in train_perturbations
            if value != dataset.config.control_perturbation_id and value % dataset.config.num_programs != program_id
        ]
        heldout_direction = dataset.perturbation_directions[int(perturbation_id)]
        same_mean = dataset.perturbation_directions[np.asarray(same_program, dtype=int)].mean(axis=0) if same_program else np.zeros_like(heldout_direction)
        different_mean = dataset.perturbation_directions[np.asarray(different_program, dtype=int)].mean(axis=0) if different_program else np.zeros_like(heldout_direction)
        same_cosine = _safe_vector_cosine(heldout_direction, same_mean)
        different_cosine = _safe_vector_cosine(heldout_direction, different_mean)
        rows.append(
            {
                "seed": seed,
                "benchmark": benchmark,
                "perturbation_id": int(perturbation_id),
                "program_id": program_id,
                "same_program_train_count": int(len(same_program)),
                "different_program_train_count": int(len(different_program)),
                "same_program_cosine": same_cosine,
                "different_program_cosine": different_cosine,
                "program_cosine_margin": same_cosine - different_cosine,
            }
        )
    return rows


def _safe_vector_cosine(left: np.ndarray, right: np.ndarray) -> float:
    denom = float(np.linalg.norm(left) * np.linalg.norm(right))
    if denom <= 1.0e-8:
        return 0.0
    return float(np.dot(left, right) / denom)


def _f026_summary_row(summary: pd.DataFrame, benchmark: str, representation: str, baseline: str) -> dict[str, Any]:
    if summary.empty:
        return {}
    mask = (
        (summary["benchmark"] == benchmark)
        & (summary["representation"] == representation)
        & (summary["baseline"] == baseline)
    )
    if not mask.any():
        return {}
    return summary[mask].iloc[0].to_dict()


def _f026_row_passes_gates(row: dict[str, Any], gates: dict[str, float]) -> bool:
    return bool(
        row
        and int(row.get("seed_count", 0)) >= 5
        and float(row.get("mean_transition_improvement", -1.0)) >= gates["primary_transition_gate"]
        and float(row.get("mean_delta_cosine", -1.0)) >= gates["primary_delta_cosine_gate"]
        and float(row.get("mean_condition_recall_at_1", -1.0)) >= gates["secondary_recall_gate"]
        and float(row.get("mean_delta_rank", 0.0)) >= 2.0
    )


def _write_f026_report(path: Path, payload: dict[str, Any], summary: pd.DataFrame, geometry_summary: pd.DataFrame, frame: pd.DataFrame) -> None:
    key = pd.DataFrame(
        [
            payload.get("old_true_program_summary", {}),
            payload.get("new_true_program_summary", {}),
            payload.get("new_observed_rna_program_summary", {}),
            payload.get("new_true_supported_action_summary", {}),
        ]
    )
    key_tsv = key.to_csv(sep="\t", index=False) if not key.empty else "No key rows.\n"
    summary_tsv = summary.to_csv(sep="\t", index=False) if not summary.empty else "No summary rows.\n"
    geometry_tsv = geometry_summary.to_csv(sep="\t", index=False) if not geometry_summary.empty else "No geometry rows.\n"
    frame_head_tsv = frame.head(120).to_csv(sep="\t", index=False) if not frame.empty else "No per-seed rows.\n"
    gates = payload["gates"]
    path.write_text(
        f"""# F026 Descriptor-Aligned Synthetic Benchmark Audit

## Decision
`{payload['diagnostic_label']}`

## Why This Branch Exists
F022 showed that true synthetic `z_bio` failed under the current held-out transition target. F025 then showed that pure program descriptors do not preserve the old floor. The generator inspection identified the construction issue: the historical benchmark samples perturbation directions independently at random, while the non-exact action descriptor only exposes program membership. A held-out perturbation direction therefore is not guaranteed to be predictable from its supported program descriptor.

## New Named Benchmark
`{payload['new_benchmark']}`

This benchmark keeps the low-compute synthetic scRNA+image setup, fixed genetic-guide dose, held-out perturbation split, cross-batch replicates, and no real data. The only intended change is the action-target contract: perturbation effects are generated from a shared program direction plus small perturbation-level noise, so held-out perturbations have train-supported non-exact biological action structure.

## Active Gates
- transition improvement >= `{gates['primary_transition_gate']:.6f}`
- delta cosine >= `{gates['primary_delta_cosine_gate']:.6f}`
- condition recall@1 >= `{gates['secondary_recall_gate']:.6f}`

## Key Rows
```tsv
{key_tsv}
```

## Direction Geometry
```tsv
{geometry_tsv}
```

## Full Step 0 Summary
```tsv
{summary_tsv}
```

## Per-Seed Rows Preview
```tsv
{frame_head_tsv}
```

## Leakage And Promotion Status
- No model is promoted.
- PCA bases and ridge floors are fit on train rows only.
- Eval rows are used only for scoring.
- The reopen decision is based on non-exact program action descriptors, not `condition_key`, `biological_key`, held-out target means, or exact target-key one-hot features.
""",
        encoding="utf-8",
    )


def _f026_redirect_decision_text(payload: dict[str, Any]) -> str:
    return f"""# F026 Benchmark Redirect Decision

## Decision
`{payload['diagnostic_label']}`

## Actionable Interpretation
- Historical benchmark: `{payload['old_benchmark']}`
- New benchmark: `{payload['new_benchmark']}`
- Program descriptor geometry fixed: `{payload['geometry_fixed']}`
- True synthetic z_bio with non-exact program action passes active gates: `{payload['program_true_passes_gates']}`
- Observed RNA PCA with non-exact program action passes active gates: `{payload['observed_rna_program_passes_gates']}`

If reopened, the next JEPA work should use the new named benchmark for synthetic Step 0 and representation training. The old benchmark remains a locked historical artifact and should not be silently mutated.
"""


def write_amendment_f026_descriptor_aligned_benchmark(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Descriptor-Aligned Synthetic Benchmark Audit

## Trigger
`{trigger}`

## Evidence
F022 showed that true synthetic `z_bio` does not reproduce the current positive transition floor. F024/F025 localized a descriptor-support problem: exact held-out perturbation dimensions are unsupported, and pure program descriptors fail. Inspecting the synthetic generator shows why: perturbation directions are independent random vectors, so the program descriptor is not causally tied to the held-out target direction.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it.

## New Diagnostic Branch
`F026_DESCRIPTOR_ALIGNED_SYNTHETIC_BENCHMARK_AUDIT`

## Implementation Tasks
- Add a new named synthetic config that leaves the old benchmark locked.
- Generate perturbation directions from shared program factors plus small perturbation-specific noise.
- Keep genetic-guide dose fixed and ignore chemical dose for this benchmark.
- Run Step 0 floors across seeds 0-4 using true synthetic `z_bio`, clean RNA PCA, and observed RNA PCA.
- Compare source-as-target, mean delta, source-only ridge, full action ridge, supported-action ridge, and non-exact program-action ridge.
- Use train rows only for PCA/ridge fitting and eval rows only for scoring.

## Decision Use
Reopen JEPA architecture only if the new true `z_bio` plus non-exact program action descriptors passes the active gates and the direction geometry audit proves held-out program support. Otherwise keep architecture cooled and continue metric/data redesign.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def run_f027_celljepa_program_aligned_warmstart(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F027_celljepa_program_aligned_warmstart"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    gates = _active_multiseed_gates(args)
    benchmark = "synth_program_aligned_genetic_lite"
    rows: list[dict[str, Any]] = []
    rep_rows: list[dict[str, Any]] = []
    for seed in seeds:
        dataset = generate_synthetic_biology_lite(synthetic_lite_config(benchmark, seed=seed))
        train_cell_indices = np.flatnonzero((dataset.metadata["split"] == "train").to_numpy())
        model_config = CellJEPARNAConfig(
            vocab_size=dataset.config.genes,
            dim=24,
            depth=1,
            heads=4,
            max_genes=dataset.config.genes,
            mask_prob=0.15,
            num_expression_bins=50,
            expressed_gene_subsample=96,
            w_jepa=1000.0,
            w_rec=1.0e-3,
        )
        train_config = CellJEPAWarmstartTrainConfig(seed=seed, steps=30, batch_size=32, max_train_genes=128, device=args.device)
        seed_out = out / f"seed{seed}"
        model, train_trace = train_cell_jepa_rna_warmstart(dataset.expression_values[train_cell_indices], model_config, train_config, output_dir=seed_out)
        celljepa_z = encode_cell_jepa_rna(model, dataset.expression_values, batch_size=128, device=args.device)
        observed_pca = _train_only_pca_embeddings(dataset.expression_values, dataset.metadata, dim=24)
        true_z = dataset.z_bio.astype(np.float64)
        for representation, embeddings in {
            "celljepa_rna_z": celljepa_z,
            "observed_rna_train_pca": observed_pca,
            "true_synthetic_z_bio": true_z,
        }.items():
            train_bundle = _dataset_transition_bundle_from_embeddings(
                dataset,
                embeddings,
                split="train",
                name=f"f027_{representation}_seed{seed}_train",
            )
            eval_bundle = _dataset_transition_bundle_from_embeddings(
                dataset,
                embeddings,
                split=args.eval_split,
                name=f"f027_{representation}_seed{seed}_eval",
            )
            for baseline in ("source_as_target", "source_only_ridge", "source_plus_program_action", "program_action_only"):
                pred_delta = _f026_baseline_delta(train_bundle, eval_bundle, dataset, baseline)
                metrics = bundle_transition_metrics(eval_bundle, pred_delta)
                rows.append(
                    {
                        "seed": seed,
                        "benchmark": benchmark,
                        "representation": representation,
                        "baseline": baseline,
                        "status": "completed",
                        "transition_improvement": metrics["transition_source_cosine_improvement"],
                        "delta_cosine": metrics["delta_cosine"],
                        "condition_recall_at_1": metrics.get("transition_to_target_recall@1", 0.0),
                        "delta_prediction_effective_rank": metrics["delta_prediction_effective_rank"],
                        "delta_magnitude_ratio": metrics["delta_magnitude_ratio"],
                    }
                )
            rep_metrics = _representation_metrics_for_bundle(train_bundle, eval_bundle, eval_bundle.target)
            eval_cell_idx = _target_cell_indices_for_bundle(dataset, eval_bundle, split=args.eval_split)
            view_a = encode_cell_jepa_augmented_view(model, dataset.expression_values[eval_cell_idx], seed=seed + 700, device=args.device)
            view_b = encode_cell_jepa_augmented_view(model, dataset.expression_values[eval_cell_idx], seed=seed + 800, device=args.device)
            rep_rows.append(
                {
                    "seed": seed,
                    "representation": representation,
                    "same_condition_recall_at_1": rep_metrics["same_condition_recall_at_1"],
                    "effective_rank": rep_metrics["effective_rank"],
                    "perturbation_probe_cv": rep_metrics["perturbation_probe_cv"],
                    "batch_probe_cv": rep_metrics["batch_probe_cv"],
                    "same_cell_recall_at_1": _paired_same_cell_recall_at_1(view_a, view_b) if representation == "celljepa_rna_z" else 0.0,
                    "dropout_robustness_cosine": cell_jepa_dropout_robustness(model, dataset.expression_values[eval_cell_idx], repeats=4, seed=seed + 900, device=args.device) if representation == "celljepa_rna_z" else 0.0,
                    "final_jepa_loss": train_trace["final_jepa_loss"] if representation == "celljepa_rna_z" else 0.0,
                    "final_reconstruction_loss": train_trace["final_reconstruction_loss"] if representation == "celljepa_rna_z" else 0.0,
                    "final_weighted_jepa_to_rec_ratio": train_trace["final_weighted_jepa_to_rec_ratio"] if representation == "celljepa_rna_z" else 0.0,
                }
            )
    frame = pd.DataFrame(rows)
    rep_frame = pd.DataFrame(rep_rows)
    frame.to_csv(out / "transition_by_seed.tsv", sep="\t", index=False)
    rep_frame.to_csv(out / "representation_by_seed.tsv", sep="\t", index=False)
    summary = (
        frame.groupby(["representation", "baseline"], as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_transition_improvement=("transition_improvement", "mean"),
            min_transition_improvement=("transition_improvement", "min"),
            mean_delta_cosine=("delta_cosine", "mean"),
            min_delta_cosine=("delta_cosine", "min"),
            mean_condition_recall_at_1=("condition_recall_at_1", "mean"),
            min_condition_recall_at_1=("condition_recall_at_1", "min"),
            mean_delta_rank=("delta_prediction_effective_rank", "mean"),
            mean_magnitude_ratio=("delta_magnitude_ratio", "mean"),
        )
        .sort_values(["representation", "mean_transition_improvement"], ascending=[True, False])
    )
    rep_summary = (
        rep_frame.groupby("representation", as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_same_condition_recall_at_1=("same_condition_recall_at_1", "mean"),
            mean_effective_rank=("effective_rank", "mean"),
            mean_perturbation_probe_cv=("perturbation_probe_cv", "mean"),
            mean_batch_probe_cv=("batch_probe_cv", "mean"),
            mean_same_cell_recall_at_1=("same_cell_recall_at_1", "mean"),
            mean_dropout_robustness_cosine=("dropout_robustness_cosine", "mean"),
            min_weighted_jepa_to_rec_ratio=("final_weighted_jepa_to_rec_ratio", "min"),
        )
    )
    summary.to_csv(out / "transition_summary.tsv", sep="\t", index=False)
    rep_summary.to_csv(out / "representation_summary.tsv", sep="\t", index=False)
    cell_program = _summary_row_by_key(summary[summary["representation"] == "celljepa_rna_z"], "baseline", "source_plus_program_action")
    pca_program = _summary_row_by_key(summary[summary["representation"] == "observed_rna_train_pca"], "baseline", "source_plus_program_action")
    true_program = _summary_row_by_key(summary[summary["representation"] == "true_synthetic_z_bio"], "baseline", "source_plus_program_action")
    cell_rep = _summary_row_by_key(rep_summary, "representation", "celljepa_rna_z")
    cell_passes = _f026_row_passes_gates(cell_program, gates) and float(cell_rep.get("min_weighted_jepa_to_rec_ratio", 0.0)) > 1.0
    pca_passes = _f026_row_passes_gates(pca_program, gates)
    if cell_passes:
        decision = "F027_CELLJEPA_PROGRAM_ALIGNED_WARMSTART_PASSES_STEP0"
    elif pca_passes:
        decision = "F027_CELLJEPA_BELOW_PCA_FLOOR_USE_REPRESENTATION_REPAIR"
    else:
        decision = "F027_PROGRAM_ALIGNED_REPRESENTATION_WARMSTART_FAILS"
    payload = {
        "diagnostic_label": decision,
        "benchmark": benchmark,
        "gates": gates,
        "celljepa_passes_gates": cell_passes,
        "observed_pca_passes_gates": pca_passes,
        "celljepa_program_summary": cell_program,
        "observed_pca_program_summary": pca_program,
        "true_z_program_summary": true_program,
        "celljepa_representation_summary": cell_rep,
        "transition_summary": summary.to_dict("records"),
        "representation_summary": rep_summary.to_dict("records"),
        "model_promoted": False,
        "leakage_controls": "Cell-JEPA warmstart uses train expression only; program-action transition floors use train split only; eval rows are scoring-only; no condition_key/biological_key/exact target-key one-hot inputs",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f027_report(out / "F027_CELLJEPA_PROGRAM_ALIGNED_WARMSTART.md", payload, summary, rep_summary)
    append_journal(
        args.output_root,
        "F027_CELLJEPA_PROGRAM_ALIGNED_WARMSTART",
        "Representation warmstart on descriptor-aligned benchmark",
        f"Decision={decision}; CellJEPA transition={float(cell_program.get('mean_transition_improvement', 0.0)):.6f}; PCA transition={float(pca_program.get('mean_transition_improvement', 0.0)):.6f}.",
    )
    row_metrics = cell_program
    return {
        "experiment_id": "F027",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Step0",
        "seed": "0,1,2,3,4",
        "dataset": benchmark,
        "eval_split": args.eval_split,
        "mode": "celljepa_program_aligned_warmstart",
        "status_label": decision,
        "transition_improvement": f"{float(row_metrics.get('mean_transition_improvement', 0.0)):.6f}",
        "delta_cosine": f"{float(row_metrics.get('mean_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(row_metrics.get('mean_condition_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(row_metrics.get('mean_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(row_metrics.get('mean_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": f"{float(cell_rep.get('mean_batch_probe_cv', 0.0)):.6f}",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(cell_rep.get('mean_effective_rank', 0.0)):.6f}",
        "effective_rank_target": f"{float(true_program.get('mean_delta_rank', 0.0)):.6f}",
        "collapse_flag": str(float(cell_rep.get("mean_effective_rank", 0.0)) < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{float(row_metrics.get('mean_transition_improvement', 0.0)) - gates['primary_transition_gate']:.6f}",
        "floor_gap_recall": f"{float(row_metrics.get('mean_condition_recall_at_1', 0.0)) - gates['secondary_recall_gate']:.6f}",
        "floor_gap_delta_cosine": f"{float(row_metrics.get('mean_delta_cosine', 0.0)) - gates['primary_delta_cosine_gate']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{float(row_metrics.get('min_transition_improvement', 0.0)):.6f}",
        "calibration_lcb_recall_gap": f"{float(row_metrics.get('min_condition_recall_at_1', 0.0)):.6f}",
        "action_negative_gap": f"{float(cell_program.get('mean_transition_improvement', 0.0)) - float(pca_program.get('mean_transition_improvement', 0.0)):.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Cell-JEPA RNA warmstart on descriptor-aligned benchmark; no transition model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f026_to_f027(args: argparse.Namespace) -> dict[str, Any]:
    f026 = _load_metric_json(args.output_root / "experiments/F026_descriptor_aligned_synthetic_benchmark_audit/metrics_eval.json")
    trigger = str(f026.get("diagnostic_label", "F026_DESCRIPTOR_ALIGNED_BENCHMARK_APPROVES_STEP0_REDESIGN"))
    proposals = [
        CouncilProposal(
            "F027 Cell-JEPA warmstart on descriptor-aligned benchmark",
            {"novelty": 0.70, "feasibility": 0.90, "identity": 0.95, "effect": 0.76, "falsifiability": 0.96, "leakage": 0.95, "compute": 0.86},
            "Train a tiny Cell-JEPA RNA warmstart on the repaired benchmark and compare its program-action floor with true z_bio and observed RNA PCA.",
        ),
        CouncilProposal(
            "Train full cross-modal JEPA immediately",
            {"novelty": 0.88, "feasibility": 0.56, "identity": 0.94, "effect": 0.78, "falsifiability": 0.78, "leakage": 0.82, "compute": 0.52},
            "Defer one step because representation extraction should be checked on the repaired benchmark before spending training compute.",
        ),
        CouncilProposal(
            "Return to old benchmark residuals",
            {"novelty": 0.28, "feasibility": 0.80, "identity": 0.90, "effect": 0.20, "falsifiability": 0.70, "leakage": 0.90, "compute": 0.90},
            "Reject because F026 proved the old action-target contract is not suitable for non-exact descriptor learning.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "056", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f027_celljepa_program_aligned(root=args.output_root, number="056", trigger=trigger, selected=selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "056", trigger, council_path, amendment_path, selected.next_action)
    return run_f027_celljepa_program_aligned_warmstart(args)


def _write_f027_report(path: Path, payload: dict[str, Any], summary: pd.DataFrame, rep_summary: pd.DataFrame) -> None:
    key = pd.DataFrame(
        [
            payload.get("true_z_program_summary", {}),
            payload.get("observed_pca_program_summary", {}),
            payload.get("celljepa_program_summary", {}),
            payload.get("celljepa_representation_summary", {}),
        ]
    )
    key_tsv = key.to_csv(sep="\t", index=False) if not key.empty else "No key rows.\n"
    summary_tsv = summary.to_csv(sep="\t", index=False) if not summary.empty else "No transition summary rows.\n"
    rep_tsv = rep_summary.to_csv(sep="\t", index=False) if not rep_summary.empty else "No representation summary rows.\n"
    gates = payload["gates"]
    path.write_text(
        f"""# F027 Cell-JEPA Program-Aligned Warmstart

## Decision
`{payload['diagnostic_label']}`

## Purpose
F026 fixed the synthetic action-target contract. This branch tests whether a JEPA-style RNA representation can preserve the new non-exact program-action transition floor before launching a full cross-modal/action JEPA.

## Active Gates
- transition improvement >= `{gates['primary_transition_gate']:.6f}`
- delta cosine >= `{gates['primary_delta_cosine_gate']:.6f}`
- condition recall@1 >= `{gates['secondary_recall_gate']:.6f}`

## Key Rows
```tsv
{key_tsv}
```

## Transition Summary
```tsv
{summary_tsv}
```

## Representation Summary
```tsv
{rep_tsv}
```

## Leakage And Promotion Status
- No model is promoted.
- Cell-JEPA pretraining uses train expression values only.
- Program-action floors are fit on train split only and scored on held-out perturbations.
- No `condition_key`, `biological_key`, held-out target means, pooled train+test statistics, or exact held-out perturbation one-hot features are model inputs.
""",
        encoding="utf-8",
    )


def write_amendment_f027_celljepa_program_aligned(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Cell-JEPA Warmstart On Descriptor-Aligned Benchmark

## Trigger
`{trigger}`

## Evidence
F026 approved the new `synth_program_aligned_genetic_lite` benchmark: true synthetic `z_bio` plus non-exact program actions passed the active Step 0 gates, and observed RNA PCA also passed. Before spending more compute on a full cross-modal/action JEPA, the representation path should be checked on the repaired benchmark.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it.

## New Diagnostic Branch
`F027_CELLJEPA_PROGRAM_ALIGNED_WARMSTART`

## Implementation Tasks
- Train a tiny Cell-JEPA-style RNA warmstart on train expression rows only.
- Use masked student RNA, unmasked EMA teacher RNA, stop-gradient latent targets, cosine JEPA loss, and light reconstruction anchor.
- Compare frozen Cell-JEPA `z_bio` against true synthetic `z_bio` and train-only observed RNA PCA under non-exact program-action transition floors.
- Do not use exact held-out perturbation one-hot features, `condition_key`, `biological_key`, held-out target means, or pooled train+test statistics.

## Decision Use
If Cell-JEPA preserves the repaired benchmark floor, proceed to a small full cross-modal/action JEPA probe. If Cell-JEPA falls below observed RNA PCA, prioritize representation repair or PCA-teacher distillation instead of transition residuals.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def run_f028_train_only_pca_distilled_rna_encoder(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F028_train_only_pca_distilled_rna_encoder"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    gates = _active_multiseed_gates(args)
    benchmark = "synth_program_aligned_genetic_lite"
    rows: list[dict[str, Any]] = []
    train_rows: list[dict[str, Any]] = []
    for seed in seeds:
        dataset = generate_synthetic_biology_lite(synthetic_lite_config(benchmark, seed=seed))
        pca_z = _train_only_pca_embeddings(dataset.expression_values, dataset.metadata, dim=24)
        learned_z, trace = _fit_pca_distilled_rna_encoder(
            dataset.expression_values,
            pca_z,
            dataset.metadata,
            seed=seed,
            device=args.device,
            output_dir=out / f"seed{seed}",
        )
        train_rows.append({"seed": seed, **trace})
        for representation, embeddings in {
            "pca_distilled_rna_encoder": learned_z,
            "observed_rna_train_pca": pca_z,
            "true_synthetic_z_bio": dataset.z_bio.astype(np.float64),
        }.items():
            train_bundle = _dataset_transition_bundle_from_embeddings(
                dataset,
                embeddings,
                split="train",
                name=f"f028_{representation}_seed{seed}_train",
            )
            eval_bundle = _dataset_transition_bundle_from_embeddings(
                dataset,
                embeddings,
                split=args.eval_split,
                name=f"f028_{representation}_seed{seed}_eval",
            )
            rep_metrics = _representation_metrics_for_bundle(train_bundle, eval_bundle, eval_bundle.target)
            for baseline in ("source_as_target", "source_only_ridge", "source_plus_program_action", "program_action_only"):
                pred_delta = _f026_baseline_delta(train_bundle, eval_bundle, dataset, baseline)
                metrics = bundle_transition_metrics(eval_bundle, pred_delta)
                rows.append(
                    {
                        "seed": seed,
                        "benchmark": benchmark,
                        "representation": representation,
                        "baseline": baseline,
                        "status": "completed",
                        "transition_improvement": metrics["transition_source_cosine_improvement"],
                        "delta_cosine": metrics["delta_cosine"],
                        "condition_recall_at_1": metrics.get("transition_to_target_recall@1", 0.0),
                        "delta_prediction_effective_rank": metrics["delta_prediction_effective_rank"],
                        "delta_magnitude_ratio": metrics["delta_magnitude_ratio"],
                        "same_condition_recall_at_1": rep_metrics["same_condition_recall_at_1"],
                        "effective_rank_z": rep_metrics["effective_rank"],
                        "perturbation_probe_cv": rep_metrics["perturbation_probe_cv"],
                        "batch_probe_cv": rep_metrics["batch_probe_cv"],
                    }
                )
    frame = pd.DataFrame(rows)
    trace_frame = pd.DataFrame(train_rows)
    frame.to_csv(out / "transition_by_seed.tsv", sep="\t", index=False)
    trace_frame.to_csv(out / "distillation_trace_by_seed.tsv", sep="\t", index=False)
    summary = (
        frame.groupby(["representation", "baseline"], as_index=False)
        .agg(
            seed_count=("seed", "nunique"),
            mean_transition_improvement=("transition_improvement", "mean"),
            min_transition_improvement=("transition_improvement", "min"),
            mean_delta_cosine=("delta_cosine", "mean"),
            min_delta_cosine=("delta_cosine", "min"),
            mean_condition_recall_at_1=("condition_recall_at_1", "mean"),
            min_condition_recall_at_1=("condition_recall_at_1", "min"),
            mean_delta_rank=("delta_prediction_effective_rank", "mean"),
            mean_magnitude_ratio=("delta_magnitude_ratio", "mean"),
            mean_same_condition_recall_at_1=("same_condition_recall_at_1", "mean"),
            mean_effective_rank_z=("effective_rank_z", "mean"),
            mean_perturbation_probe_cv=("perturbation_probe_cv", "mean"),
            mean_batch_probe_cv=("batch_probe_cv", "mean"),
        )
        .sort_values(["representation", "mean_transition_improvement"], ascending=[True, False])
    )
    summary.to_csv(out / "transition_summary.tsv", sep="\t", index=False)
    distilled_program = _summary_row_by_key(summary[summary["representation"] == "pca_distilled_rna_encoder"], "baseline", "source_plus_program_action")
    pca_program = _summary_row_by_key(summary[summary["representation"] == "observed_rna_train_pca"], "baseline", "source_plus_program_action")
    true_program = _summary_row_by_key(summary[summary["representation"] == "true_synthetic_z_bio"], "baseline", "source_plus_program_action")
    distilled_passes = _f026_row_passes_gates(distilled_program, gates)
    pca_passes = _f026_row_passes_gates(pca_program, gates)
    transition_gap_vs_pca = float(distilled_program.get("mean_transition_improvement", 0.0)) - float(pca_program.get("mean_transition_improvement", 0.0))
    recall_gap_vs_pca = float(distilled_program.get("mean_condition_recall_at_1", 0.0)) - float(pca_program.get("mean_condition_recall_at_1", 0.0))
    if distilled_passes and transition_gap_vs_pca >= -0.05 and recall_gap_vs_pca >= -0.15:
        decision = "F028_PCA_DISTILLED_RNA_ENCODER_PRESERVES_PROGRAM_FLOOR"
    elif distilled_passes:
        decision = "F028_PCA_DISTILLED_ENCODER_PASSES_GATES_BUT_BELOW_PCA"
    elif pca_passes:
        decision = "F028_NEURAL_ENCODER_UNDERFITS_TRAIN_ONLY_PCA_TEACHER"
    else:
        decision = "F028_PCA_TEACHER_AND_DISTILLED_ENCODER_FAIL"
    payload = {
        "diagnostic_label": decision,
        "benchmark": benchmark,
        "gates": gates,
        "distilled_passes_gates": distilled_passes,
        "pca_passes_gates": pca_passes,
        "transition_gap_vs_pca": transition_gap_vs_pca,
        "recall_gap_vs_pca": recall_gap_vs_pca,
        "distilled_program_summary": distilled_program,
        "observed_pca_program_summary": pca_program,
        "true_z_program_summary": true_program,
        "summary": summary.to_dict("records"),
        "distillation_trace": trace_frame.to_dict("records"),
        "model_promoted": False,
        "leakage_controls": "PCA basis and neural distillation use train rows only; eval rows scoring-only; no condition_key/biological_key/exact target-key one-hot inputs",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f028_report(out / "F028_TRAIN_ONLY_PCA_DISTILLED_RNA_ENCODER.md", payload, summary, trace_frame)
    append_journal(
        args.output_root,
        "F028_TRAIN_ONLY_PCA_DISTILLED_RNA_ENCODER",
        "Representation repair with train-only PCA teacher",
        f"Decision={decision}; distilled transition={float(distilled_program.get('mean_transition_improvement', 0.0)):.6f}; PCA transition={float(pca_program.get('mean_transition_improvement', 0.0)):.6f}.",
    )
    row_metrics = distilled_program
    return {
        "experiment_id": "F028",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Step0",
        "seed": "0,1,2,3,4",
        "dataset": benchmark,
        "eval_split": args.eval_split,
        "mode": "train_only_pca_distilled_rna_encoder",
        "status_label": decision,
        "transition_improvement": f"{float(row_metrics.get('mean_transition_improvement', 0.0)):.6f}",
        "delta_cosine": f"{float(row_metrics.get('mean_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(row_metrics.get('mean_condition_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(row_metrics.get('mean_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(row_metrics.get('mean_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": f"{float(row_metrics.get('mean_batch_probe_cv', 0.0)):.6f}",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(row_metrics.get('mean_effective_rank_z', 0.0)):.6f}",
        "effective_rank_target": f"{float(true_program.get('mean_delta_rank', 0.0)):.6f}",
        "collapse_flag": str(float(row_metrics.get("mean_effective_rank_z", 0.0)) < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{float(row_metrics.get('mean_transition_improvement', 0.0)) - gates['primary_transition_gate']:.6f}",
        "floor_gap_recall": f"{float(row_metrics.get('mean_condition_recall_at_1', 0.0)) - gates['secondary_recall_gate']:.6f}",
        "floor_gap_delta_cosine": f"{float(row_metrics.get('mean_delta_cosine', 0.0)) - gates['primary_delta_cosine_gate']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{float(row_metrics.get('min_transition_improvement', 0.0)):.6f}",
        "calibration_lcb_recall_gap": f"{float(row_metrics.get('min_condition_recall_at_1', 0.0)):.6f}",
        "action_negative_gap": f"{transition_gap_vs_pca:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Train-only PCA-distilled RNA encoder diagnostic; no model promotion.",
        "artifact_dir": str(out),
    }


def _fit_pca_distilled_rna_encoder(
    expression_values: np.ndarray,
    pca_targets: np.ndarray,
    metadata: pd.DataFrame,
    *,
    seed: int,
    device: str,
    output_dir: Path,
) -> tuple[np.ndarray, dict[str, float]]:
    output_dir.mkdir(parents=True, exist_ok=True)
    rng = np.random.default_rng(seed)
    train_idx = np.flatnonzero((metadata["split"] == "train").to_numpy())
    x_train = torch.as_tensor(expression_values[train_idx], dtype=torch.float32, device=device)
    y_train = torch.as_tensor(pca_targets[train_idx], dtype=torch.float32, device=device)
    model = torch.nn.Sequential(
        torch.nn.LayerNorm(expression_values.shape[1]),
        torch.nn.Linear(expression_values.shape[1], 96),
        torch.nn.GELU(),
        torch.nn.Linear(96, pca_targets.shape[1]),
    ).to(device)
    opt = torch.optim.AdamW(model.parameters(), lr=1.0e-3, weight_decay=1.0e-4)
    last_loss = 0.0
    last_cos = 0.0
    for _ in range(80):
        batch = rng.choice(train_idx.size, size=min(64, train_idx.size), replace=train_idx.size < 64)
        xb = x_train[batch]
        yb = y_train[batch]
        mask = torch.rand_like(xb) > 0.10
        pred = model(xb * mask)
        cosine_loss = 1.0 - torch.nn.functional.cosine_similarity(pred, yb, dim=-1).mean()
        mse_loss = torch.nn.functional.mse_loss(pred, yb)
        loss = cosine_loss + 0.05 * mse_loss
        opt.zero_grad(set_to_none=True)
        loss.backward()
        torch.nn.utils.clip_grad_norm_(model.parameters(), 1.0)
        opt.step()
        last_loss = float(loss.detach().cpu())
        last_cos = float(1.0 - cosine_loss.detach().cpu())
    with torch.no_grad():
        all_x = torch.as_tensor(expression_values, dtype=torch.float32, device=device)
        embeddings = []
        for start in range(0, all_x.shape[0], 256):
            embeddings.append(model(all_x[start : start + 256]).detach().cpu().numpy())
    learned = np.concatenate(embeddings, axis=0).astype(np.float64)
    write_json(output_dir / "train_trace_summary.json", {"final_loss": last_loss, "final_train_cosine": last_cos})
    return learned, {"final_loss": last_loss, "final_train_cosine": last_cos}


def continue_after_f027_to_f028(args: argparse.Namespace) -> dict[str, Any]:
    f027 = _load_metric_json(args.output_root / "experiments/F027_celljepa_program_aligned_warmstart/metrics_eval.json")
    trigger = str(f027.get("diagnostic_label", "F027_CELLJEPA_BELOW_PCA_FLOOR_USE_REPRESENTATION_REPAIR"))
    proposals = [
        CouncilProposal(
            "F028 train-only PCA-distilled RNA encoder",
            {"novelty": 0.64, "feasibility": 0.94, "identity": 0.88, "effect": 0.82, "falsifiability": 0.96, "leakage": 0.94, "compute": 0.90},
            "Distill the train-only observed-RNA PCA representation into a neural encoder and test whether the program-action floor is preserved.",
        ),
        CouncilProposal(
            "Train Cell-JEPA longer",
            {"novelty": 0.32, "feasibility": 0.80, "identity": 0.95, "effect": 0.42, "falsifiability": 0.70, "leakage": 0.90, "compute": 0.58},
            "Reject as the default because F027 failed by a large transition margin despite JEPA-dominant weighting.",
        ),
        CouncilProposal(
            "Full cross-modal JEPA now",
            {"novelty": 0.88, "feasibility": 0.48, "identity": 0.94, "effect": 0.76, "falsifiability": 0.76, "leakage": 0.82, "compute": 0.46},
            "Defer until a learned RNA encoder can preserve the simple train-only PCA floor.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "057", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f028_pca_distilled_encoder(args.output_root, "057", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "057", trigger, council_path, amendment_path, selected.next_action)
    return run_f028_train_only_pca_distilled_rna_encoder(args)


