def continue_after_f030_to_f031(args: argparse.Namespace) -> dict[str, Any]:
    f030 = _load_metric_json(args.output_root / "experiments/F030_delta_direction_cross_modal_action_jepa/metrics_eval.json")
    trigger = str(f030.get("diagnostic_label", "F030_DELTA_DIRECTION_CROSS_MODAL_ACTION_JEPA_TIER1_PASS"))
    proposals = [
        CouncilProposal(
            "F031 Tier 2 delta-direction validation",
            {"novelty": 0.58, "feasibility": 0.92, "identity": 0.96, "effect": 0.78, "falsifiability": 0.98, "leakage": 0.96, "compute": 0.82},
            "Rerun the F030 candidate across seeds 0-4 and evaluate protected-floor and same-representation ridge-floor preservation.",
        ),
        CouncilProposal(
            "Immediate Tier 3 design",
            {"novelty": 0.68, "feasibility": 0.54, "identity": 0.90, "effect": 0.78, "falsifiability": 0.72, "leakage": 0.88, "compute": 0.52},
            "Defer because F030 is still Tier 1 and needs multi-seed no-regression statistics first.",
        ),
        CouncilProposal(
            "Train F030 longer",
            {"novelty": 0.20, "feasibility": 0.90, "identity": 0.94, "effect": 0.28, "falsifiability": 0.56, "leakage": 0.94, "compute": 0.60},
            "Reject because the gate passed; the next risk is stability and floor preservation, not optimization time.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "060", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f031_delta_direction_tier2(args.output_root, "060", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "060", trigger, council_path, amendment_path, selected.next_action)
    return run_f031_delta_direction_tier2_validation(args)


def _write_f031_report(path: Path, payload: dict[str, Any], frame: pd.DataFrame, trace: pd.DataFrame) -> None:
    frame_tsv = frame.to_csv(sep="\t", index=False) if not frame.empty else "No seed rows.\n"
    trace_tsv = trace.to_csv(sep="\t", index=False) if not trace.empty else "No trace rows.\n"
    path.write_text(
        f"""# F031 Delta-Direction JEPA Tier 2 Validation

## Decision
`{payload['diagnostic_label']}`

## Purpose
F030 passed Tier 1 after adding stop-gradient teacher-delta direction and source-improvement losses. F031 tests whether that result holds across five synthetic seeds and whether the direct JEPA predictor preserves both the protected historical floor and the same-representation train-only ridge floor.

## Tier 2 Checks
- protected Tier 2 pass: `{payload['protected_tier2_pass']}`
- active gate pass: `{payload['active_gate_pass']}`
- local same-representation ridge floor preserved: `{payload['local_ridge_floor_preserved']}`
- cross-modal healthy: `{payload['cross_modal_healthy']}`
- transition std <= protected effect: `{payload['std_not_larger_than_effect']}`

## Mean Metrics
- direct transition improvement: `{payload['mean_direct_transition_improvement']:.6f}` +/- `{payload['std_direct_transition_improvement']:.6f}`
- direct delta cosine: `{payload['mean_direct_delta_cosine']:.6f}` +/- `{payload['std_direct_delta_cosine']:.6f}`
- direct recall@1: `{payload['mean_direct_recall_at_1']:.6f}` +/- `{payload['std_direct_recall_at_1']:.6f}`
- direct delta rank: `{payload['mean_direct_delta_rank']:.6f}`
- same-representation ridge transition: `{payload['mean_ridge_floor_transition_improvement']:.6f}`
- local floor gap transition: `{payload['mean_local_floor_gap_transition']:.6f}` (min `{payload['min_local_floor_gap_transition']:.6f}`)
- local floor gap delta cosine: `{payload['mean_local_floor_gap_delta_cosine']:.6f}` (min `{payload['min_local_floor_gap_delta_cosine']:.6f}`)
- local floor gap recall: `{payload['mean_local_floor_gap_recall']:.6f}` (min `{payload['min_local_floor_gap_recall']:.6f}`)
- RNA->image recall@1: `{payload['mean_rna_to_image_recall_at_1']:.6f}`
- image->RNA recall@1: `{payload['mean_image_to_rna_recall_at_1']:.6f}`
- action-negative transition gap: `{payload['mean_action_negative_transition_gap']:.6f}`

## Seed Rows
```tsv
{frame_tsv}
```

## Train Trace
```tsv
{trace_tsv}
```

## Promotion Status
No model is promoted. Tier 2 can only justify a future Tier 3/no-regression plan, and failure to preserve the same-representation ridge floor requires a floor-preserving transition-head pivot before promotion can be considered.
""",
        encoding="utf-8",
    )


def write_amendment_f031_delta_direction_tier2(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Delta-Direction JEPA Tier 2 Validation

## Trigger
`{trigger}`

## Evidence
F030 passed the active Tier 1 gates with a real cross-modal/action JEPA, but Tier 1 cannot promote and does not prove stability. The next required step is multi-seed validation with explicit protected-floor and same-representation ridge-floor checks.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it.

## New Validation Branch
`F031_DELTA_DIRECTION_TIER2_VALIDATION`

## Implementation Tasks
- Rerun the F030 architecture across synthetic seeds 0-4.
- Keep the same low-compute setting and do not train longer by default.
- Report mean/std, per-seed rows, and whether std is smaller than the claimed protected-floor effect.
- Check protected historical floor gates and same-representation train-only ridge floor preservation separately.
- Preserve JEPA identity: online encoders, EMA targets, stop-gradient latent targets, query predictors, cross-modal prediction, action-conditioned transition.
- Keep action input as non-exact program descriptors only.

## Decision Use
If F031 passes protected Tier 2 but fails the same-representation ridge floor, pivot to a floor-preserving transition head before Tier 3. If it preserves both, design Tier 3/no-regression validation. No Tier 2 result can promote.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def run_f032_floor_preserving_jepa_residual_calibration(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F032_floor_preserving_jepa_residual_calibration"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    benchmark = "synth_program_aligned_genetic_lite"
    rows: list[dict[str, Any]] = []
    train_trace_rows: list[dict[str, Any]] = []
    for seed in seeds:
        dataset = generate_synthetic_biology_lite(synthetic_lite_config(benchmark, seed=seed))
        pca_z = _train_only_pca_embeddings(dataset.expression_values, dataset.metadata, dim=24)
        train_table = _program_jepa_condition_table(dataset, pca_z, split="train")
        eval_table = _program_jepa_condition_table(dataset, pca_z, split=args.eval_split)
        config = ProgramBootstrapJEPAConfig(
            genes=dataset.config.genes,
            image_dim=int(dataset.images.reshape(dataset.images.shape[0], -1).shape[1]),
            action_dim=int(train_table["action"].shape[1]),
            z_dim=24,
            hidden_dim=96,
            pca_anchor_weight=0.15,
            transition_weight=1.0,
            cross_modal_weight=0.75,
            action_negative_weight=0.15,
            delta_direction_weight=0.8,
            source_improvement_weight=0.5,
            variance_weight=0.05,
        )
        model, trace = _train_program_bootstrap_jepa(train_table, config, seed=seed + 3032, device=args.device)
        seed_out = out / f"seed{seed}"
        seed_out.mkdir(parents=True, exist_ok=True)
        write_json(seed_out / "train_trace_summary.json", trace)
        train_trace_rows.append({"seed": seed, **trace})
        eval_payload = _evaluate_program_jepa_floor_blend(model, train_table, eval_table, device=args.device)
        write_json(seed_out / "metrics_eval.json", eval_payload)
        rows.append({"seed": seed, **eval_payload})
    frame = pd.DataFrame(rows)
    trace_frame = pd.DataFrame(train_trace_rows)
    frame.to_csv(out / "f032_by_seed.tsv", sep="\t", index=False)
    trace_frame.to_csv(out / "train_trace_by_seed.tsv", sep="\t", index=False)
    selected_nonzero_fraction = float((frame["selected_residual_scale"] > 0.0).mean()) if not frame.empty else 0.0
    heldout_preserved = (
        bool((frame["selected_gap_transition"] >= -0.001).all())
        and bool((frame["selected_gap_delta_cosine"] >= -0.001).all())
        and bool((frame["selected_gap_recall"] >= -0.001).all())
    )
    summary = {
        "seed_count": int(len(frame)),
        "selected_nonzero_fraction": selected_nonzero_fraction,
        "mean_selected_residual_scale": float(frame["selected_residual_scale"].mean()) if not frame.empty else 0.0,
        "max_selected_residual_scale": float(frame["selected_residual_scale"].max()) if not frame.empty else 0.0,
        "mean_selected_transition_improvement": float(frame["selected_transition_improvement"].mean()) if not frame.empty else 0.0,
        "mean_selected_delta_cosine": float(frame["selected_delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_selected_recall_at_1": float(frame["selected_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_selected_delta_rank": float(frame["selected_delta_rank"].mean()) if not frame.empty else 0.0,
        "mean_selected_magnitude_ratio": float(frame["selected_magnitude_ratio"].mean()) if not frame.empty else 0.0,
        "mean_floor_transition_improvement": float(frame["floor_transition_improvement"].mean()) if not frame.empty else 0.0,
        "mean_floor_delta_cosine": float(frame["floor_delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_floor_recall_at_1": float(frame["floor_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_direct_transition_improvement": float(frame["direct_transition_improvement"].mean()) if not frame.empty else 0.0,
        "mean_direct_delta_cosine": float(frame["direct_delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_direct_recall_at_1": float(frame["direct_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_selected_gap_transition": float(frame["selected_gap_transition"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_transition": float(frame["selected_gap_transition"].min()) if not frame.empty else 0.0,
        "mean_selected_gap_delta_cosine": float(frame["selected_gap_delta_cosine"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_delta_cosine": float(frame["selected_gap_delta_cosine"].min()) if not frame.empty else 0.0,
        "mean_selected_gap_recall": float(frame["selected_gap_recall"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_recall": float(frame["selected_gap_recall"].min()) if not frame.empty else 0.0,
        "mean_rna_to_image_recall_at_1": float(frame["rna_to_image_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_image_to_rna_recall_at_1": float(frame["image_to_rna_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_action_negative_transition_gap": float(frame["selected_action_negative_gap"].mean()) if not frame.empty else 0.0,
        "max_identity_violation": float(frame["identity_violation"].max()) if not frame.empty else 1.0,
        "max_leakage_flag": float(frame["leakage_flag"].max()) if not frame.empty else 1.0,
    }
    cross_modal_healthy = summary["mean_rna_to_image_recall_at_1"] >= 0.25 and summary["mean_image_to_rna_recall_at_1"] >= 0.25
    if selected_nonzero_fraction > 0.0 and heldout_preserved and cross_modal_healthy:
        decision = "F032_SAFE_NONZERO_JEPA_RESIDUAL_PRESERVES_LOCAL_FLOOR"
    elif selected_nonzero_fraction == 0.0 and heldout_preserved:
        decision = "F032_ZERO_RESIDUAL_LOCAL_FLOOR_FALLBACK_SELECTED"
    elif selected_nonzero_fraction > 0.0:
        decision = "F032_NONZERO_RESIDUAL_DISCARDED_HELDOUT_BELOW_LOCAL_FLOOR"
    else:
        decision = "F032_FLOOR_PRESERVING_CALIBRATION_FAIL"
    payload = {
        "diagnostic_label": decision,
        "benchmark": benchmark,
        "selected_nonzero_fraction": selected_nonzero_fraction,
        "heldout_local_floor_preserved": heldout_preserved,
        "cross_modal_healthy": cross_modal_healthy,
        **summary,
        "seed_rows": rows,
        "train_trace": train_trace_rows,
        "model_promoted": False,
        "identity_controls": {
            "online_context_encoders": True,
            "ema_target_encoders": True,
            "stop_gradient_latent_targets": True,
            "target_query_predictors": True,
            "cross_modal_jepa": True,
            "action_conditioned_transition_jepa": True,
            "floor_preserving_transition_wrapper": True,
            "exact_perturbation_id_input": False,
        },
        "leakage_controls": "residual scale selected from train split only; heldout rows scoring-only; action input is program descriptor only",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f032_report(out / "F032_FLOOR_PRESERVING_JEPA_RESIDUAL_CALIBRATION.md", payload, frame, trace_frame)
    append_journal(
        args.output_root,
        "F032_FLOOR_PRESERVING_JEPA_RESIDUAL_CALIBRATION",
        "Train-only floor-preserving residual calibration for F030/F031",
        f"Decision={decision}; selected scale mean={summary['mean_selected_residual_scale']:.6f}; selected transition={summary['mean_selected_transition_improvement']:.6f}; floor transition={summary['mean_floor_transition_improvement']:.6f}.",
    )
    return {
        "experiment_id": "F032",
        "phase": "PostPhase8Council",
        "family": "Floor-preserving real JEPA",
        "tier": "Tier2Calibration",
        "seed": "0,1,2,3,4",
        "dataset": benchmark,
        "eval_split": args.eval_split,
        "mode": "floor_preserving_jepa_residual_calibration",
        "status_label": decision,
        "transition_improvement": f"{summary['mean_selected_transition_improvement']:.6f}",
        "delta_cosine": f"{summary['mean_selected_delta_cosine']:.6f}",
        "recall_at_1": f"{summary['mean_selected_recall_at_1']:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{summary['mean_selected_delta_rank']:.6f}",
        "magnitude_ratio": f"{summary['mean_selected_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": f"{summary['mean_rna_to_image_recall_at_1']:.6f}",
        "image_to_rna_recall_at_1": f"{summary['mean_image_to_rna_recall_at_1']:.6f}",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(frame['target_effective_rank'].mean()) if not frame.empty else 0.0:.6f}",
        "effective_rank_target": f"{summary['mean_floor_delta_cosine']:.6f}",
        "collapse_flag": str(summary["mean_selected_delta_rank"] < 2.0),
        "leakage_flag": str(summary["max_leakage_flag"] > 0.0),
        "floor_gap_transition": f"{summary['mean_selected_gap_transition']:.6f}",
        "floor_gap_recall": f"{summary['mean_selected_gap_recall']:.6f}",
        "floor_gap_delta_cosine": f"{summary['mean_selected_gap_delta_cosine']:.6f}",
        "selected_residual_scale": f"{summary['mean_selected_residual_scale']:.6f}",
        "calibration_lcb_transition_gap": f"{summary['min_selected_gap_transition']:.6f}",
        "calibration_lcb_recall_gap": f"{summary['min_selected_gap_recall']:.6f}",
        "action_negative_gap": f"{summary['mean_action_negative_transition_gap']:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": str(summary["max_identity_violation"] == 0.0),
        "notes": "Train-only floor-preserving residual calibration; no model promotion.",
        "artifact_dir": str(out),
    }


@torch.no_grad()
def _evaluate_program_jepa_floor_blend(
    model: ProgramBootstrapJEPA,
    train_table: dict[str, Any],
    eval_table: dict[str, Any],
    *,
    device: str,
    scale_grid: tuple[float, ...] = (0.0, 0.1, 0.25, 0.5, 0.75, 1.0),
    train_transition_margin: float = 0.0,
    train_delta_margin: float = 0.0,
    train_recall_margin: float = 0.0,
) -> dict[str, float]:
    train_encoded = _encode_program_jepa_table(model, train_table, device=device)
    eval_encoded = _encode_program_jepa_table(model, eval_table, device=device)
    train_bundle = LatentOperatorBundle(
        name="f032_train",
        arrays={
            "source_z_bio_teacher": train_encoded["source"],
            "target_z_bio_teacher": train_encoded["target"],
            "action_descriptor": train_table["action"].astype(np.float64),
        },
        metadata=train_table["metadata"],
    )
    eval_bundle = LatentOperatorBundle(
        name="f032_eval",
        arrays={
            "source_z_bio_teacher": eval_encoded["source"],
            "target_z_bio_teacher": eval_encoded["target"],
            "action_descriptor": eval_table["action"].astype(np.float64),
        },
        metadata=eval_table["metadata"],
    )
    ridge_fit = fit_ridge_numpy(np.concatenate((train_bundle.source, train_bundle.action), axis=1), train_bundle.delta, alpha=1.0e-2)
    train_floor_delta = predict_ridge_numpy(ridge_fit, np.concatenate((train_bundle.source, train_bundle.action), axis=1))
    eval_floor_delta = predict_ridge_numpy(ridge_fit, np.concatenate((eval_bundle.source, eval_bundle.action), axis=1))
    train_direct_delta = train_encoded["transition"] - train_encoded["source"]
    eval_direct_delta = eval_encoded["transition"] - eval_encoded["source"]
    floor_train_metrics = bundle_transition_metrics(train_bundle, train_floor_delta)
    floor_eval_metrics = bundle_transition_metrics(eval_bundle, eval_floor_delta)
    direct_eval_metrics = bundle_transition_metrics(eval_bundle, eval_direct_delta)
    selected_scale = 0.0
    selected_train_metrics = floor_train_metrics
    for scale in scale_grid:
        train_delta = train_floor_delta + scale * (train_direct_delta - train_floor_delta)
        metrics = bundle_transition_metrics(train_bundle, train_delta)
        preserves = scale == 0.0 or (
            metrics["transition_source_cosine_improvement"] >= floor_train_metrics["transition_source_cosine_improvement"] + train_transition_margin - 1.0e-9
            and metrics["delta_cosine"] >= floor_train_metrics["delta_cosine"] + train_delta_margin - 1.0e-9
            and metrics.get("transition_to_target_recall@1", 0.0) >= floor_train_metrics.get("transition_to_target_recall@1", 0.0) + train_recall_margin - 1.0e-9
        )
        if preserves and metrics["transition_source_cosine_improvement"] >= selected_train_metrics["transition_source_cosine_improvement"] - 1.0e-9:
            selected_scale = float(scale)
            selected_train_metrics = metrics
    selected_eval_delta = eval_floor_delta + selected_scale * (eval_direct_delta - eval_floor_delta)
    selected_eval_metrics = bundle_transition_metrics(eval_bundle, selected_eval_delta)
    wrong_action = np.roll(eval_table["action"], shift=1, axis=0)
    wrong_floor_delta = predict_ridge_numpy(ridge_fit, np.concatenate((eval_bundle.source, wrong_action), axis=1))
    wrong_direct_transition = _predict_program_jepa_transition(model, eval_table["control_expression"], wrong_action, device=device)
    wrong_direct_delta = wrong_direct_transition - eval_encoded["source"]
    wrong_selected_delta = wrong_floor_delta + selected_scale * (wrong_direct_delta - wrong_floor_delta)
    wrong_metrics = bundle_transition_metrics(eval_bundle, wrong_selected_delta)
    rna_to_image = directional_retrieval_metrics(
        _l2_normalize_numpy(eval_encoded["rna_to_image"]),
        _l2_normalize_numpy(eval_encoded["image_target"]),
        eval_table["metadata"],
        eval_table["metadata"],
        label_col="condition_key",
        ks=(1, 5),
        prefix="rna_to_image",
        stratify_by=(),
    )
    image_to_rna = directional_retrieval_metrics(
        _l2_normalize_numpy(eval_encoded["image_to_rna"]),
        _l2_normalize_numpy(eval_encoded["target"]),
        eval_table["metadata"],
        eval_table["metadata"],
        label_col="condition_key",
        ks=(1, 5),
        prefix="image_to_rna",
        stratify_by=(),
    )
    return {
        "selected_residual_scale": selected_scale,
        "selected_train_transition_improvement": selected_train_metrics["transition_source_cosine_improvement"],
        "selected_train_delta_cosine": selected_train_metrics["delta_cosine"],
        "selected_train_recall_at_1": selected_train_metrics.get("transition_to_target_recall@1", 0.0),
        "selected_transition_improvement": selected_eval_metrics["transition_source_cosine_improvement"],
        "selected_delta_cosine": selected_eval_metrics["delta_cosine"],
        "selected_recall_at_1": selected_eval_metrics.get("transition_to_target_recall@1", 0.0),
        "selected_delta_rank": selected_eval_metrics["delta_prediction_effective_rank"],
        "selected_magnitude_ratio": selected_eval_metrics["delta_magnitude_ratio"],
        "floor_transition_improvement": floor_eval_metrics["transition_source_cosine_improvement"],
        "floor_delta_cosine": floor_eval_metrics["delta_cosine"],
        "floor_recall_at_1": floor_eval_metrics.get("transition_to_target_recall@1", 0.0),
        "floor_delta_rank": floor_eval_metrics["delta_prediction_effective_rank"],
        "direct_transition_improvement": direct_eval_metrics["transition_source_cosine_improvement"],
        "direct_delta_cosine": direct_eval_metrics["delta_cosine"],
        "direct_recall_at_1": direct_eval_metrics.get("transition_to_target_recall@1", 0.0),
        "direct_delta_rank": direct_eval_metrics["delta_prediction_effective_rank"],
        "selected_gap_transition": selected_eval_metrics["transition_source_cosine_improvement"] - floor_eval_metrics["transition_source_cosine_improvement"],
        "selected_gap_delta_cosine": selected_eval_metrics["delta_cosine"] - floor_eval_metrics["delta_cosine"],
        "selected_gap_recall": selected_eval_metrics.get("transition_to_target_recall@1", 0.0) - floor_eval_metrics.get("transition_to_target_recall@1", 0.0),
        "selected_action_negative_gap": selected_eval_metrics["transition_source_cosine_improvement"] - wrong_metrics["transition_source_cosine_improvement"],
        "rna_to_image_recall_at_1": float(rna_to_image.get("rna_to_image_recall@1", 0.0)),
        "image_to_rna_recall_at_1": float(image_to_rna.get("image_to_rna_recall@1", 0.0)),
        "target_effective_rank": effective_rank(eval_encoded["target"]),
        "image_target_effective_rank": effective_rank(eval_encoded["image_target"]),
        "identity_violation": 0.0,
        "leakage_flag": 0.0,
    }


def continue_after_f031_to_f032(args: argparse.Namespace) -> dict[str, Any]:
    f031 = _load_metric_json(args.output_root / "experiments/F031_delta_direction_tier2_validation/metrics_eval.json")
    trigger = str(f031.get("diagnostic_label", "F031_PROTECTED_TIER2_PASS_LOCAL_RIDGE_FLOOR_NOT_PRESERVED"))
    proposals = [
        CouncilProposal(
            "F032 train-only floor-preserving JEPA residual calibration",
            {"novelty": 0.62, "feasibility": 0.90, "identity": 0.94, "effect": 0.66, "falsifiability": 0.98, "leakage": 0.96, "compute": 0.82},
            "Default to the train-only same-representation ridge floor and select a JEPA residual scale only if train-only calibration preserves transition, delta cosine, and recall.",
        ),
        CouncilProposal(
            "Proceed to Tier 3 despite local floor miss",
            {"novelty": 0.55, "feasibility": 0.52, "identity": 0.86, "effect": 0.62, "falsifiability": 0.62, "leakage": 0.78, "compute": 0.44},
            "Reject because F031 did not preserve the stronger local train-only floor required for no-regression confidence.",
        ),
        CouncilProposal(
            "Train longer with the same direct head",
            {"novelty": 0.18, "feasibility": 0.86, "identity": 0.94, "effect": 0.32, "falsifiability": 0.54, "leakage": 0.94, "compute": 0.58},
            "Reject because the failure is local floor preservation, not lack of positive protected-floor signal.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "061", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f032_floor_preserving_jepa(args.output_root, "061", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "061", trigger, council_path, amendment_path, selected.next_action)
    return run_f032_floor_preserving_jepa_residual_calibration(args)


def _write_f032_report(path: Path, payload: dict[str, Any], frame: pd.DataFrame, trace: pd.DataFrame) -> None:
    frame_tsv = frame.to_csv(sep="\t", index=False) if not frame.empty else "No seed rows.\n"
    trace_tsv = trace.to_csv(sep="\t", index=False) if not trace.empty else "No trace rows.\n"
    path.write_text(
        f"""# F032 Floor-Preserving JEPA Residual Calibration

## Decision
`{payload['diagnostic_label']}`

## Purpose
F031 passed the protected Tier 2 gates but failed to preserve the same-representation train-only ridge floor. F032 wraps the real JEPA predictor in a floor-preserving calibration rule: start exactly at the local train-only ridge floor and only add the JEPA residual if train-only calibration preserves transition, delta cosine, and recall.

## Mean Metrics
- selected residual scale mean: `{payload['mean_selected_residual_scale']:.6f}`
- selected nonzero fraction: `{payload['selected_nonzero_fraction']:.6f}`
- heldout local floor preserved: `{payload['heldout_local_floor_preserved']}`
- selected transition: `{payload['mean_selected_transition_improvement']:.6f}`
- local floor transition: `{payload['mean_floor_transition_improvement']:.6f}`
- direct JEPA transition: `{payload['mean_direct_transition_improvement']:.6f}`
- selected delta cosine: `{payload['mean_selected_delta_cosine']:.6f}`
- local floor delta cosine: `{payload['mean_floor_delta_cosine']:.6f}`
- selected recall@1: `{payload['mean_selected_recall_at_1']:.6f}`
- local floor recall@1: `{payload['mean_floor_recall_at_1']:.6f}`
- selected floor gap transition: `{payload['mean_selected_gap_transition']:.6f}` (min `{payload['min_selected_gap_transition']:.6f}`)
- selected floor gap delta cosine: `{payload['mean_selected_gap_delta_cosine']:.6f}` (min `{payload['min_selected_gap_delta_cosine']:.6f}`)
- selected floor gap recall: `{payload['mean_selected_gap_recall']:.6f}` (min `{payload['min_selected_gap_recall']:.6f}`)
- RNA->image recall@1: `{payload['mean_rna_to_image_recall_at_1']:.6f}`
- image->RNA recall@1: `{payload['mean_image_to_rna_recall_at_1']:.6f}`

## Seed Rows
```tsv
{frame_tsv}
```

## Train Trace
```tsv
{trace_tsv}
```

## Promotion Status
No model is promoted. If the selected scale is zero, this branch confirms that F030's direct JEPA residual is useful for representation and direction learning but not yet safe above the local train-only ridge floor.
""",
        encoding="utf-8",
    )


def write_amendment_f032_floor_preserving_jepa(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Floor-Preserving JEPA Residual Calibration

## Trigger
`{trigger}`

## Evidence
F031 passed protected Tier 2 gates and maintained cross-modal retrieval, but the direct JEPA transition head fell below the same-representation train-only ridge floor on transition, delta cosine, and recall. The next experiment must preserve the local floor exactly before allowing any JEPA residual.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it.

## New Candidate Branch
`F032_FLOOR_PRESERVING_JEPA_RESIDUAL_CALIBRATION`

## Implementation Tasks
- Train the same low-compute F030 real JEPA on seeds 0-4.
- Fit the same-representation train-only ridge floor on frozen learned latents.
- Build residuals as `direct_jepa_delta - local_ridge_floor_delta`.
- Select residual scale using train rows only, requiring transition, delta cosine, and recall to preserve the train floor.
- Score held-out rows only after selection.
- Keep action input as non-exact program descriptors only.

## Decision Use
If nonzero residual scale preserves the held-out local floor, design a Tier 3/no-regression amendment. If scale zero is selected, pivot to an operator-initialized transition predictor instead of treating direct residuals as safe.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def run_f033_conservative_floor_gate(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F033_conservative_floor_gate"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [0, 1, 2, 3, 4]
    benchmark = "synth_program_aligned_genetic_lite"
    rows: list[dict[str, Any]] = []
    train_trace_rows: list[dict[str, Any]] = []
    for seed in seeds:
        dataset = generate_synthetic_biology_lite(synthetic_lite_config(benchmark, seed=seed))
        pca_z = _train_only_pca_embeddings(dataset.expression_values, dataset.metadata, dim=24)
        train_table = _program_jepa_condition_table(dataset, pca_z, split="train")
        eval_table = _program_jepa_condition_table(dataset, pca_z, split=args.eval_split)
        config = ProgramBootstrapJEPAConfig(
            genes=dataset.config.genes,
            image_dim=int(dataset.images.reshape(dataset.images.shape[0], -1).shape[1]),
            action_dim=int(train_table["action"].shape[1]),
            z_dim=24,
            hidden_dim=96,
            pca_anchor_weight=0.15,
            transition_weight=1.0,
            cross_modal_weight=0.75,
            action_negative_weight=0.15,
            delta_direction_weight=0.8,
            source_improvement_weight=0.5,
            variance_weight=0.05,
        )
        model, trace = _train_program_bootstrap_jepa(train_table, config, seed=seed + 3032, device=args.device)
        seed_out = out / f"seed{seed}"
        seed_out.mkdir(parents=True, exist_ok=True)
        write_json(seed_out / "train_trace_summary.json", trace)
        train_trace_rows.append({"seed": seed, **trace})
        eval_payload = _evaluate_program_jepa_floor_blend(
            model,
            train_table,
            eval_table,
            device=args.device,
            scale_grid=(0.0, 0.025, 0.05, 0.1, 0.15, 0.2, 0.25),
            train_transition_margin=0.002,
            train_delta_margin=0.005,
            train_recall_margin=0.05,
        )
        write_json(seed_out / "metrics_eval.json", eval_payload)
        rows.append({"seed": seed, **eval_payload})
    frame = pd.DataFrame(rows)
    trace_frame = pd.DataFrame(train_trace_rows)
    frame.to_csv(out / "f033_by_seed.tsv", sep="\t", index=False)
    trace_frame.to_csv(out / "train_trace_by_seed.tsv", sep="\t", index=False)
    selected_nonzero_fraction = float((frame["selected_residual_scale"] > 0.0).mean()) if not frame.empty else 0.0
    heldout_preserved = (
        bool((frame["selected_gap_transition"] >= -0.001).all())
        and bool((frame["selected_gap_delta_cosine"] >= -0.001).all())
        and bool((frame["selected_gap_recall"] >= -0.001).all())
    )
    summary = {
        "seed_count": int(len(frame)),
        "selected_nonzero_fraction": selected_nonzero_fraction,
        "mean_selected_residual_scale": float(frame["selected_residual_scale"].mean()) if not frame.empty else 0.0,
        "max_selected_residual_scale": float(frame["selected_residual_scale"].max()) if not frame.empty else 0.0,
        "mean_selected_transition_improvement": float(frame["selected_transition_improvement"].mean()) if not frame.empty else 0.0,
        "mean_selected_delta_cosine": float(frame["selected_delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_selected_recall_at_1": float(frame["selected_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_selected_delta_rank": float(frame["selected_delta_rank"].mean()) if not frame.empty else 0.0,
        "mean_selected_magnitude_ratio": float(frame["selected_magnitude_ratio"].mean()) if not frame.empty else 0.0,
        "mean_floor_transition_improvement": float(frame["floor_transition_improvement"].mean()) if not frame.empty else 0.0,
        "mean_floor_delta_cosine": float(frame["floor_delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_floor_recall_at_1": float(frame["floor_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_selected_gap_transition": float(frame["selected_gap_transition"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_transition": float(frame["selected_gap_transition"].min()) if not frame.empty else 0.0,
        "mean_selected_gap_delta_cosine": float(frame["selected_gap_delta_cosine"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_delta_cosine": float(frame["selected_gap_delta_cosine"].min()) if not frame.empty else 0.0,
        "mean_selected_gap_recall": float(frame["selected_gap_recall"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_recall": float(frame["selected_gap_recall"].min()) if not frame.empty else 0.0,
        "mean_rna_to_image_recall_at_1": float(frame["rna_to_image_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_image_to_rna_recall_at_1": float(frame["image_to_rna_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_action_negative_transition_gap": float(frame["selected_action_negative_gap"].mean()) if not frame.empty else 0.0,
        "max_identity_violation": float(frame["identity_violation"].max()) if not frame.empty else 1.0,
        "max_leakage_flag": float(frame["leakage_flag"].max()) if not frame.empty else 1.0,
    }
    if selected_nonzero_fraction > 0.0 and heldout_preserved:
        decision = "F033_CONSERVATIVE_GATE_SAFE_NONZERO_RESIDUAL"
    elif selected_nonzero_fraction == 0.0 and heldout_preserved:
        decision = "F033_CONSERVATIVE_GATE_ZERO_FALLBACK"
    elif selected_nonzero_fraction > 0.0:
        decision = "F033_CONSERVATIVE_GATE_STILL_HELDOUT_BELOW_LOCAL_FLOOR"
    else:
        decision = "F033_CONSERVATIVE_GATE_FAIL"
    payload = {
        "diagnostic_label": decision,
        "benchmark": benchmark,
        "heldout_local_floor_preserved": heldout_preserved,
        "selection_rule": {
            "scale_grid": [0.0, 0.025, 0.05, 0.1, 0.15, 0.2, 0.25],
            "train_transition_margin": 0.002,
            "train_delta_margin": 0.005,
            "train_recall_margin": 0.05,
        },
        **summary,
        "seed_rows": rows,
        "train_trace": train_trace_rows,
        "model_promoted": False,
        "identity_controls": {
            "online_context_encoders": True,
            "ema_target_encoders": True,
            "stop_gradient_latent_targets": True,
            "target_query_predictors": True,
            "cross_modal_jepa": True,
            "action_conditioned_transition_jepa": True,
            "floor_preserving_transition_wrapper": True,
            "exact_perturbation_id_input": False,
        },
        "leakage_controls": "conservative residual scale selected from train split only; heldout rows scoring-only; action input is program descriptor only",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f033_report(out / "F033_CONSERVATIVE_FLOOR_GATE.md", payload, frame, trace_frame)
    append_journal(
        args.output_root,
        "F033_CONSERVATIVE_FLOOR_GATE",
        "Conservative train-only gate for JEPA residual above local floor",
        f"Decision={decision}; nonzero fraction={selected_nonzero_fraction:.3f}; heldout preserved={heldout_preserved}; selected transition={summary['mean_selected_transition_improvement']:.6f}.",
    )
    return {
        "experiment_id": "F033",
        "phase": "PostPhase8Council",
        "family": "Floor-preserving real JEPA",
        "tier": "Tier2Calibration",
        "seed": "0,1,2,3,4",
        "dataset": benchmark,
        "eval_split": args.eval_split,
        "mode": "conservative_floor_gate",
        "status_label": decision,
        "transition_improvement": f"{summary['mean_selected_transition_improvement']:.6f}",
        "delta_cosine": f"{summary['mean_selected_delta_cosine']:.6f}",
        "recall_at_1": f"{summary['mean_selected_recall_at_1']:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{summary['mean_selected_delta_rank']:.6f}",
        "magnitude_ratio": f"{summary['mean_selected_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": f"{summary['mean_rna_to_image_recall_at_1']:.6f}",
        "image_to_rna_recall_at_1": f"{summary['mean_image_to_rna_recall_at_1']:.6f}",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(frame['target_effective_rank'].mean()) if not frame.empty else 0.0:.6f}",
        "effective_rank_target": f"{summary['mean_floor_delta_cosine']:.6f}",
        "collapse_flag": str(summary["mean_selected_delta_rank"] < 2.0),
        "leakage_flag": str(summary["max_leakage_flag"] > 0.0),
        "floor_gap_transition": f"{summary['mean_selected_gap_transition']:.6f}",
        "floor_gap_recall": f"{summary['mean_selected_gap_recall']:.6f}",
        "floor_gap_delta_cosine": f"{summary['mean_selected_gap_delta_cosine']:.6f}",
        "selected_residual_scale": f"{summary['mean_selected_residual_scale']:.6f}",
        "calibration_lcb_transition_gap": f"{summary['min_selected_gap_transition']:.6f}",
        "calibration_lcb_recall_gap": f"{summary['min_selected_gap_recall']:.6f}",
        "action_negative_gap": f"{summary['mean_action_negative_transition_gap']:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": str(summary["max_identity_violation"] == 0.0),
        "notes": "Conservative train-only residual gate; no model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f032_to_f033(args: argparse.Namespace) -> dict[str, Any]:
    f032 = _load_metric_json(args.output_root / "experiments/F032_floor_preserving_jepa_residual_calibration/metrics_eval.json")
    trigger = str(f032.get("diagnostic_label", "F032_NONZERO_RESIDUAL_DISCARDED_HELDOUT_BELOW_LOCAL_FLOOR"))
    proposals = [
        CouncilProposal(
            "F033 conservative train-only residual gate",
            {"novelty": 0.58, "feasibility": 0.92, "identity": 0.94, "effect": 0.62, "falsifiability": 0.98, "leakage": 0.96, "compute": 0.82},
            "Use a smaller residual scale grid and require positive train-side transition, delta, and recall slack before deploying a nonzero residual.",
        ),
        CouncilProposal(
            "Tier 3 despite one heldout recall miss",
            {"novelty": 0.50, "feasibility": 0.46, "identity": 0.88, "effect": 0.64, "falsifiability": 0.58, "leakage": 0.80, "compute": 0.42},
            "Reject because F032 explicitly violated the heldout local floor on recall.",
        ),
        CouncilProposal(
            "Discard all residuals immediately",
            {"novelty": 0.30, "feasibility": 0.95, "identity": 0.90, "effect": 0.42, "falsifiability": 0.74, "leakage": 0.96, "compute": 0.94},
            "Defer one stricter calibration check because F032 had positive mean local floor gaps and only a small recall failure.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "062", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f033_conservative_floor_gate(args.output_root, "062", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "062", trigger, council_path, amendment_path, selected.next_action)
    return run_f033_conservative_floor_gate(args)


