def continue_after_f048_to_f049(args: argparse.Namespace) -> dict[str, Any]:
    f048 = _load_metric_json(args.output_root / "experiments/F048_non_exact_action_contract/metrics_eval.json")
    trigger = str(f048.get("diagnostic_label", "F048_NON_EXACT_ACTION_OPERATOR_STILL_BELOW_FLOOR"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F047", "F048"])].to_dict("records")
    write_phase_closure(args.output_root, "078", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F049 protected floor feature contract audit",
            {"novelty": 0.58, "feasibility": 0.99, "identity": 0.98, "effect": 0.80, "falsifiability": 0.99, "leakage": 0.98, "compute": 0.99},
            "Decompose the protected full-ridge floor and quantify whether train exact-action columns create a centering/extrapolation advantage over candidate-legal program actions.",
        ),
        CouncilProposal(
            "Train program-only JEPA longer",
            {"novelty": 0.36, "feasibility": 0.74, "identity": 0.88, "effect": 0.34, "falsifiability": 0.60, "leakage": 0.90, "compute": 0.48},
            "Reject because F048 program-only floor itself falls below the protected full floor and active gates.",
        ),
        CouncilProposal(
            "Replace the protected floor immediately",
            {"novelty": 0.42, "feasibility": 0.66, "identity": 0.72, "effect": 0.58, "falsifiability": 0.64, "leakage": 0.62, "compute": 0.90},
            "Defer; the prompt protects the full-ridge floor, so any floor-contract change requires explicit diagnostic evidence first.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "078", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f049_floor_feature_contract(args.output_root, "078", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "078", trigger, council_path, amendment_path, selected.next_action)
    return run_f049_floor_feature_contract(args)


def _write_f049_report(path: Path, payload: dict[str, Any], frame: pd.DataFrame) -> None:
    seed_tsv = frame.to_csv(sep="\t", index=False) if not frame.empty else "No seed rows.\n"
    path.write_text(
        f"""# F049 Floor Feature Contract

## Decision
`{payload['diagnostic_label']}`

## Purpose
F048 showed that removing exact perturbation one-hot action columns makes the candidate-legal program-action floor fall below the protected full floor. F049 decomposes the protected full-ridge prediction to determine whether train exact-action columns provide a centering/extrapolation contribution on held-out perturbations.

## Key Metrics
- mean full transition: `{payload['mean_full_transition_improvement']:.6f}`
- mean full delta cosine: `{payload['mean_full_delta_cosine']:.6f}`
- mean full recall@1: `{payload['mean_full_recall_at_1']:.6f}`
- mean no-train-exact transition: `{payload['mean_no_train_exact_transition_improvement']:.6f}`
- mean no-train-exact delta cosine: `{payload['mean_no_train_exact_delta_cosine']:.6f}`
- mean no-train-exact recall@1: `{payload['mean_no_train_exact_recall_at_1']:.6f}`
- no-train-exact transition gap: `{payload['mean_no_train_exact_gap_transition']:.6f}`
- no-train-exact delta gap: `{payload['mean_no_train_exact_gap_delta_cosine']:.6f}`
- no-train-exact recall gap: `{payload['mean_no_train_exact_gap_recall']:.6f}`
- exact train-action contribution norm fraction: `{payload['mean_exact_train_contrib_norm_fraction']:.6f}`
- program contribution norm fraction: `{payload['mean_program_contrib_norm_fraction']:.6f}`
- exact train-action contribution delta cosine: `{payload['mean_exact_train_contrib_delta_cosine']:.6f}`
- eval unseen exact-action contribution norm: `{payload['mean_eval_unseen_exact_contrib_norm']:.6f}`

## Interpretation
This is a diagnostic-only audit of the protected floor. It does not replace the protected model of record or protected floor, but it documents whether the protected floor depends on feature behavior that candidate JEPA paths are forbidden to use as their main representation/action path.

## Seed Rows
```tsv
{seed_tsv}
```

## Promotion Status
No model is promoted.
""",
        encoding="utf-8",
    )


def write_amendment_f049_floor_feature_contract(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Protected Floor Feature Contract Audit

## Trigger
`{trigger}`

## Evidence
F048 removed exact perturbation action one-hots and used only shared program action descriptors. The program-action floor and program-action residual stayed below the protected full floor, while the full floor remained much stronger. This suggests the protected floor may benefit from train exact-action feature centering or extrapolation even though candidate JEPA paths cannot use exact perturbation one-hots.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it. This audit does not demote or replace it.

## New Diagnostic Branch
`F049_FLOOR_FEATURE_CONTRACT`

## Implementation Tasks
- Fit the protected full action-ridge floor on train only.
- Decompose held-out predictions into source, train exact-action, eval-unseen exact-action, and program-action feature contributions.
- Score the full prediction and counterfactual predictions with train exact-action contribution removed.
- Quantify whether the full floor advantage depends on exact train-action feature centering.

## Decision Use
If the full floor depends materially on exact train-action contribution, keep it as protected audit baseline but stop treating it as a candidate-legal action contract. The next branch should target a valid biological action descriptor or benchmark contract.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def run_f050_source_action_contract_synthesis(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F050_source_action_contract_synthesis"
    out.mkdir(parents=True, exist_ok=True)
    f048 = _load_metric_json(args.output_root / "experiments/F048_non_exact_action_contract/metrics_eval.json")
    f049 = _load_metric_json(args.output_root / "experiments/F049_floor_feature_contract/metrics_eval.json")
    full = f048.get("full_floor_summary", {})
    program = f048.get("program_floor_summary", {})
    source = {}
    for row in f048.get("floor_variant_summary", []):
        if row.get("variant") == "source_only":
            source = row
            break
    full_transition = float(full.get("mean_transition_improvement", f049.get("mean_full_transition_improvement", 0.0)))
    full_delta = float(full.get("mean_delta_cosine", f049.get("mean_full_delta_cosine", 0.0)))
    full_recall = float(full.get("mean_recall_at_1", f049.get("mean_full_recall_at_1", 0.0)))
    source_transition = float(source.get("mean_transition_improvement", 0.0))
    source_delta = float(source.get("mean_delta_cosine", 0.0))
    source_recall = float(source.get("mean_recall_at_1", 0.0))
    program_transition = float(program.get("mean_transition_improvement", 0.0))
    program_delta = float(program.get("mean_delta_cosine", 0.0))
    program_recall = float(program.get("mean_recall_at_1", 0.0))
    adjusted_source_transition = float(f049.get("mean_no_action_transition_improvement", 0.0))
    adjusted_source_delta = float(f049.get("mean_no_action_delta_cosine", 0.0))
    no_exact_transition = float(f049.get("mean_no_train_exact_transition_improvement", 0.0))
    no_exact_delta = float(f049.get("mean_no_train_exact_delta_cosine", 0.0))
    exact_fraction = float(f049.get("mean_exact_train_contrib_norm_fraction", 0.0))
    program_fraction = float(f049.get("mean_program_contrib_norm_fraction", 0.0))
    metrics = {
        "full_transition": full_transition,
        "full_delta_cosine": full_delta,
        "full_recall_at_1": full_recall,
        "source_transition": source_transition,
        "source_delta_cosine": source_delta,
        "source_recall_at_1": source_recall,
        "program_transition": program_transition,
        "program_delta_cosine": program_delta,
        "program_recall_at_1": program_recall,
        "adjusted_source_transition": adjusted_source_transition,
        "adjusted_source_delta_cosine": adjusted_source_delta,
        "no_exact_transition": no_exact_transition,
        "no_exact_delta_cosine": no_exact_delta,
        "source_gap_transition_vs_full": source_transition - full_transition,
        "source_gap_delta_vs_full": source_delta - full_delta,
        "source_gap_recall_vs_full": source_recall - full_recall,
        "program_gap_transition_vs_full": program_transition - full_transition,
        "program_gap_delta_vs_full": program_delta - full_delta,
        "program_gap_recall_vs_full": program_recall - full_recall,
        "adjusted_source_gap_transition_vs_full": adjusted_source_transition - full_transition,
        "adjusted_source_gap_delta_vs_full": adjusted_source_delta - full_delta,
        "no_exact_gap_transition_vs_full": no_exact_transition - full_transition,
        "no_exact_gap_delta_vs_full": no_exact_delta - full_delta,
        "adjusted_source_gain_transition_vs_source_only": adjusted_source_transition - source_transition,
        "adjusted_source_gain_delta_vs_source_only": adjusted_source_delta - source_delta,
        "exact_train_contrib_norm_fraction": exact_fraction,
        "program_contrib_norm_fraction": program_fraction,
    }
    if (
        abs(metrics["no_exact_gap_transition_vs_full"]) <= 1.0e-6
        and exact_fraction <= 1.0e-6
        and metrics["program_gap_transition_vs_full"] < -0.003
        and metrics["adjusted_source_gap_transition_vs_full"] >= -0.001
    ):
        decision = "F050_PROTECTED_FLOOR_IS_COVARIATE_ADJUSTED_SOURCE_DOMINATED"
    elif metrics["program_gap_transition_vs_full"] < -0.003:
        decision = "F050_PROGRAM_ACTION_CONTRACT_BELOW_PROTECTED_FLOOR"
    else:
        decision = "F050_SOURCE_ACTION_CONTRACT_SYNTHESIS_AMBIGUOUS"
    payload = {
        "diagnostic_label": decision,
        **metrics,
        "model_promoted": False,
        "interpretation": "The full protected floor is not directly using held-out exact perturbation one-hots. Its advantage over the candidate-legal program-action floor is mainly a covariate-adjusted source-state fit learned with train action covariates. This makes the protected floor a valid audit baseline but a poor identity target for a JEPA action contract.",
        "next_recommendation": "Pivot to a biological action-target contract with shared descriptors or a descriptor-aligned benchmark before another residual/operator head.",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f050_report(out / "F050_SOURCE_ACTION_CONTRACT_SYNTHESIS.md", payload)
    append_journal(
        args.output_root,
        "F050_SOURCE_ACTION_CONTRACT_SYNTHESIS",
        "Synthesis of F047-F049 source/action contract evidence",
        f"Decision={decision}; program gap={metrics['program_gap_transition_vs_full']:.6f}; adjusted-source gap={metrics['adjusted_source_gap_transition_vs_full']:.6f}.",
    )
    return {
        "experiment_id": "F050",
        "phase": "PostPhase8Council",
        "family": "Source/action contract synthesis",
        "tier": "DiagnosticSynthesis",
        "seed": "0,1,2,3,4",
        "dataset": "synthetic_genetic_anchor_lite_multiseed_v1",
        "eval_split": args.eval_split,
        "mode": "source_action_contract_synthesis",
        "status_label": decision,
        "transition_improvement": f"{full_transition:.6f}",
        "delta_cosine": f"{full_delta:.6f}",
        "recall_at_1": f"{full_recall:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(f048.get('mean_selected_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": f"{float(f048.get('mean_selected_magnitude_ratio', 0.0)):.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(f048.get('mean_selected_delta_rank', 0.0)):.6f}",
        "effective_rank_target": f"{program_fraction:.6f}",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": f"{metrics['program_gap_transition_vs_full']:.6f}",
        "floor_gap_recall": f"{metrics['program_gap_recall_vs_full']:.6f}",
        "floor_gap_delta_cosine": f"{metrics['program_gap_delta_vs_full']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{metrics['adjusted_source_gap_transition_vs_full']:.6f}",
        "calibration_lcb_recall_gap": f"{exact_fraction:.6f}",
        "action_negative_gap": f"{program_fraction:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Diagnostic synthesis of active source/action contract; no model promotion.",
        "artifact_dir": str(out),
    }


