def _write_f050_report(path: Path, payload: dict[str, Any]) -> None:
    rows = [
        ("full protected floor", payload["full_transition"], payload["full_delta_cosine"], payload["full_recall_at_1"]),
        ("source-only floor", payload["source_transition"], payload["source_delta_cosine"], payload["source_recall_at_1"]),
        ("program-action-only floor", payload["program_transition"], payload["program_delta_cosine"], payload["program_recall_at_1"]),
        ("full-fit no-action contribution", payload["adjusted_source_transition"], payload["adjusted_source_delta_cosine"], 0.0),
        ("full-fit no-exact contribution", payload["no_exact_transition"], payload["no_exact_delta_cosine"], 0.0),
    ]
    table = "\n".join(f"| {name} | {transition:.6f} | {delta:.6f} | {recall:.6f} |" for name, transition, delta, recall in rows)
    path.write_text(
        f"""# F050 Source/Action Contract Synthesis

## Decision
`{payload['diagnostic_label']}`

## Purpose
F047-F049 collectively test whether the active failure is an architecture problem, an exact-action support problem, or a benchmark/action-contract problem.

## Summary Table
| model/audit view | transition improvement | delta cosine | recall@1 |
| --- | ---: | ---: | ---: |
{table}

## Key Gaps
- program-action transition gap vs full: `{payload['program_gap_transition_vs_full']:.6f}`
- program-action delta gap vs full: `{payload['program_gap_delta_vs_full']:.6f}`
- source-only transition gap vs full: `{payload['source_gap_transition_vs_full']:.6f}`
- adjusted-source transition gap vs full: `{payload['adjusted_source_gap_transition_vs_full']:.6f}`
- exact train-action direct contribution fraction: `{payload['exact_train_contrib_norm_fraction']:.6f}`
- program direct contribution fraction: `{payload['program_contrib_norm_fraction']:.6f}`

## Interpretation
{payload['interpretation']}

## Next Recommendation
{payload['next_recommendation']}

## Promotion Status
No model is promoted. The protected model of record and protected full-ridge floor remain active audit references.
""",
        encoding="utf-8",
    )


def write_amendment_f050_source_action_contract(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Source/Action Contract Synthesis

## Trigger
`{trigger}`

## Evidence
F049 found no direct train exact-action contribution to held-out full-ridge predictions, while F048 showed program-only action features fall below the protected full floor. The remaining issue is that the full floor appears to be a covariate-adjusted source-state baseline rather than a deployable action-transition contract.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it. The full-ridge transition floor remains an audit reference.

## New Diagnostic Branch
`F050_SOURCE_ACTION_CONTRACT_SYNTHESIS`

## Implementation Tasks
- Read F047-F049 artifacts.
- Compare full protected floor, source-only floor, candidate-legal program-action floor, no-exact full fit, and no-action full fit.
- Decide whether further operator residual training is cooled.
- Recommend the next autonomous branch around biological action-target contract redesign if the active floor is source/covariate dominated.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def _run_program_aligned_small_cap_validation(
    args: argparse.Namespace,
    out: Path,
    *,
    seeds: list[int],
    benchmark: str,
    seed_offset: int,
    selector=None,
    bundle_prefix: str = "f051",
) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    rows: list[dict[str, Any]] = []
    selection_rows: list[dict[str, Any]] = []
    query_frames: list[pd.DataFrame] = []
    trace_rows: list[dict[str, Any]] = []
    for seed in seeds:
        dataset = generate_synthetic_biology_lite(synthetic_lite_config(benchmark, seed=seed))
        pca_z = _train_only_pca_embeddings(dataset.expression_values, dataset.metadata, dim=24)
        train_table = _program_jepa_condition_table(dataset, pca_z, split="train")
        eval_table = _program_jepa_condition_table(dataset, pca_z, split=args.eval_split)
        config = ProgramBootstrapJEPAConfig(
            genes=dataset.config.genes,
            image_dim=int(dataset.images.reshape(dataset.images.shape[0], -1).shape[1]),
            action_dim=int(train_table["action"].shape[1]),
            z_dim=24,
            hidden_dim=96,
            pca_anchor_weight=0.15,
            transition_weight=1.0,
            cross_modal_weight=0.75,
            action_negative_weight=0.15,
            delta_direction_weight=0.8,
            source_improvement_weight=0.5,
            variance_weight=0.05,
        )
        base_model, trace = _train_program_bootstrap_jepa(train_table, config, seed=seed + seed_offset, device=args.device)
        train_encoded = _encode_program_jepa_table(base_model, train_table, device=args.device)
        eval_encoded = _encode_program_jepa_table(base_model, eval_table, device=args.device)
        train_bundle = LatentOperatorBundle(
            name=f"{bundle_prefix}_seed{seed}_train",
            arrays={
                "source_z_bio_teacher": train_encoded["source"],
                "target_z_bio_teacher": train_encoded["target"],
                "action_descriptor": train_table["action"].astype(np.float64),
            },
            metadata=train_table["metadata"],
        )
        eval_bundle = LatentOperatorBundle(
            name=f"{bundle_prefix}_seed{seed}_eval",
            arrays={
                "source_z_bio_teacher": eval_encoded["source"],
                "target_z_bio_teacher": eval_encoded["target"],
                "action_descriptor": eval_table["action"].astype(np.float64),
            },
            metadata=eval_table["metadata"],
        )
        ridge_fit = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
        head, head_trace = _train_floor_initialized_transition_head(train_bundle, ridge_fit, seed=seed + seed_offset + 3000, device=args.device)
        selector_fn = selector or _select_scale_by_train_continuous_small_cap
        selected_scale, selection_metrics, selection_frame = selector_fn(
            head,
            ridge_fit,
            train_bundle,
            cap=0.05,
            device=args.device,
        )
        eval_payload = _evaluate_floor_initialized_transition_head_fixed_scale(
            head,
            ridge_fit,
            train_bundle,
            eval_bundle,
            eval_encoded,
            eval_table,
            selected_scale=selected_scale,
            device=args.device,
        )
        floor_delta = predict_ridge_numpy(ridge_fit, bundle_features(eval_bundle))
        head_delta = _predict_floor_initialized_head_delta(head, eval_bundle.source, eval_bundle.action, device=args.device)
        selected_delta = floor_delta + float(selected_scale) * (head_delta - floor_delta)
        query_frame = _retrieval_failure_rows(eval_bundle, floor_delta, selected_delta, seed=seed, selected_scale=float(selected_scale))
        query_summary = _summarize_retrieval_failure_rows(query_frame)
        eval_payload.update({f"train_small_cap_{key}": value for key, value in selection_metrics.items()})
        eval_payload.update({f"retrieval_{key}": value for key, value in query_summary.items()})
        eval_payload["selected_residual_scale"] = float(selected_scale)
        rows.append({"seed": seed, **eval_payload})
        query_frames.append(query_frame)
        selection_frame = selection_frame.copy()
        selection_frame.insert(0, "seed", seed)
        selection_rows.extend(selection_frame.to_dict("records"))
        seed_out = out / f"seed{seed}"
        seed_out.mkdir(parents=True, exist_ok=True)
        query_frame.to_csv(seed_out / "query_retrieval_failures.tsv", sep="\t", index=False)
        selection_frame.to_csv(seed_out / "train_small_cap_scale_grid.tsv", sep="\t", index=False)
        trace_row = {"seed": seed, **{f"base_{key}": value for key, value in trace.items()}, **{f"head_{key}": value for key, value in head_trace.items()}}
        trace_rows.append(trace_row)
        write_json(seed_out / "metrics_eval.json", {"seed": seed, **eval_payload})
        write_json(seed_out / "train_trace_summary.json", trace_row)
    frame = pd.DataFrame(rows)
    selection_grid = pd.DataFrame(selection_rows)
    query_frame_all = pd.concat(query_frames, ignore_index=True) if query_frames else pd.DataFrame()
    trace_frame = pd.DataFrame(trace_rows)
    return frame, selection_grid, query_frame_all, trace_frame


def _summarize_small_cap_validation(frame: pd.DataFrame, query_frame: pd.DataFrame, gates: dict[str, float]) -> dict[str, Any]:
    def _column_mean(name: str) -> float:
        return float(frame[name].mean()) if not frame.empty and name in frame.columns else 0.0

    selected_nonzero_fraction = float((frame["selected_residual_scale"] > 0.0).mean()) if not frame.empty else 0.0
    heldout_preserved = (
        bool((frame["selected_gap_transition"] >= -0.001).all())
        and bool((frame["selected_gap_delta_cosine"] >= -0.001).all())
        and bool((frame["selected_gap_recall"] >= -0.001).all())
        and bool((frame["retrieval_broken_count"] <= 0.0).all())
    ) if not frame.empty else False
    active_gates_pass = (
        bool(float(frame["selected_transition_improvement"].mean()) >= gates["primary_transition_gate"])
        and bool(float(frame["selected_delta_cosine"].mean()) >= gates["primary_delta_cosine_gate"])
        and bool(float(frame["selected_recall_at_1"].mean()) >= gates["secondary_recall_gate"])
    ) if not frame.empty else False
    query_summary = _summarize_retrieval_failure_rows(query_frame)
    return {
        "seed_count": int(len(frame)),
        "selected_nonzero_fraction": selected_nonzero_fraction,
        "heldout_local_floor_preserved": heldout_preserved,
        "active_gates_pass": active_gates_pass,
        "mean_selected_residual_scale": float(frame["selected_residual_scale"].mean()) if not frame.empty else 0.0,
        "mean_selected_transition_improvement": float(frame["selected_transition_improvement"].mean()) if not frame.empty else 0.0,
        "mean_selected_delta_cosine": float(frame["selected_delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_selected_recall_at_1": float(frame["selected_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_selected_delta_rank": float(frame["selected_delta_rank"].mean()) if not frame.empty else 0.0,
        "mean_selected_magnitude_ratio": float(frame["selected_magnitude_ratio"].mean()) if not frame.empty else 0.0,
        "mean_floor_transition_improvement": float(frame["floor_transition_improvement"].mean()) if not frame.empty else 0.0,
        "mean_floor_delta_cosine": float(frame["floor_delta_cosine"].mean()) if not frame.empty else 0.0,
        "mean_floor_recall_at_1": float(frame["floor_recall_at_1"].mean()) if not frame.empty else 0.0,
        "mean_selected_gap_transition": float(frame["selected_gap_transition"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_transition": float(frame["selected_gap_transition"].min()) if not frame.empty else 0.0,
        "mean_selected_gap_delta_cosine": float(frame["selected_gap_delta_cosine"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_delta_cosine": float(frame["selected_gap_delta_cosine"].min()) if not frame.empty else 0.0,
        "mean_selected_gap_recall": float(frame["selected_gap_recall"].mean()) if not frame.empty else 0.0,
        "min_selected_gap_recall": float(frame["selected_gap_recall"].min()) if not frame.empty else 0.0,
        "max_identity_violation": float(frame["identity_violation"].max()) if not frame.empty else 1.0,
        "max_leakage_flag": float(frame["leakage_flag"].max()) if not frame.empty else 1.0,
        "max_floor_init_error": float(frame["floor_init_error"].max()) if not frame.empty else 1.0,
        "mean_train_selected_gap_transition": _column_mean("train_small_cap_selected_gap_transition") or _column_mean("train_rowwise_selected_gap_transition"),
        "mean_train_selected_gap_delta_cosine": _column_mean("train_small_cap_selected_gap_delta_cosine") or _column_mean("train_rowwise_selected_gap_delta_cosine"),
        "mean_train_selected_gap_recall": _column_mean("train_small_cap_selected_gap_recall") or _column_mean("train_rowwise_selected_gap_recall"),
        **query_summary,
    }


def run_f051_descriptor_aligned_replication(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F051_descriptor_aligned_replication"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [10, 11, 12]
    benchmark = "synth_program_aligned_genetic_lite"
    gates = _active_multiseed_gates(args)
    frame, selection_grid, query_frame, trace_frame = _run_program_aligned_small_cap_validation(
        args,
        out,
        seeds=seeds,
        benchmark=benchmark,
        seed_offset=9051,
    )
    frame.to_csv(out / "f051_by_seed.tsv", sep="\t", index=False)
    selection_grid.to_csv(out / "f051_train_small_cap_scale_grid.tsv", sep="\t", index=False)
    query_frame.to_csv(out / "f051_query_retrieval_rows.tsv", sep="\t", index=False)
    trace_frame.to_csv(out / "train_trace_by_seed.tsv", sep="\t", index=False)
    summary = _summarize_small_cap_validation(frame, query_frame, gates)
    if summary["selected_nonzero_fraction"] == 1.0 and summary["heldout_local_floor_preserved"] and summary["active_gates_pass"]:
        decision = "F051_DESCRIPTOR_ALIGNED_ACTION_CONTRACT_REPLICATES_SAFE_NONZERO"
    elif summary["selected_nonzero_fraction"] > 0.0 and summary["heldout_local_floor_preserved"]:
        decision = "F051_DESCRIPTOR_ALIGNED_ACTION_CONTRACT_PARTIAL_PASS"
    elif summary["selected_nonzero_fraction"] == 0.0 and summary["heldout_local_floor_preserved"]:
        decision = "F051_DESCRIPTOR_ALIGNED_ACTION_CONTRACT_ZERO_FALLBACK"
    elif summary["selected_nonzero_fraction"] > 0.0:
        decision = "F051_DESCRIPTOR_ALIGNED_ACTION_CONTRACT_HELDOUT_BELOW_FLOOR"
    else:
        decision = "F051_DESCRIPTOR_ALIGNED_ACTION_CONTRACT_FAIL"
    payload = {
        "diagnostic_label": decision,
        "benchmark": benchmark,
        "fresh_seed_set": seeds,
        "gates": gates,
        "selection_rule": "F042 pre-registered tiny-cap rule: choose best train-continuous-safe scale from {0, 0.025, 0.05}; held-out rows scoring-only.",
        **summary,
        "seed_rows": frame.to_dict("records"),
        "model_promoted": False,
        "identity_controls": {
            "online_context_encoders": True,
            "ema_target_encoders": True,
            "stop_gradient_latent_targets": True,
            "target_query_predictors": True,
            "cross_modal_rna_image_jepa": True,
            "action_conditioned_transition_jepa": True,
            "non_exact_program_actions_only": True,
            "exact_perturbation_id_input": False,
        },
        "leakage_controls": "Program action descriptors are deterministic non-exact descriptors. PCA/ridge/residual fitting and scale selection use train rows only; held-out rows are scoring-only.",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f051_report(out / "F051_DESCRIPTOR_ALIGNED_REPLICATION.md", payload, frame, selection_grid, query_frame)
    append_journal(
        args.output_root,
        "F051_DESCRIPTOR_ALIGNED_REPLICATION",
        "Fresh descriptor-aligned action contract replication",
        f"Decision={decision}; nonzero fraction={summary['selected_nonzero_fraction']:.3f}; heldout preserved={summary['heldout_local_floor_preserved']}; transition gap={summary['mean_selected_gap_transition']:.6f}.",
    )
    return {
        "experiment_id": "F051",
        "phase": "PostPhase8Council",
        "family": "Descriptor-aligned action contract",
        "tier": "DiagnosticValidation",
        "seed": "10,11,12",
        "dataset": benchmark,
        "eval_split": args.eval_split,
        "mode": "descriptor_aligned_replication",
        "status_label": decision,
        "transition_improvement": f"{summary['mean_selected_transition_improvement']:.6f}",
        "delta_cosine": f"{summary['mean_selected_delta_cosine']:.6f}",
        "recall_at_1": f"{summary['mean_selected_recall_at_1']:.6f}",
        "median_rank": f"{summary['selected_median_rank']:.6f}",
        "delta_rank": f"{summary['mean_selected_delta_rank']:.6f}",
        "magnitude_ratio": f"{summary['mean_selected_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{summary['mean_selected_delta_rank']:.6f}",
        "effective_rank_target": f"{summary['mean_floor_delta_cosine']:.6f}",
        "collapse_flag": str(summary["mean_selected_delta_rank"] < 2.0),
        "leakage_flag": str(summary["max_leakage_flag"] > 0.0),
        "floor_gap_transition": f"{summary['mean_selected_gap_transition']:.6f}",
        "floor_gap_recall": f"{summary['mean_selected_gap_recall']:.6f}",
        "floor_gap_delta_cosine": f"{summary['mean_selected_gap_delta_cosine']:.6f}",
        "selected_residual_scale": f"{summary['mean_selected_residual_scale']:.6f}",
        "calibration_lcb_transition_gap": f"{summary['min_selected_gap_transition']:.6f}",
        "calibration_lcb_recall_gap": f"{summary['min_selected_gap_recall']:.6f}",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": str(summary["max_identity_violation"] == 0.0 and summary["max_floor_init_error"] <= 1.0e-5),
        "notes": "Fresh descriptor-aligned program-action JEPA diagnostic replication; no model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f050_to_f051(args: argparse.Namespace) -> dict[str, Any]:
    f050 = _load_metric_json(args.output_root / "experiments/F050_source_action_contract_synthesis/metrics_eval.json")
    trigger = str(f050.get("diagnostic_label", "F050_PROTECTED_FLOOR_IS_COVARIATE_ADJUSTED_SOURCE_DOMINATED"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F026", "F042", "F050"])].to_dict("records")
    write_phase_closure(args.output_root, "080", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F051 descriptor-aligned action-contract replication",
            {"novelty": 0.54, "feasibility": 0.88, "identity": 0.98, "effect": 0.82, "falsifiability": 0.98, "leakage": 0.96, "compute": 0.74},
            "Run a low-compute fresh-seed replication on the descriptor-aligned benchmark using non-exact program actions and the F042 train-only tiny-cap rule.",
        ),
        CouncilProposal(
            "Train another residual on the source/covariate-dominated active contract",
            {"novelty": 0.28, "feasibility": 0.80, "identity": 0.88, "effect": 0.26, "falsifiability": 0.56, "leakage": 0.88, "compute": 0.62},
            "Reject because F050 identified the active contract as the wrong target for action-transition JEPA progress.",
        ),
        CouncilProposal(
            "Jump straight to Tier 3 promotion",
            {"novelty": 0.20, "feasibility": 0.42, "identity": 0.62, "effect": 0.44, "falsifiability": 0.50, "leakage": 0.60, "compute": 0.48},
            "Reject because F051 is still diagnostic validation and no Tier 3 no-regression plan has passed.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "080", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f051_descriptor_aligned(args.output_root, "080", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "080", trigger, council_path, amendment_path, selected.next_action)
    return run_f051_descriptor_aligned_replication(args)


def _write_f051_report(path: Path, payload: dict[str, Any], frame: pd.DataFrame, selection_grid: pd.DataFrame, query_frame: pd.DataFrame) -> None:
    seed_tsv = frame.to_csv(sep="\t", index=False) if not frame.empty else "No seed rows.\n"
    selection_tsv = selection_grid.to_csv(sep="\t", index=False) if not selection_grid.empty else "No selection rows.\n"
    broken = query_frame[query_frame["flip_type"] == "broken_by_residual"] if not query_frame.empty else pd.DataFrame()
    broken_tsv = broken.to_csv(sep="\t", index=False) if not broken.empty else "No broken-by-residual rows.\n"
    path.write_text(
        f"""# F051 Descriptor-Aligned Replication

## Decision
`{payload['diagnostic_label']}`

## Purpose
F050 showed the active protected floor is source/covariate dominated and should not drive another residual-head search. F051 returns to the descriptor-aligned biological action-target contract approved in F026 and replicates the F042 non-exact program-action JEPA diagnostic on fresh seeds.

## Selection Rule
`{payload['selection_rule']}`

## Mean Metrics
- selected residual scale mean: `{payload['mean_selected_residual_scale']:.6f}`
- selected nonzero fraction: `{payload['selected_nonzero_fraction']:.6f}`
- heldout local floor preserved: `{payload['heldout_local_floor_preserved']}`
- active gates pass: `{payload['active_gates_pass']}`
- selected transition: `{payload['mean_selected_transition_improvement']:.6f}`
- floor transition: `{payload['mean_floor_transition_improvement']:.6f}`
- selected delta cosine: `{payload['mean_selected_delta_cosine']:.6f}`
- floor delta cosine: `{payload['mean_floor_delta_cosine']:.6f}`
- selected recall@1: `{payload['mean_selected_recall_at_1']:.6f}`
- floor recall@1: `{payload['mean_floor_recall_at_1']:.6f}`
- selected floor gap transition: `{payload['mean_selected_gap_transition']:.6f}` (min `{payload['min_selected_gap_transition']:.6f}`)
- selected floor gap delta cosine: `{payload['mean_selected_gap_delta_cosine']:.6f}` (min `{payload['min_selected_gap_delta_cosine']:.6f}`)
- selected floor gap recall: `{payload['mean_selected_gap_recall']:.6f}` (min `{payload['min_selected_gap_recall']:.6f}`)
- heldout broken rows: `{payload['broken_count']:.0f}`

## Seed Rows
```tsv
{seed_tsv}
```

## Train Selection Grid
```tsv
{selection_tsv}
```

## Held-Out Broken Rows
```tsv
{broken_tsv}
```

## Promotion Status
No model is promoted. This is a fresh-seed diagnostic validation branch for the descriptor-aligned action-target contract.
""",
        encoding="utf-8",
    )


def write_amendment_f051_descriptor_aligned(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Descriptor-Aligned Action Contract Replication

## Trigger
`{trigger}`

## Evidence
F050 showed that the active protected full-ridge floor is source/covariate dominated and is a poor identity target for a biological action-transition JEPA. Earlier F026 approved the descriptor-aligned synthetic benchmark, and F042 showed fresh-seed nonzero residual safety on that benchmark. The next step is a low-compute replication before designing another full JEPA phase.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it. No Phase 8/F051 diagnostic can promote.

## New Diagnostic Branch
`F051_DESCRIPTOR_ALIGNED_REPLICATION`

## Implementation Tasks
- Use `synth_program_aligned_genetic_lite`.
- Use non-exact program action descriptors only.
- Train the existing small real JEPA path with RNA online/context encoder, image online/context encoder, EMA target encoders, stop-gradient latent targets, query predictors, cross-modal RNA/image losses, and action-conditioned transition JEPA.
- Fit ridge floor and residual head on train rows only.
- Select residual scale using the F042 train-only tiny-cap rule.
- Score held-out rows only after train-only selection.

## Decision Use
If F051 replicates safe nonzero behavior, design the next full descriptor-aligned BioGuard-WM/JEPAction branch. If it fails, close residual/operator heads and pivot to representation or action-descriptor redesign.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def _f052_descriptor_near_tie_summary(f051_metrics: dict[str, Any], query_frame: pd.DataFrame) -> dict[str, Any]:
    if query_frame.empty:
        query_frame = pd.DataFrame(
            columns=[
                "flip_type",
                "floor_top1_correct",
                "floor_near_tie_0p02",
                "selected_near_tie_0p02",
                "floor_near_tie_0p05",
                "selected_near_tie_0p05",
                "floor_margin",
                "selected_margin",
                "margin_change_selected_minus_floor",
                "transition_gain_change_selected_minus_floor",
                "delta_cosine_change_selected_minus_floor",
                "residual_norm",
            ]
        )
    broken = query_frame[query_frame["flip_type"] == "broken_by_residual"].copy()
    floor_correct_count = float(query_frame["floor_top1_correct"].astype(bool).sum()) if "floor_top1_correct" in query_frame else 0.0
    broken_count = float(len(broken))
    row_count = float(len(query_frame))
    broken_near_tie_0p02 = (
        float((broken["floor_near_tie_0p02"].astype(bool) | broken["selected_near_tie_0p02"].astype(bool)).mean())
        if not broken.empty
        else 0.0
    )
    broken_near_tie_0p05 = (
        float((broken["floor_near_tie_0p05"].astype(bool) | broken["selected_near_tie_0p05"].astype(bool)).mean())
        if not broken.empty
        else 0.0
    )
    broken_continuous_help_fraction = (
        float(
            (
                (broken["transition_gain_change_selected_minus_floor"] > 0.0)
                & (broken["delta_cosine_change_selected_minus_floor"] > 0.0)
            ).mean()
        )
        if not broken.empty
        else 0.0
    )
    active_gates_pass = bool(f051_metrics.get("active_gates_pass", False))
    mean_delta_gap = float(f051_metrics.get("mean_selected_gap_delta_cosine", 0.0))
    mean_transition_gap = float(f051_metrics.get("mean_selected_gap_transition", 0.0))
    mean_recall_gap = float(f051_metrics.get("mean_selected_gap_recall", 0.0))
    if broken_count == 0.0 and bool(f051_metrics.get("heldout_local_floor_preserved", False)):
        decision = "F052_DESCRIPTOR_NEAR_TIE_AUDIT_NO_RETRIEVAL_BREAK"
        next_recommendation = "Descriptor-aligned residuals preserved retrieval in F051; design a Tier 1 continuation only after preregistering promotion-ineligible gates."
    elif (
        active_gates_pass
        and row_count > 0.0
        and broken_count <= max(1.0, 0.02 * row_count)
        and broken_near_tie_0p05 >= 1.0
        and broken_continuous_help_fraction >= 1.0
        and mean_delta_gap >= 0.0
    ):
        decision = "F052_DESCRIPTOR_FAILURE_IS_NEAR_TIE_RETRIEVAL_MARGIN"
        next_recommendation = "Implement a train-only retrieval-margin safety gate for the descriptor-aligned contract: residual scale must default to zero unless train-internal near-tie margin diagnostics prove no local floor flip risk."
    elif broken_count > 0.0 and broken_near_tie_0p05 >= 0.75:
        decision = "F052_DESCRIPTOR_FAILURE_MOSTLY_NEAR_TIE_BUT_NOT_SAFE"
        next_recommendation = "Keep descriptor-aligned contract active, but require stricter train-only abstention before any nonzero residual is used."
    elif broken_count > 0.0:
        decision = "F052_DESCRIPTOR_FAILURE_NOT_ONLY_NEAR_TIE"
        next_recommendation = "Cool residual heads and reopen representation/action-descriptor redesign before further transition operators."
    else:
        decision = "F052_DESCRIPTOR_NEAR_TIE_AUDIT_INCONCLUSIVE"
        next_recommendation = "Do not train larger models; first regenerate complete query-level diagnostics."
    return {
        "diagnostic_label": decision,
        "row_count": row_count,
        "floor_correct_count": floor_correct_count,
        "broken_count": broken_count,
        "broken_fraction_of_rows": broken_count / max(row_count, 1.0),
        "broken_fraction_of_floor_correct": broken_count / max(floor_correct_count, 1.0),
        "broken_near_tie_0p02_fraction": broken_near_tie_0p02,
        "broken_near_tie_0p05_fraction": broken_near_tie_0p05,
        "broken_continuous_help_fraction": broken_continuous_help_fraction,
        "broken_mean_floor_margin": float(broken["floor_margin"].mean()) if not broken.empty else 0.0,
        "broken_min_floor_margin": float(broken["floor_margin"].min()) if not broken.empty else 0.0,
        "broken_mean_selected_margin": float(broken["selected_margin"].mean()) if not broken.empty else 0.0,
        "broken_mean_margin_change": float(broken["margin_change_selected_minus_floor"].mean()) if not broken.empty else 0.0,
        "broken_mean_transition_gain_change": float(broken["transition_gain_change_selected_minus_floor"].mean()) if not broken.empty else 0.0,
        "broken_mean_delta_cosine_change": float(broken["delta_cosine_change_selected_minus_floor"].mean()) if not broken.empty else 0.0,
        "mean_selected_transition_improvement": float(f051_metrics.get("mean_selected_transition_improvement", 0.0)),
        "mean_floor_transition_improvement": float(f051_metrics.get("mean_floor_transition_improvement", 0.0)),
        "mean_selected_delta_cosine": float(f051_metrics.get("mean_selected_delta_cosine", 0.0)),
        "mean_floor_delta_cosine": float(f051_metrics.get("mean_floor_delta_cosine", 0.0)),
        "mean_selected_recall_at_1": float(f051_metrics.get("mean_selected_recall_at_1", 0.0)),
        "mean_floor_recall_at_1": float(f051_metrics.get("mean_floor_recall_at_1", 0.0)),
        "mean_selected_gap_transition": mean_transition_gap,
        "min_selected_gap_transition": float(f051_metrics.get("min_selected_gap_transition", 0.0)),
        "mean_selected_gap_delta_cosine": mean_delta_gap,
        "min_selected_gap_delta_cosine": float(f051_metrics.get("min_selected_gap_delta_cosine", 0.0)),
        "mean_selected_gap_recall": mean_recall_gap,
        "min_selected_gap_recall": float(f051_metrics.get("min_selected_gap_recall", 0.0)),
        "mean_selected_residual_scale": float(f051_metrics.get("mean_selected_residual_scale", 0.0)),
        "selected_nonzero_fraction": float(f051_metrics.get("selected_nonzero_fraction", 0.0)),
        "mean_selected_delta_rank": float(f051_metrics.get("mean_selected_delta_rank", 0.0)),
        "mean_selected_magnitude_ratio": float(f051_metrics.get("mean_selected_magnitude_ratio", 0.0)),
        "heldout_local_floor_preserved": bool(f051_metrics.get("heldout_local_floor_preserved", False)),
        "active_gates_pass": active_gates_pass,
        "next_recommendation": next_recommendation,
    }


def run_f052_descriptor_near_tie_audit(args: argparse.Namespace) -> dict[str, Any]:
    source_dir = args.output_root / "experiments/F051_descriptor_aligned_replication"
    out = args.output_root / "experiments/F052_descriptor_near_tie_audit"
    out.mkdir(parents=True, exist_ok=True)
    f051_metrics = _load_metric_json(source_dir / "metrics_eval.json")
    query_path = source_dir / "f051_query_retrieval_rows.tsv"
    seed_path = source_dir / "f051_by_seed.tsv"
    selection_path = source_dir / "f051_train_small_cap_scale_grid.tsv"
    query_frame = pd.read_csv(query_path, sep="\t") if query_path.exists() else pd.DataFrame()
    seed_frame = pd.read_csv(seed_path, sep="\t") if seed_path.exists() else pd.DataFrame()
    selection_grid = pd.read_csv(selection_path, sep="\t") if selection_path.exists() else pd.DataFrame()
    summary = _f052_descriptor_near_tie_summary(f051_metrics, query_frame)
    broken = query_frame[query_frame["flip_type"] == "broken_by_residual"].copy() if not query_frame.empty else pd.DataFrame()
    payload = {
        **summary,
        "source_experiment": "F051_descriptor_aligned_replication",
        "source_artifacts": {
            "metrics_eval": str(source_dir / "metrics_eval.json"),
            "query_rows": str(query_path),
            "seed_rows": str(seed_path),
            "selection_grid": str(selection_path),
        },
        "audit_scope": "Read-only diagnostic over F051 held-out retrieval rows; no training, no eval selection, no split changes.",
        "model_promoted": False,
        "leakage_controls": "F052 consumes only already-scored F051 artifacts and does not fit, calibrate, or select residuals on held-out rows.",
    }
    write_json(out / "metrics_eval.json", payload)
    seed_frame.to_csv(out / "f051_seed_rows_snapshot.tsv", sep="\t", index=False)
    selection_grid.to_csv(out / "f051_train_selection_snapshot.tsv", sep="\t", index=False)
    broken.to_csv(out / "f052_broken_near_tie_rows.tsv", sep="\t", index=False)
