def run_f054_descriptor_margin_rerun(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F054_descriptor_margin_rerun"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [13, 14, 15]
    benchmark = "synth_program_aligned_genetic_lite"
    gates = _active_multiseed_gates(args)
    frame, selection_grid, query_frame, trace_frame = _run_program_aligned_small_cap_validation(
        args,
        out,
        seeds=seeds,
        benchmark=benchmark,
        seed_offset=9054,
        selector=_select_scale_by_train_near_tie_small_grid,
        bundle_prefix="f054",
    )
    frame.to_csv(out / "f054_by_seed.tsv", sep="\t", index=False)
    selection_grid.to_csv(out / "f054_train_margin_scale_grid.tsv", sep="\t", index=False)
    query_frame.to_csv(out / "f054_query_retrieval_rows.tsv", sep="\t", index=False)
    trace_frame.to_csv(out / "train_trace_by_seed.tsv", sep="\t", index=False)
    summary = _summarize_small_cap_validation(frame, query_frame, gates)
    margin_diagnostics = {
        "mean_train_selected_near_tie_erosions": float(frame["train_small_cap_selected_near_tie_erosions"].mean()) if not frame.empty and "train_small_cap_selected_near_tie_erosions" in frame else 0.0,
        "mean_train_selected_near_tie_flips": float(frame["train_small_cap_selected_near_tie_flips"].mean()) if not frame.empty and "train_small_cap_selected_near_tie_flips" in frame else 0.0,
        "mean_train_selected_near_tie_count": float(frame["train_small_cap_selected_near_tie_count"].mean()) if not frame.empty and "train_small_cap_selected_near_tie_count" in frame else 0.0,
        "mean_train_selected_margin_q10_change": float(frame["train_small_cap_selected_margin_q10_change"].mean()) if not frame.empty and "train_small_cap_selected_margin_q10_change" in frame else 0.0,
        "mean_train_selected_near_tie_min_margin_change": float(frame["train_small_cap_selected_near_tie_min_margin_change"].mean()) if not frame.empty and "train_small_cap_selected_near_tie_min_margin_change" in frame else 0.0,
    }
    if summary["selected_nonzero_fraction"] > 0.0 and summary["heldout_local_floor_preserved"] and summary["active_gates_pass"]:
        decision = "F054_DESCRIPTOR_MARGIN_RERUN_SAFE_NONZERO_DIAGNOSTIC"
    elif summary["selected_nonzero_fraction"] == 0.0 and summary["heldout_local_floor_preserved"]:
        decision = "F054_DESCRIPTOR_MARGIN_RERUN_ZERO_FALLBACK"
