def continue_after_f054_to_f055(args: argparse.Namespace) -> dict[str, Any]:
    f054 = _load_metric_json(args.output_root / "experiments/F054_descriptor_margin_rerun/metrics_eval.json")
    trigger = str(f054.get("diagnostic_label", "F054_DESCRIPTOR_MARGIN_RERUN_ZERO_FALLBACK"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F053", "F054"])].to_dict("records")
    write_phase_closure(args.output_root, "084", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F055 row-wise residual abstention",
            {"novelty": 0.68, "feasibility": 0.80, "identity": 0.98, "effect": 0.78, "falsifiability": 0.98, "leakage": 0.96, "compute": 0.66},
            "Replace global residual scale with train-only row-wise abstention based on source/action/floor/head risk features.",
        ),
        CouncilProposal(
            "Relax near-tie safety thresholds",
            {"novelty": 0.30, "feasibility": 0.98, "identity": 0.94, "effect": 0.62, "falsifiability": 0.58, "leakage": 0.88, "compute": 0.98},
            "Reject because F052/F054 show near-tie margin erosion is the protected failure mode.",
        ),
        CouncilProposal(
            "Train larger descriptor-aligned JEPA",
            {"novelty": 0.62, "feasibility": 0.68, "identity": 0.92, "effect": 0.54, "falsifiability": 0.70, "leakage": 0.88, "compute": 0.34},
            "Defer because the scalar control mechanism, not representation capacity, is the current bottleneck.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "084", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f055_rowwise_abstention(args.output_root, "084", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "084", trigger, council_path, amendment_path, selected.next_action)
    return run_f055_rowwise_abstention(args)


def _write_f055_report(path: Path, payload: dict[str, Any], frame: pd.DataFrame, selection_grid: pd.DataFrame, query_frame: pd.DataFrame) -> None:
    seed_tsv = frame.to_csv(sep="\t", index=False) if not frame.empty else "No seed rows.\n"
    safe_rows = selection_grid[selection_grid["safe"]] if not selection_grid.empty else pd.DataFrame()
    safe_tsv = safe_rows.to_csv(sep="\t", index=False) if not safe_rows.empty else "No train-safe row-wise candidates.\n"
    broken = query_frame[query_frame["flip_type"] == "broken_by_residual"] if not query_frame.empty else pd.DataFrame()
    broken_tsv = broken.to_csv(sep="\t", index=False) if not broken.empty else "No broken-by-residual rows.\n"
    path.write_text(
        f"""# F055 Row-Wise Residual Abstention

## Decision
`{payload['diagnostic_label']}`

## Purpose
F054 showed that a single residual scale is too blunt: every nonzero scalar scale improved train transition/delta metrics but eroded near-tie margins. F055 tests whether a train-only row-wise abstention rule can preserve fragile rows while allowing residuals on safer rows.

## Selection Rule
`{payload['selection_rule']}`

## Mean Metrics
- row-wise base scale mean: `{payload['mean_rowwise_selected_base_scale']:.6f}`
- row-wise active fraction mean: `{payload['mean_rowwise_active_fraction']:.6f}`
- row-wise effective scale mean: `{payload['mean_rowwise_effective_scale']:.6f}`
- heldout local floor preserved: `{payload['heldout_local_floor_preserved']}`
- active gates pass: `{payload['active_gates_pass']}`
- selected transition: `{payload['mean_selected_transition_improvement']:.6f}`
- floor transition: `{payload['mean_floor_transition_improvement']:.6f}`
- selected delta cosine: `{payload['mean_selected_delta_cosine']:.6f}`
- floor delta cosine: `{payload['mean_floor_delta_cosine']:.6f}`
- selected recall@1: `{payload['mean_selected_recall_at_1']:.6f}`
- floor recall@1: `{payload['mean_floor_recall_at_1']:.6f}`
- selected floor gap transition: `{payload['mean_selected_gap_transition']:.6f}` (min `{payload['min_selected_gap_transition']:.6f}`)
- selected floor gap delta cosine: `{payload['mean_selected_gap_delta_cosine']:.6f}` (min `{payload['min_selected_gap_delta_cosine']:.6f}`)
- selected floor gap recall: `{payload['mean_selected_gap_recall']:.6f}` (min `{payload['min_selected_gap_recall']:.6f}`)
- heldout broken rows: `{payload['broken_count']:.0f}`

## Seed Rows
```tsv
{seed_tsv}
```

## Train-Safe Row-Wise Candidates
```tsv
{safe_tsv}
```

## Held-Out Broken Rows
```tsv
{broken_tsv}
```

## Promotion Status
No model is promoted. F055 is a low-compute diagnostic validation branch.
""",
        encoding="utf-8",
    )


def write_amendment_f055_rowwise_abstention(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Row-Wise Residual Abstention

## Trigger
`{trigger}`

## Evidence
F054 selected zero residual because every nonzero global scale caused train near-tie margin erosion. The residual direction still improved train transition and delta metrics, so the next mechanism should be local abstention rather than another scalar scale.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it. F055 is diagnostic validation only and cannot promote.

## New Diagnostic Branch
`F055_ROWWISE_ABSTENTION`

## Implementation Tasks
- Use fresh seeds 16, 17, and 18.
- Use `synth_program_aligned_genetic_lite` with non-exact program action descriptors only.
- Train the same low-compute real ProgramBootstrapJEPA path.
- Fit ridge floor and residual head on train rows only.
- Build train-only unsafe-margin labels from train retrieval/margin diagnostics.
- Use only inference-available source/action/floor/head-derived features for row-wise abstention.
- Score held-out rows only after the train-only rule is fixed.
- Do not promote.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def _run_rowwise_abstention_validation(
    args: argparse.Namespace,
    out: Path,
    *,
    seeds: list[int],
    benchmark: str,
    base_seed_offset: int,
    head_seed_offset: int,
    bundle_prefix: str,
    delta_transform=None,
) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    rows: list[dict[str, Any]] = []
    selection_rows: list[dict[str, Any]] = []
    query_frames: list[pd.DataFrame] = []
    trace_rows: list[dict[str, Any]] = []
    for seed in seeds:
        dataset = generate_synthetic_biology_lite(synthetic_lite_config(benchmark, seed=seed))
        pca_z = _train_only_pca_embeddings(dataset.expression_values, dataset.metadata, dim=24)
        train_table = _program_jepa_condition_table(dataset, pca_z, split="train")
        eval_table = _program_jepa_condition_table(dataset, pca_z, split=args.eval_split)
        config = ProgramBootstrapJEPAConfig(
            genes=dataset.config.genes,
            image_dim=int(dataset.images.reshape(dataset.images.shape[0], -1).shape[1]),
            action_dim=int(train_table["action"].shape[1]),
            z_dim=24,
            hidden_dim=96,
            pca_anchor_weight=0.15,
            transition_weight=1.0,
            cross_modal_weight=0.75,
            action_negative_weight=0.15,
            delta_direction_weight=0.8,
            source_improvement_weight=0.5,
            variance_weight=0.05,
        )
        base_model, trace = _train_program_bootstrap_jepa(train_table, config, seed=seed + base_seed_offset, device=args.device)
        train_encoded = _encode_program_jepa_table(base_model, train_table, device=args.device)
        eval_encoded = _encode_program_jepa_table(base_model, eval_table, device=args.device)
        train_bundle = LatentOperatorBundle(
            name=f"{bundle_prefix}_seed{seed}_train",
            arrays={
                "source_z_bio_teacher": train_encoded["source"],
                "target_z_bio_teacher": train_encoded["target"],
                "action_descriptor": train_table["action"].astype(np.float64),
            },
            metadata=train_table["metadata"],
        )
        eval_bundle = LatentOperatorBundle(
            name=f"{bundle_prefix}_seed{seed}_eval",
            arrays={
                "source_z_bio_teacher": eval_encoded["source"],
                "target_z_bio_teacher": eval_encoded["target"],
                "action_descriptor": eval_table["action"].astype(np.float64),
            },
            metadata=eval_table["metadata"],
        )
        ridge_fit = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
        head, head_trace = _train_floor_initialized_transition_head(train_bundle, ridge_fit, seed=seed + head_seed_offset, device=args.device)
        rule, selection_metrics, selection_frame = _select_rowwise_abstention_rule(
            head,
            ridge_fit,
            train_bundle,
            cap=0.05,
            device=args.device,
            delta_transform=delta_transform,
        )
        eval_payload, query_frame = _evaluate_rowwise_abstention(
            rule,
            head,
            ridge_fit,
            eval_bundle,
            eval_encoded,
            eval_table,
            device=args.device,
            delta_transform=delta_transform,
        )
        query_summary = _summarize_retrieval_failure_rows(query_frame)
        eval_payload.update({f"train_rowwise_{key}": value for key, value in selection_metrics.items()})
        eval_payload.update({f"retrieval_{key}": value for key, value in query_summary.items()})
        eval_payload["selected_residual_scale"] = float(eval_payload["rowwise_effective_scale"])
        rows.append({"seed": seed, **eval_payload})
        selection_frame = selection_frame.copy()
        selection_frame.insert(0, "seed", seed)
        selection_rows.extend(selection_frame.to_dict("records"))
        query_frame = query_frame.copy()
        query_frame["seed"] = seed
        query_frames.append(query_frame)
        seed_out = out / f"seed{seed}"
        seed_out.mkdir(parents=True, exist_ok=True)
        selection_frame.to_csv(seed_out / "train_rowwise_abstention_grid.tsv", sep="\t", index=False)
        query_frame.to_csv(seed_out / "query_retrieval_rows.tsv", sep="\t", index=False)
        trace_row = {"seed": seed, **{f"base_{key}": value for key, value in trace.items()}, **{f"head_{key}": value for key, value in head_trace.items()}}
        trace_rows.append(trace_row)
        write_json(seed_out / "metrics_eval.json", {"seed": seed, **eval_payload})
        write_json(seed_out / "train_trace_summary.json", trace_row)
    frame = pd.DataFrame(rows)
    selection_grid = pd.DataFrame(selection_rows)
    query_frame_all = pd.concat(query_frames, ignore_index=True) if query_frames else pd.DataFrame()
    trace_frame = pd.DataFrame(trace_rows)
    return frame, selection_grid, query_frame_all, trace_frame


def _summarize_rowwise_abstention(frame: pd.DataFrame, query_frame: pd.DataFrame, gates: dict[str, float]) -> dict[str, Any]:
    summary = _summarize_small_cap_validation(frame, query_frame, gates)
    summary.update(
        {
            "mean_rowwise_active_fraction": float(frame["rowwise_active_fraction"].mean()) if not frame.empty else 0.0,
            "mean_rowwise_selected_base_scale": float(frame["rowwise_selected_base_scale"].mean()) if not frame.empty else 0.0,
            "mean_rowwise_effective_scale": float(frame["rowwise_effective_scale"].mean()) if not frame.empty else 0.0,
            "mean_train_rowwise_active_fraction": float(frame["train_rowwise_selected_active_fraction"].mean()) if not frame.empty else 0.0,
            "mean_train_rowwise_unsafe_count": float(frame["train_rowwise_selected_unsafe_count"].mean()) if not frame.empty else 0.0,
        }
    )
    return summary


def run_f056_rowwise_abstention_replication(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F056_rowwise_abstention_replication"
    out.mkdir(parents=True, exist_ok=True)
    seeds = [19, 20, 21]
    benchmark = "synth_program_aligned_genetic_lite"
    gates = _active_multiseed_gates(args)
    frame, selection_grid, query_frame, trace_frame = _run_rowwise_abstention_validation(
        args,
        out,
        seeds=seeds,
        benchmark=benchmark,
        base_seed_offset=9056,
        head_seed_offset=12056,
        bundle_prefix="f056",
    )
    frame.to_csv(out / "f056_by_seed.tsv", sep="\t", index=False)
    selection_grid.to_csv(out / "f056_train_rowwise_abstention_grid.tsv", sep="\t", index=False)
    query_frame.to_csv(out / "f056_query_retrieval_rows.tsv", sep="\t", index=False)
    trace_frame.to_csv(out / "train_trace_by_seed.tsv", sep="\t", index=False)
    summary = _summarize_rowwise_abstention(frame, query_frame, gates)
    if summary["selected_nonzero_fraction"] > 0.0 and summary["heldout_local_floor_preserved"] and summary["active_gates_pass"]:
        decision = "F056_ROWWISE_ABSTENTION_REPLICATES_SAFE_NONZERO"
    elif summary["selected_nonzero_fraction"] == 0.0 and summary["heldout_local_floor_preserved"]:
        decision = "F056_ROWWISE_ABSTENTION_REPLICATION_ZERO_FALLBACK"
    elif summary["selected_nonzero_fraction"] > 0.0:
        decision = "F056_ROWWISE_ABSTENTION_REPLICATION_HELDOUT_BELOW_FLOOR"
    else:
        decision = "F056_ROWWISE_ABSTENTION_REPLICATION_FAIL"
    payload = {
        "diagnostic_label": decision,
        "benchmark": benchmark,
        "fresh_seed_set": seeds,
        "gates": gates,
        "selection_rule": "Independent fresh-seed replication of F055 train-only row-wise risk abstention.",
        **summary,
        "seed_rows": frame.to_dict("records"),
        "model_promoted": False,
        "identity_controls": {
            "online_context_encoders": True,
            "ema_target_encoders": True,
            "stop_gradient_latent_targets": True,
            "target_query_predictors": True,
            "cross_modal_rna_image_jepa": True,
            "action_conditioned_transition_jepa": True,
            "non_exact_program_actions_only": True,
            "exact_perturbation_id_input": False,
        },
        "leakage_controls": "Same as F055: row-wise abstention labels use train retrieval/margin diagnostics only; held-out rows are scoring-only.",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f056_report(out / "F056_ROWWISE_ABSTENTION_REPLICATION.md", payload, frame, selection_grid, query_frame)
    append_journal(
        args.output_root,
        "F056_ROWWISE_ABSTENTION_REPLICATION",
        "Independent row-wise residual abstention replication",
        f"Decision={decision}; active fraction={summary['mean_rowwise_active_fraction']:.3f}; transition gap={summary['mean_selected_gap_transition']:.6f}; heldout preserved={summary['heldout_local_floor_preserved']}.",
    )
    return {
        "experiment_id": "F056",
        "phase": "PostPhase8Council",
        "family": "Descriptor-aligned action contract",
        "tier": "DiagnosticValidation",
        "seed": "19,20,21",
        "dataset": benchmark,
        "eval_split": args.eval_split,
        "mode": "rowwise_abstention_replication",
        "status_label": decision,
        "transition_improvement": f"{summary['mean_selected_transition_improvement']:.6f}",
        "delta_cosine": f"{summary['mean_selected_delta_cosine']:.6f}",
        "recall_at_1": f"{summary['mean_selected_recall_at_1']:.6f}",
        "median_rank": f"{summary['selected_median_rank']:.6f}",
        "delta_rank": f"{summary['mean_selected_delta_rank']:.6f}",
        "magnitude_ratio": f"{summary['mean_selected_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{summary['mean_selected_delta_rank']:.6f}",
        "effective_rank_target": f"{summary['mean_floor_delta_cosine']:.6f}",
        "collapse_flag": str(summary["mean_selected_delta_rank"] < 2.0),
        "leakage_flag": str(summary["max_leakage_flag"] > 0.0),
        "floor_gap_transition": f"{summary['mean_selected_gap_transition']:.6f}",
        "floor_gap_recall": f"{summary['mean_selected_gap_recall']:.6f}",
        "floor_gap_delta_cosine": f"{summary['mean_selected_gap_delta_cosine']:.6f}",
        "selected_residual_scale": f"{summary['mean_rowwise_effective_scale']:.6f}",
        "calibration_lcb_transition_gap": f"{summary['min_selected_gap_transition']:.6f}",
        "calibration_lcb_recall_gap": f"{summary['min_selected_gap_recall']:.6f}",
        "action_negative_gap": f"{summary['mean_rowwise_active_fraction']:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": str(summary["max_identity_violation"] == 0.0 and summary["max_floor_init_error"] <= 1.0e-5),
        "notes": "Independent fresh-seed row-wise residual abstention replication; no model promotion.",
        "artifact_dir": str(out),
    }


