def run_f057_rowwise_synthesis(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F057_rowwise_synthesis"
    out.mkdir(parents=True, exist_ok=True)
    f055 = _load_metric_json(args.output_root / "experiments/F055_rowwise_abstention/metrics_eval.json")
    f056 = _load_metric_json(args.output_root / "experiments/F056_rowwise_abstention_replication/metrics_eval.json")
    frames: list[pd.DataFrame] = []
    for name, rel in [
        ("F055", "F055_rowwise_abstention/f055_by_seed.tsv"),
        ("F056", "F056_rowwise_abstention_replication/f056_by_seed.tsv"),
    ]:
        path = args.output_root / "experiments" / rel
        if path.exists():
            frame = pd.read_csv(path, sep="\t")
            frame.insert(0, "source_experiment", name)
            frames.append(frame)
    combined = pd.concat(frames, ignore_index=True) if frames else pd.DataFrame()
    combined.to_csv(out / "f057_combined_seed_rows.tsv", sep="\t", index=False)
    if combined.empty:
        decision = "F057_ROWWISE_SYNTHESIS_BLOCKED_MISSING_ROWS"
        summary = {
            "seed_count": 0,
            "mean_selected_transition_improvement": 0.0,
            "mean_floor_transition_improvement": 0.0,
            "mean_selected_delta_cosine": 0.0,
            "mean_floor_delta_cosine": 0.0,
            "mean_selected_recall_at_1": 0.0,
            "mean_floor_recall_at_1": 0.0,
            "mean_selected_gap_transition": 0.0,
            "min_selected_gap_transition": 0.0,
            "mean_selected_gap_delta_cosine": 0.0,
            "min_selected_gap_delta_cosine": 0.0,
            "mean_selected_gap_recall": 0.0,
            "min_selected_gap_recall": 0.0,
            "mean_rowwise_active_fraction": 0.0,
            "mean_rowwise_effective_scale": 0.0,
            "total_broken_count": 0.0,
            "heldout_local_floor_preserved": False,
            "active_gates_pass": False,
        }
    else:
        summary = {
            "seed_count": int(combined["seed"].nunique()),
            "mean_selected_transition_improvement": float(combined["selected_transition_improvement"].mean()),
            "std_selected_transition_improvement": float(combined["selected_transition_improvement"].std(ddof=0)),
            "mean_floor_transition_improvement": float(combined["floor_transition_improvement"].mean()),
            "mean_selected_delta_cosine": float(combined["selected_delta_cosine"].mean()),
            "std_selected_delta_cosine": float(combined["selected_delta_cosine"].std(ddof=0)),
            "mean_floor_delta_cosine": float(combined["floor_delta_cosine"].mean()),
            "mean_selected_recall_at_1": float(combined["selected_recall_at_1"].mean()),
            "mean_floor_recall_at_1": float(combined["floor_recall_at_1"].mean()),
            "mean_selected_gap_transition": float(combined["selected_gap_transition"].mean()),
            "min_selected_gap_transition": float(combined["selected_gap_transition"].min()),
            "mean_selected_gap_delta_cosine": float(combined["selected_gap_delta_cosine"].mean()),
            "min_selected_gap_delta_cosine": float(combined["selected_gap_delta_cosine"].min()),
            "mean_selected_gap_recall": float(combined["selected_gap_recall"].mean()),
            "min_selected_gap_recall": float(combined["selected_gap_recall"].min()),
            "mean_rowwise_active_fraction": float(combined["rowwise_active_fraction"].mean()),
            "mean_rowwise_effective_scale": float(combined["rowwise_effective_scale"].mean()),
            "total_broken_count": float(combined["retrieval_broken_count"].sum()),
            "heldout_local_floor_preserved": bool(
                (combined["selected_gap_transition"] >= -0.001).all()
                and (combined["selected_gap_delta_cosine"] >= -0.001).all()
                and (combined["selected_gap_recall"] >= -0.001).all()
                and (combined["retrieval_broken_count"] <= 0.0).all()
            ),
            "active_gates_pass": bool(
                f055.get("active_gates_pass", False)
                and f056.get("active_gates_pass", False)
            ),
        }
        if (
            summary["seed_count"] >= 6
            and summary["heldout_local_floor_preserved"]
            and summary["active_gates_pass"]
            and summary["mean_selected_gap_transition"] > 0.0
            and summary["mean_selected_gap_delta_cosine"] > 0.0
            and summary["min_selected_gap_recall"] >= 0.0
            and summary["total_broken_count"] == 0.0
        ):
            decision = "F057_ROWWISE_ABSTENTION_READY_FOR_TIER2_DESIGN"
        elif summary["heldout_local_floor_preserved"]:
            decision = "F057_ROWWISE_ABSTENTION_SAFE_BUT_WEAK"
        else:
            decision = "F057_ROWWISE_ABSTENTION_SYNTHESIS_FAILS_FLOOR_PRESERVATION"
    payload = {
        "diagnostic_label": decision,
        "source_experiments": ["F055", "F056"],
        "benchmark": "synth_program_aligned_genetic_lite",
        **summary,
        "model_promoted": False,
        "next_recommendation": "Design a promotion-ineligible Tier 2 amendment for row-wise abstention with more seeds, stricter artifact contracts, and eventually an external/Norman diagnostic only after synthetic gates remain clean.",
        "leakage_controls": "F057 is read-only synthesis over F055/F056 train-only-selected held-out scoring rows; no new model fitting or scale selection.",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f057_report(out / "F057_ROWWISE_SYNTHESIS.md", payload, combined)
    append_journal(
        args.output_root,
        "F057_ROWWISE_SYNTHESIS",
        "Six-seed row-wise abstention synthesis",
        f"Decision={decision}; seeds={summary['seed_count']}; transition gap={summary['mean_selected_gap_transition']:.6f}; delta gap={summary['mean_selected_gap_delta_cosine']:.6f}; broken={summary['total_broken_count']:.0f}.",
    )
    return {
        "experiment_id": "F057",
        "phase": "PostPhase8Council",
        "family": "Descriptor-aligned action contract",
        "tier": "Synthesis",
        "seed": "16,17,18,19,20,21",
        "dataset": "synth_program_aligned_genetic_lite",
        "eval_split": args.eval_split,
        "mode": "rowwise_synthesis",
        "status_label": decision,
        "transition_improvement": f"{summary['mean_selected_transition_improvement']:.6f}",
        "delta_cosine": f"{summary['mean_selected_delta_cosine']:.6f}",
        "recall_at_1": f"{summary['mean_selected_recall_at_1']:.6f}",
        "median_rank": "1.000000",
        "delta_rank": "0.000000",
        "magnitude_ratio": "0.000000",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": "0.000000",
        "effective_rank_target": f"{summary['mean_floor_delta_cosine']:.6f}",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": f"{summary['mean_selected_gap_transition']:.6f}",
        "floor_gap_recall": f"{summary['mean_selected_gap_recall']:.6f}",
        "floor_gap_delta_cosine": f"{summary['mean_selected_gap_delta_cosine']:.6f}",
        "selected_residual_scale": f"{summary['mean_rowwise_effective_scale']:.6f}",
        "calibration_lcb_transition_gap": f"{summary['min_selected_gap_transition']:.6f}",
        "calibration_lcb_recall_gap": f"{summary['min_selected_gap_recall']:.6f}",
        "action_negative_gap": f"{summary['mean_rowwise_active_fraction']:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Read-only six-seed row-wise abstention synthesis; no model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f056_to_f057(args: argparse.Namespace) -> dict[str, Any]:
    f056 = _load_metric_json(args.output_root / "experiments/F056_rowwise_abstention_replication/metrics_eval.json")
    trigger = str(f056.get("diagnostic_label", "F056_ROWWISE_ABSTENTION_REPLICATES_SAFE_NONZERO"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F055", "F056"])].to_dict("records")
    write_phase_closure(args.output_root, "086", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F057 six-seed row-wise synthesis",
            {"novelty": 0.36, "feasibility": 1.00, "identity": 1.00, "effect": 0.86, "falsifiability": 0.98, "leakage": 1.00, "compute": 1.00},
            "Aggregate F055/F056 into a read-only six-seed synthesis before drafting a Tier 2 design.",
        ),
        CouncilProposal(
            "Promote row-wise abstention immediately",
            {"novelty": 0.20, "feasibility": 0.92, "identity": 0.44, "effect": 0.78, "falsifiability": 0.30, "leakage": 0.82, "compute": 1.00},
            "Reject because only Tier 3 can promote and this is still synthetic diagnostic evidence.",
        ),
        CouncilProposal(
            "Skip synthesis and train a larger predictor",
            {"novelty": 0.68, "feasibility": 0.62, "identity": 0.90, "effect": 0.64, "falsifiability": 0.72, "leakage": 0.88, "compute": 0.34},
            "Defer until the current evidence is summarized and converted into exact next gates.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "086", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f057_rowwise_synthesis(args.output_root, "086", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "086", trigger, council_path, amendment_path, selected.next_action)
    return run_f057_rowwise_synthesis(args)


