def continue_after_f058_to_f059(args: argparse.Namespace) -> dict[str, Any]:
    f058 = _load_metric_json(args.output_root / "experiments/F058_rowwise_tier2/metrics_eval.json")
    trigger = str(f058.get("diagnostic_label", "F058_ROWWISE_TIER2_SAFE_BUT_WEAK"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F057", "F058"])].to_dict("records")
    write_phase_closure(args.output_root, "088", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F059 row-wise transition stability audit",
            {"novelty": 0.30, "feasibility": 1.00, "identity": 1.00, "effect": 0.78, "falsifiability": 1.00, "leakage": 1.00, "compute": 1.00},
            "Read F058 seed rows and isolate whether the Tier 2 miss is retrieval failure, delta failure, or transition-source cosine instability.",
        ),
        CouncilProposal(
            "Immediately add another residual predictor",
            {"novelty": 0.72, "feasibility": 0.54, "identity": 0.88, "effect": 0.58, "falsifiability": 0.70, "leakage": 0.86, "compute": 0.32},
            "Reject until the F058 weak-but-safe failure is localized; larger predictors risk increasing variance.",
        ),
        CouncilProposal(
            "Promote row-wise abstention despite weak Tier 2",
            {"novelty": 0.18, "feasibility": 0.92, "identity": 0.36, "effect": 0.30, "falsifiability": 0.28, "leakage": 0.80, "compute": 1.00},
            "Reject because F058 did not pass the registered Tier 2 stability gates and Tier 2 cannot promote.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "088", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f059_rowwise_stability_audit(args.output_root, "088", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "088", trigger, council_path, amendment_path, selected.next_action)
    return run_f059_rowwise_stability_audit(args)


