def _write_f060_report(path: Path, payload: dict[str, Any], frame: pd.DataFrame, selection_grid: pd.DataFrame, query_frame: pd.DataFrame) -> None:
    seed_tsv = frame.to_csv(sep="\t", index=False) if not frame.empty else "No seed rows.\n"
    safe_rows = selection_grid[selection_grid["safe"]] if not selection_grid.empty else pd.DataFrame()
    safe_tsv = safe_rows.to_csv(sep="\t", index=False) if not safe_rows.empty else "No train-safe projected candidates.\n"
    broken = query_frame[query_frame["flip_type"] == "broken_by_residual"] if not query_frame.empty else pd.DataFrame()
    broken_tsv = broken.to_csv(sep="\t", index=False) if not broken.empty else "No broken-by-residual rows.\n"
    path.write_text(
        f"""# F060 Floor-Direction-Projected Row-Wise Residual

## Decision
`{payload['diagnostic_label']}`

## Purpose
F059 showed that row-wise residuals preserve retrieval and improve delta metrics, but transition-source cosine improvement is unstable. F060 tests a small geometry constraint: project the learned residual onto the positive ridge floor-delta direction before applying the train-only row-wise abstention rule.

## Projection
{payload['projection']}

## Mean Metrics
- selected nonzero fraction: `{payload['selected_nonzero_fraction']:.6f}`
- row-wise active fraction mean: `{payload['mean_rowwise_active_fraction']:.6f}`
- row-wise effective scale mean: `{payload['mean_rowwise_effective_scale']:.6f}`
- heldout local floor preserved: `{payload['heldout_local_floor_preserved']}`
- active gates pass: `{payload['active_gates_pass']}`
- selected transition: `{payload['mean_selected_transition_improvement']:.6f}`
- floor transition: `{payload['mean_floor_transition_improvement']:.6f}`
- selected delta cosine: `{payload['mean_selected_delta_cosine']:.6f}`
- floor delta cosine: `{payload['mean_floor_delta_cosine']:.6f}`
- selected recall@1: `{payload['mean_selected_recall_at_1']:.6f}`
- floor recall@1: `{payload['mean_floor_recall_at_1']:.6f}`
- selected floor gap transition: `{payload['mean_selected_gap_transition']:.6f}` (min `{payload['min_selected_gap_transition']:.6f}`, std `{payload['std_selected_gap_transition']:.6f}`)
- selected floor gap delta cosine: `{payload['mean_selected_gap_delta_cosine']:.6f}` (min `{payload['min_selected_gap_delta_cosine']:.6f}`, std `{payload['std_selected_gap_delta_cosine']:.6f}`)
- selected floor gap recall: `{payload['mean_selected_gap_recall']:.6f}` (min `{payload['min_selected_gap_recall']:.6f}`, std `{payload['std_selected_gap_recall']:.6f}`)
- negative transition seeds: `{payload['negative_transition_seed_count']:.0f}`
- heldout broken rows: `{payload['broken_count']:.0f}`

## Seed Rows
```tsv
{seed_tsv}
```

## Train-Safe Projected Candidates
```tsv
{safe_tsv}
```

## Held-Out Broken Rows
```tsv
{broken_tsv}
```

## Promotion Status
No model is promoted. F060 is a low-compute diagnostic validation only.
""",
        encoding="utf-8",
    )


def write_amendment_f060_floor_direction_projection(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Floor-Direction-Projected Row-Wise Residual

## Trigger
`{trigger}`

## Evidence
F059 localized F058's Tier 2 miss to transition-source cosine generalization noise. Delta cosine was positive on every seed, recall was preserved, and no retrieval rows broke, but train transition gains were anti-correlated with held-out transition gaps. A train transition gate alone is therefore not trustworthy.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it. F060 is diagnostic validation only and cannot promote.

## New Diagnostic Branch
`F060_FLOOR_DIRECTION_PROJECTION`

## Implementation Tasks
- Use fresh seeds 28, 29, and 30.
- Train the same low-compute descriptor-aligned ProgramBootstrapJEPA path.
- Fit ridge floor and residual head on train rows only.
- Project the residual onto the positive ridge floor-delta direction before train-only row-wise abstention.
- Score held-out rows only after train-only rule selection.
- Do not promote.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def run_f061_projection_collapse_audit(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F061_projection_collapse_audit"
    out.mkdir(parents=True, exist_ok=True)
    f058 = _load_metric_json(args.output_root / "experiments/F058_rowwise_tier2/metrics_eval.json")
    f059 = _load_metric_json(args.output_root / "experiments/F059_rowwise_stability_audit/metrics_eval.json")
    f060 = _load_metric_json(args.output_root / "experiments/F060_floor_direction_projection/metrics_eval.json")
    summary = {
        "f058_transition_gap": float(f058.get("mean_selected_gap_transition", 0.0)),
        "f058_min_transition_gap": float(f058.get("min_selected_gap_transition", 0.0)),
        "f058_delta_gap": float(f058.get("mean_selected_gap_delta_cosine", 0.0)),
        "f058_broken_count": float(f058.get("broken_count", 0.0)),
        "f060_transition_gap": float(f060.get("mean_selected_gap_transition", 0.0)),
        "f060_min_transition_gap": float(f060.get("min_selected_gap_transition", 0.0)),
        "f060_delta_gap": float(f060.get("mean_selected_gap_delta_cosine", 0.0)),
        "f060_broken_count": float(f060.get("broken_count", 0.0)),
        "f060_negative_transition_seed_count": float(f060.get("negative_transition_seed_count", 0.0)),
        "f059_train_heldout_transition_gap_corr": float(f059.get("train_heldout_transition_gap_corr", 0.0)),
        "f059_train_heldout_delta_gap_corr": float(f059.get("train_heldout_delta_gap_corr", 0.0)),
    }
    if (
        summary["f060_delta_gap"] <= 1.0e-12
        and summary["f060_negative_transition_seed_count"] > 0.0
        and summary["f058_delta_gap"] > 0.0
    ):
        decision = "F061_PROJECTION_KILLS_DELTA_WITHOUT_STABILIZING_TRANSITION"
    elif summary["f060_min_transition_gap"] >= 0.0 and summary["f060_delta_gap"] > 0.0:
        decision = "F061_PROJECTION_RETAINS_SIGNAL_READY_FOR_REPLICATION"
    else:
        decision = "F061_PROJECTION_AUDIT_AMBIGUOUS"
    payload = {
        "diagnostic_label": decision,
        **summary,
        "model_promoted": False,
        "interpretation": (
            "Pure positive floor-direction projection is too restrictive: it removes the delta-cosine improvement that "
            "made row-wise abstention promising, while still failing to give a nonnegative transition gap on every seed."
        ),
        "next_recommendation": (
            "Do not continue pure floor-direction projection. The next candidate should either run an oracle diagnostic "
            "over a residual cone between unprojected and projected residuals, or pivot back to representation/data "
            "contract work if the oracle cone lacks capacity."
        ),
        "leakage_controls": "F061 reads only prior metric JSON artifacts and performs no fitting, selection, or held-out target reuse.",
    }
    write_json(out / "metrics_eval.json", payload)
    _write_f061_report(out / "F061_PROJECTION_COLLAPSE_AUDIT.md", payload)
    append_journal(
        args.output_root,
        "F061_PROJECTION_COLLAPSE_AUDIT",
        "Read-only floor-direction projection collapse audit",
        f"Decision={decision}; F060 transition gap={summary['f060_transition_gap']:.6f}; F060 delta gap={summary['f060_delta_gap']:.6f}.",
    )
    return {
        "experiment_id": "F061",
        "phase": "PostPhase8Council",
        "family": "Descriptor-aligned action contract",
        "tier": "Diagnostic",
        "seed": "22,23,24,25,26,27,28,29,30",
        "dataset": "synth_program_aligned_genetic_lite",
        "eval_split": args.eval_split,
        "mode": "projection_collapse_audit",
        "status_label": decision,
        "transition_improvement": f"{summary['f060_transition_gap']:.6f}",
        "delta_cosine": f"{summary['f060_delta_gap']:.6f}",
        "recall_at_1": "0.000000",
        "median_rank": "0.000000",
        "delta_rank": "0.000000",
        "magnitude_ratio": "0.000000",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": "0.000000",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": f"{summary['f060_transition_gap']:.6f}",
        "floor_gap_recall": "0.000000",
        "floor_gap_delta_cosine": f"{summary['f060_delta_gap']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{summary['f060_min_transition_gap']:.6f}",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": f"{summary['f060_negative_transition_seed_count']:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Read-only projection-collapse audit; no model promotion.",
        "artifact_dir": str(out),
    }


