def _write_f066_report(path: Path, payload: dict[str, Any], seed_frame: pd.DataFrame, direction_summary: pd.DataFrame, direction_frame: pd.DataFrame) -> None:
    seed_tsv = seed_frame.to_csv(sep="\t", index=False) if not seed_frame.empty else "No seed rows.\n"
