def _f067_decision_from_summary(summary: dict[str, Any]) -> str:
    if (
        float(summary.get("oracle_capacity_seen", 0.0)) > 0.0
        and float(summary.get("train_only_below_floor_count", 0.0)) >= 2.0
        and float(summary.get("calibration_mismatch_count", 0.0)) >= 2.0
    ):
        return "F067_CLOSE_RESIDUAL_SELECTOR_FAMILY_PIVOT_TO_DATA_CONTRACT"
    if float(summary.get("safe_nonzero_train_only_count", 0.0)) > 0.0 and float(summary.get("tier2_pass_count", 0.0)) == 0.0:
        return "F067_RESIDUAL_SELECTOR_SAFE_BUT_TOO_WEAK_FOR_PROMOTION"
    return "F067_RESIDUAL_SELECTOR_CLOSURE_INCONCLUSIVE"


def run_f067_residual_selector_closure(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F067_residual_selector_closure"
    out.mkdir(parents=True, exist_ok=True)
    results_path = args.output_root / "results.tsv"
    results = pd.read_csv(results_path, sep="\t")
    residual_ids = [f"F{idx:03d}" for idx in range(55, 67)]
    frame = results[results["experiment_id"].astype(str).isin(residual_ids)].copy()
    frame.to_csv(out / "f067_residual_selector_rows.tsv", sep="\t", index=False)
    labels = frame["status_label"].astype(str).tolist() if not frame.empty else []
    floor_gaps = pd.to_numeric(frame["floor_gap_transition"], errors="coerce").fillna(0.0) if not frame.empty else pd.Series(dtype=float)
    summary = {
        "source_experiments": residual_ids,
        "row_count": int(frame.shape[0]),
        "oracle_capacity_seen": float(any("ORACLE_CONE_CAPACITY" in label or "ORACLE_SAFE" in label for label in labels)),
        "safe_nonzero_train_only_count": float(sum("SAFE_NONZERO" in label or "PASS_DIAGNOSTIC" in label for label in labels)),
        "tier2_pass_count": float(sum("TIER2_PASS" in label for label in labels)),
        "below_floor_count": float(sum("BELOW_FLOOR" in label for label in labels)),
        "train_only_below_floor_count": float(
            sum(
                ("BELOW_FLOOR" in label)
                and ("ORACLE" not in label)
                and ("F063" in str(row["experiment_id"]) or "F065" in str(row["experiment_id"]))
                for _, row in frame.iterrows()
                for label in [str(row["status_label"])]
            )
        ),
        "calibration_mismatch_count": float(sum("MISMATCH" in label or "OPTIMISTIC" in label or "GENERALIZATION_NOISE" in label for label in labels)),
        "mean_floor_gap_transition": float(floor_gaps.mean()) if not floor_gaps.empty else 0.0,
        "min_floor_gap_transition": float(floor_gaps.min()) if not floor_gaps.empty else 0.0,
        "max_floor_gap_transition": float(floor_gaps.max()) if not floor_gaps.empty else 0.0,
        "latest_status": labels[-1] if labels else "",
        "model_promoted": False,
        "protected_model_of_record": "rank-3 train-split-only PLS raw-linear readout",
        "protected_transition_floor": "full train-only action ridge floor for residual/operator candidates",
    }
    summary["diagnostic_label"] = _f067_decision_from_summary(summary)
    write_json(out / "metrics_eval.json", summary)
    _write_f067_report(out / "F067_RESIDUAL_SELECTOR_CLOSURE.md", summary, frame)
    append_journal(
        args.output_root,
        "F067_RESIDUAL_SELECTOR_CLOSURE",
        "Residual-selector family closure synthesis",
        (
            f"Decision={summary['diagnostic_label']}; oracle_capacity={summary['oracle_capacity_seen']}; "
            f"train-only below-floor count={summary['train_only_below_floor_count']}; "
            f"calibration mismatch count={summary['calibration_mismatch_count']}."
        ),
    )
    latest = frame.iloc[-1].to_dict() if not frame.empty else {}
    return {
        "experiment_id": "F067",
        "phase": "PostPhase8Council",
        "family": "Descriptor-aligned action contract",
        "tier": "Synthesis",
        "seed": "16-36",
        "dataset": "synth_program_aligned_genetic_lite",
        "eval_split": args.eval_split,
        "mode": "residual_selector_closure",
        "status_label": summary["diagnostic_label"],
        "transition_improvement": str(latest.get("transition_improvement", "0.000000")),
        "delta_cosine": str(latest.get("delta_cosine", "0.000000")),
        "recall_at_1": str(latest.get("recall_at_1", "0.000000")),
        "median_rank": str(latest.get("median_rank", "0.000000")),
        "delta_rank": str(latest.get("delta_rank", "0.000000")),
        "magnitude_ratio": str(latest.get("magnitude_ratio", "0.000000")),
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": str(latest.get("effective_rank_z_bio", "0.000000")),
        "effective_rank_target": str(latest.get("effective_rank_target", "0.000000")),
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": f"{summary['mean_floor_gap_transition']:.6f}",
        "floor_gap_recall": "0.000000",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{summary['min_floor_gap_transition']:.6f}",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": f"{summary['calibration_mismatch_count']:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Read-only residual-selector family closure; pivot to data-contract/benchmark redesign; no model promotion.",
        "artifact_dir": str(out),
    }


