def _write_f070_report(path: Path, payload: dict[str, Any], summary: pd.DataFrame, frame: pd.DataFrame) -> None:
    key = pd.DataFrame(
        [
            payload.get("true_z_bio_summary", {}),
            payload.get("clean_rna_summary", {}),
            payload.get("observed_summary", {}),
            payload.get("best_candidate_summary", {}),
        ]
    )
    key_tsv = key.to_csv(sep="\t", index=False) if not key.empty else "No key rows.\n"
