def write_amendment_f070_denoised_representation(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Denoised Representation Ceiling Diagnostic

## Trigger
`{trigger}`

## Evidence
F069 showed that observed RNA PCA amplifies train-real calibration mismatch relative to true synthetic `z_bio`. The next step should identify whether a train-only denoising transform or oracle clean RNA can reduce that mismatch before training another representation model.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it. F070 is diagnostic and cannot promote.

## New Diagnostic Branch
`F070_DENOISED_REPRESENTATION_CEILING`

## Implementation Tasks
- Reuse the F068 split-contract benchmarks and seeds.
- Compare observed RNA PCA, observed-count PCA, train-only batch-residualized RNA PCA, clean RNA PCA, and true `z_bio`.
- Fit PCA/ridge/batch residualization from train rows only.
- Use held-out perturbation rows only for scoring.
- Report train-inner versus real-heldout optimism, latent rank, perturbation probe, and batch probe.
- Do not train JEPA and do not promote.

## Decision Use
If a train-only denoised candidate reduces mismatch, design a small representation repair branch around that target. If only clean RNA or true `z_bio` helps, prioritize learned biological denoising rather than more transition residuals.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def _train_only_zbio_recovery_embeddings(features: np.ndarray, z_bio: np.ndarray, metadata: pd.DataFrame, *, alpha: float = 1.0e-1) -> np.ndarray:
    features = np.asarray(features, dtype=np.float64)
    z_bio = np.asarray(z_bio, dtype=np.float64)
    train_idx = np.flatnonzero((metadata["split"] == "train").to_numpy())
    if train_idx.size == 0:
        raise ValueError("cannot recover z_bio without train rows")
    fit = fit_ridge_numpy(features[train_idx], z_bio[train_idx], alpha=alpha)
    return predict_ridge_numpy(fit, features).astype(np.float64)


def _cell_level_recovery_cosine(predicted: np.ndarray, target: np.ndarray, metadata: pd.DataFrame, *, split: str) -> float:
    mask = (metadata["split"] == split).to_numpy()
    if not np.any(mask):
        return 0.0
    pred = np.asarray(predicted, dtype=np.float64)[mask]
    truth = np.asarray(target, dtype=np.float64)[mask]
    if pred.shape[1] != truth.shape[1]:
        return 0.0
    return float(np.mean(np.sum(_l2_normalize_numpy(pred) * _l2_normalize_numpy(truth), axis=1)))


def _f071_decision_from_summary(summary: dict[str, Any]) -> str:
    observed_delta = float(summary.get("observed_mean_abs_delta_optimism", 0.0))
    observed_transition = float(summary.get("observed_mean_abs_transition_optimism", 0.0))
    best_delta = float(summary.get("best_recovered_mean_abs_delta_optimism", 0.0))
    best_transition = float(summary.get("best_recovered_mean_abs_transition_optimism", 0.0))
    best_recovery_cosine = float(summary.get("best_recovered_eval_zbio_cosine", 0.0))
    image_gap = float(summary.get("best_image_fusion_delta_optimism_gain", 0.0))
    reduces_mismatch = best_delta <= 0.75 * max(observed_delta, 1.0e-8) and best_transition <= 0.75 * max(observed_transition, 1.0e-8)
    if reduces_mismatch and best_recovery_cosine >= 0.70 and image_gap > 0.005:
        return "F071_CROSS_MODAL_ZBIO_RECOVERY_REDUCES_MISMATCH"
    if reduces_mismatch and best_recovery_cosine >= 0.70:
        return "F071_RNA_ZBIO_RECOVERY_REDUCES_MISMATCH"
    if best_recovery_cosine >= 0.70:
        return "F071_ZBIO_RECOVERABLE_BUT_TRANSITION_MISMATCH_REMAINS"
    return "F071_ZBIO_NOT_RECOVERABLE_FROM_CURRENT_OBSERVATIONS"


def run_f071_zbio_observability_audit(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F071_zbio_observability_audit"
    out.mkdir(parents=True, exist_ok=True)
    policies = [
        ("extrapolative_index", "synth_program_aligned_extrapolative_holdout_lite"),
        ("random_perturbation", "synth_program_aligned_random_holdout_lite"),
        ("stratified_program", "synth_program_aligned_stratified_holdout_lite"),
    ]
    seeds = [34, 35, 36, 37, 38]
    rows: list[dict[str, Any]] = []
    for policy, benchmark in policies:
        for seed in seeds:
            dataset = generate_synthetic_biology_lite(synthetic_lite_config(benchmark, seed=seed))
            observed = dataset.expression_values.astype(np.float64)
            clean = dataset.clean_rna.astype(np.float64)
            images = dataset.images.reshape(dataset.images.shape[0], -1).astype(np.float64)
            batch_residualized = _train_only_batch_residualized_values(observed, dataset.metadata)
            recovered = {
                "observed_rna_train_pca": _train_only_pca_embeddings(observed, dataset.metadata, dim=24),
                "true_z_bio": dataset.z_bio.astype(np.float64),
                "observed_rna_to_zbio_ridge": _train_only_zbio_recovery_embeddings(observed, dataset.z_bio, dataset.metadata),
                "batch_residualized_rna_to_zbio_ridge": _train_only_zbio_recovery_embeddings(batch_residualized, dataset.z_bio, dataset.metadata),
                "clean_rna_to_zbio_ridge": _train_only_zbio_recovery_embeddings(clean, dataset.z_bio, dataset.metadata),
                "image_to_zbio_ridge": _train_only_zbio_recovery_embeddings(images, dataset.z_bio, dataset.metadata),
                "rna_image_to_zbio_ridge": _train_only_zbio_recovery_embeddings(np.concatenate((observed, images), axis=1), dataset.z_bio, dataset.metadata),
            }
            for representation, latents in recovered.items():
                train_bundle = _f068_condition_bundle_from_latents(dataset, latents, split="train", name=f"f071_{policy}_{seed}_{representation}_train")
                eval_bundle = _f068_condition_bundle_from_latents(dataset, latents, split=args.eval_split, name=f"f071_{policy}_{seed}_{representation}_eval")
                ridge = fit_ridge_numpy(bundle_features(train_bundle), train_bundle.delta, alpha=1.0e-2)
                real_delta = predict_ridge_numpy(ridge, bundle_features(eval_bundle))
                real_metrics = bundle_transition_metrics(eval_bundle, real_delta)
                inner_summary, _ = _f068_inner_action_ridge_summary(train_bundle)
                rep_metrics = _representation_metrics_for_bundle(train_bundle, eval_bundle, eval_bundle.target)
                row = {
                    "policy": policy,
                    "benchmark": benchmark,
                    "seed": seed,
                    "representation": representation,
                    "representation_class": (
                        "oracle"
                        if representation in {"true_z_bio", "clean_rna_to_zbio_ridge"}
                        else "train_only_recovered"
                    ),
                    "eval_cell_zbio_cosine": (
                        1.0
                        if representation == "true_z_bio"
                        else _cell_level_recovery_cosine(latents, dataset.z_bio, dataset.metadata, split=args.eval_split)
                    ),
                    "real_transition": real_metrics["transition_source_cosine_improvement"],
                    "real_delta_cosine": real_metrics["delta_cosine"],
                    "real_recall_at_1": real_metrics.get("transition_to_target_recall@1", 0.0),
                    "real_delta_rank": real_metrics["delta_prediction_effective_rank"],
                    "real_magnitude_ratio": real_metrics["delta_magnitude_ratio"],
                    "eval_effective_rank_z": rep_metrics["effective_rank"],
                    "train_perturbation_probe_cv": rep_metrics["perturbation_probe_cv"],
                    "train_batch_probe_cv": rep_metrics["batch_probe_cv"],
                    **inner_summary,
                }
                row["transition_optimism"] = row["inner_mean_transition"] - row["real_transition"]
                row["delta_optimism"] = row["inner_mean_delta_cosine"] - row["real_delta_cosine"]
                row["recall_optimism"] = row["inner_mean_recall_at_1"] - row["real_recall_at_1"]
                row["abs_transition_optimism"] = abs(row["transition_optimism"])
                row["abs_delta_optimism"] = abs(row["delta_optimism"])
                rows.append(row)
    frame = pd.DataFrame(rows)
    frame.to_csv(out / "f071_zbio_observability_seed_metrics.tsv", sep="\t", index=False)
    summary_frame = frame.groupby(["representation", "representation_class"], as_index=False).agg(
        seed_policy_count=("seed", "count"),
        mean_eval_cell_zbio_cosine=("eval_cell_zbio_cosine", "mean"),
        mean_real_transition=("real_transition", "mean"),
        mean_real_delta_cosine=("real_delta_cosine", "mean"),
        mean_real_recall_at_1=("real_recall_at_1", "mean"),
        mean_real_delta_rank=("real_delta_rank", "mean"),
        mean_abs_transition_optimism=("abs_transition_optimism", "mean"),
        mean_abs_delta_optimism=("abs_delta_optimism", "mean"),
        max_abs_transition_optimism=("abs_transition_optimism", "max"),
        max_abs_delta_optimism=("abs_delta_optimism", "max"),
        mean_eval_effective_rank_z=("eval_effective_rank_z", "mean"),
        mean_train_perturbation_probe_cv=("train_perturbation_probe_cv", "mean"),
        mean_train_batch_probe_cv=("train_batch_probe_cv", "mean"),
    )
    summary_frame = summary_frame.sort_values(["mean_abs_delta_optimism", "mean_abs_transition_optimism"], ascending=True)
    summary_frame.to_csv(out / "f071_zbio_observability_summary.tsv", sep="\t", index=False)
    observed = _summary_row_by_key(summary_frame, "representation", "observed_rna_train_pca")
    true = _summary_row_by_key(summary_frame, "representation", "true_z_bio")
    candidate_summary = summary_frame[summary_frame["representation_class"] == "train_only_recovered"].copy()
    best_recovered = candidate_summary.iloc[0].to_dict() if not candidate_summary.empty else {}
    image_fusion = _summary_row_by_key(summary_frame, "representation", "rna_image_to_zbio_ridge")
    rna_only = _summary_row_by_key(summary_frame, "representation", "observed_rna_to_zbio_ridge")
    image_gain = float(rna_only.get("mean_abs_delta_optimism", 0.0)) - float(image_fusion.get("mean_abs_delta_optimism", 0.0))
    payload = {
        "source_experiment": "F070",
        "observed_summary": observed,
        "true_z_bio_summary": true,
        "best_recovered_summary": best_recovered,
        "rna_only_summary": rna_only,
        "image_fusion_summary": image_fusion,
        "observed_mean_abs_transition_optimism": float(observed.get("mean_abs_transition_optimism", 0.0)),
        "observed_mean_abs_delta_optimism": float(observed.get("mean_abs_delta_optimism", 0.0)),
        "best_recovered_representation": str(best_recovered.get("representation", "")),
        "best_recovered_mean_abs_transition_optimism": float(best_recovered.get("mean_abs_transition_optimism", 0.0)),
        "best_recovered_mean_abs_delta_optimism": float(best_recovered.get("mean_abs_delta_optimism", 0.0)),
        "best_recovered_eval_zbio_cosine": float(best_recovered.get("mean_eval_cell_zbio_cosine", 0.0)),
        "best_image_fusion_delta_optimism_gain": image_gain,
        "model_promoted": False,
        "leakage_controls": (
            "Synthetic z_bio recovery fits use train rows only and are oracle diagnostics. Eval z_bio is scoring-only. "
            "No condition_key, biological_key, exact heldout action one-hot, or eval target means are model inputs."
        ),
    }
    payload["diagnostic_label"] = _f071_decision_from_summary(payload)
    write_json(out / "metrics_eval.json", payload)
    _write_f071_report(out / "F071_ZBIO_OBSERVABILITY_AUDIT.md", payload, summary_frame, frame)
    append_journal(
        args.output_root,
        "F071_ZBIO_OBSERVABILITY_AUDIT",
        "Train-only z_bio observability diagnostic",
        (
            f"Decision={payload['diagnostic_label']}; best={payload['best_recovered_representation']}; "
            f"best_z_cos={payload['best_recovered_eval_zbio_cosine']:.4f}; "
            f"best_delta_optimism={payload['best_recovered_mean_abs_delta_optimism']:.6f}."
        ),
    )
    row_metrics = best_recovered if best_recovered else observed
    return {
        "experiment_id": "F071",
        "phase": "PostPhase8Council",
        "family": "Representation repair",
        "tier": "Diagnostic",
        "seed": "34,35,36,37,38",
        "dataset": "synth_program_aligned_*_holdout_lite",
        "eval_split": args.eval_split,
        "mode": "zbio_observability_audit",
        "status_label": payload["diagnostic_label"],
        "transition_improvement": f"{float(row_metrics.get('mean_real_transition', 0.0)):.6f}",
        "delta_cosine": f"{float(row_metrics.get('mean_real_delta_cosine', 0.0)):.6f}",
        "recall_at_1": f"{float(row_metrics.get('mean_real_recall_at_1', 0.0)):.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{float(row_metrics.get('mean_real_delta_rank', 0.0)):.6f}",
        "magnitude_ratio": "0.000000",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": f"{float(row_metrics.get('mean_train_batch_probe_cv', 0.0)):.6f}",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{float(row_metrics.get('mean_eval_effective_rank_z', 0.0)):.6f}",
        "effective_rank_target": f"{float(true.get('mean_eval_effective_rank_z', 0.0)):.6f}",
        "collapse_flag": str(float(row_metrics.get("mean_eval_effective_rank_z", 0.0)) < 2.0),
        "leakage_flag": "False",
        "floor_gap_transition": f"{float(observed.get('mean_abs_transition_optimism', 0.0)) - float(row_metrics.get('mean_abs_transition_optimism', 0.0)):.6f}",
        "floor_gap_recall": "0.000000",
        "floor_gap_delta_cosine": f"{float(observed.get('mean_abs_delta_optimism', 0.0)) - float(row_metrics.get('mean_abs_delta_optimism', 0.0)):.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{float(row_metrics.get('mean_abs_transition_optimism', 0.0)):.6f}",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": f"{payload['best_recovered_eval_zbio_cosine']:.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Train-only synthetic z_bio observability audit; no model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f070_to_f071(args: argparse.Namespace) -> dict[str, Any]:
    f070 = _load_metric_json(args.output_root / "experiments/F070_denoised_representation_ceiling/metrics_eval.json")
    trigger = str(f070.get("diagnostic_label", "F070_TRUE_ZBIO_ONLY_REDUCES_MISMATCH_RNA_OBSERVATION_LIMIT"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F069", "F070"])].to_dict("records")
    write_phase_closure(args.output_root, "100", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F071 train-only z_bio observability audit",
            {"novelty": 0.68, "feasibility": 1.00, "identity": 0.98, "effect": 0.84, "falsifiability": 0.98, "leakage": 0.94, "compute": 1.00},
            "Fit train-only synthetic observation-to-z_bio probes to test whether RNA/image observations contain recoverable biological state.",
        ),
        CouncilProposal(
            "Train a learned denoising JEPA immediately",
            {"novelty": 0.78, "feasibility": 0.62, "identity": 0.94, "effect": 0.70, "falsifiability": 0.74, "leakage": 0.86, "compute": 0.50},
            "Defer because F070 showed only true z_bio clearly fixes mismatch; first test observability from available modalities.",
        ),
        CouncilProposal(
            "Redesign synthetic generator immediately",
            {"novelty": 0.62, "feasibility": 0.82, "identity": 0.92, "effect": 0.62, "falsifiability": 0.78, "leakage": 0.90, "compute": 0.78},
            "Defer one diagnostic until observability of the current generator's latent state is measured.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "100", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f071_zbio_observability(args.output_root, "100", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "100", trigger, council_path, amendment_path, selected.next_action)
    return run_f071_zbio_observability_audit(args)


