def continue_after_f076_to_f077(args: argparse.Namespace) -> dict[str, Any]:
    f076 = _load_metric_json(args.output_root / "experiments/F076_condition_centroid_image_teacher/metrics_eval.json")
    trigger = str(f076.get("diagnostic_label", "F076_CONDITION_CENTROID_TEACHER_STILL_LOSES_STRUCTURE"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F075", "F076"])].to_dict("records")
    write_phase_closure(args.output_root, "106", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F077 source-state plus program-action image teacher",
            {"novelty": 0.78, "feasibility": 0.88, "identity": 0.90, "effect": 0.84, "falsifiability": 0.94, "leakage": 0.86, "compute": 0.84},
            "Test the world-model factorization directly: train-only control/source state plus coarse program action predicts condition-centroid image teacher.",
        ),
        CouncilProposal(
            "Exact action descriptor repair",
            {"novelty": 0.64, "feasibility": 0.80, "identity": 0.78, "effect": 0.78, "falsifiability": 0.80, "leakage": 0.34, "compute": 0.78},
            "Reject for now because exact action one-hot features are forbidden and would confound heldout perturbation claims.",
        ),
        CouncilProposal(
            "Increase RNA-to-image student capacity",
            {"novelty": 0.36, "feasibility": 0.84, "identity": 0.88, "effect": 0.44, "falsifiability": 0.66, "leakage": 0.88, "compute": 0.48},
            "Defer because per-cell and condition-centroid target changes already failed without identifying capacity as the bottleneck.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "106", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f077_source_program(args.output_root, "106", trigger, selected)
