def continue_after_f078_to_f079(args: argparse.Namespace) -> dict[str, Any]:
    f078 = _load_metric_json(args.output_root / "experiments/F078_source_program_failure_localization/metrics_eval.json")
    trigger = str(f078.get("diagnostic_label", "F078_SOURCE_PROGRAM_RECALL_WITH_LOW_TRANSITION_AND_ACTION_SIGNAL"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F077", "F078"])].to_dict("records")
    write_phase_closure(args.output_root, "108", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F079 source/delta/rank-constrained program repair",
            {"novelty": 0.76, "feasibility": 0.86, "identity": 0.90, "effect": 0.84, "falsifiability": 0.94, "leakage": 0.86, "compute": 0.82},
            "Add explicit source-state prediction, delta-direction, source-improvement hinge, and delta-rank variance losses to the coarse program branch.",
        ),
        CouncilProposal(
            "Richer non-exact action descriptors",
            {"novelty": 0.82, "feasibility": 0.72, "identity": 0.84, "effect": 0.78, "falsifiability": 0.80, "leakage": 0.66, "compute": 0.72},
            "Defer until source/delta objective repair shows whether the current coarse descriptor can carry transition signal.",
        ),
        CouncilProposal(
            "Full source-action JEPA wrapper",
            {"novelty": 0.90, "feasibility": 0.52, "identity": 0.98, "effect": 0.82, "falsifiability": 0.70, "leakage": 0.78, "compute": 0.34},
            "Defer because F077/F078 found a specific objective/rank failure to repair first.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "108", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f079_source_delta_rank(args.output_root, "108", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "108", trigger, council_path, amendment_path, selected.next_action)
    return run_f079_source_delta_rank_repair(args)


