    key_tsv = key.to_csv(sep="\t", index=False) if not key.empty else "No key rows.\n"
    summary_tsv = summary.to_csv(sep="\t", index=False) if not summary.empty else "No summary rows.\n"
    trace_tsv = trace.to_csv(sep="\t", index=False) if not trace.empty else "No train trace.\n"
    frame_head_tsv = frame.head(80).to_csv(sep="\t", index=False) if not frame.empty else "No per-seed rows.\n"
