def continue_after_f081_to_f082(args: argparse.Namespace) -> dict[str, Any]:
    f081 = _load_metric_json(args.output_root / "experiments/F081_delta_calibrated_jepa_wrapper/metrics_eval.json")
    trigger = str(f081.get("diagnostic_label", "F081_DELTA_CALIBRATED_JEPA_TIER1_PASS_NONPROMOTING"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F080", "F081"])].to_dict("records")
    write_phase_closure(args.output_root, "111", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F082 fresh-seed delta-calibrated JEPA validation",
            {"novelty": 0.54, "feasibility": 0.90, "identity": 0.96, "effect": 0.88, "falsifiability": 0.98, "leakage": 0.90, "compute": 0.74},
            "Validate F081 on fresh seeds and all split policies before designing any Tier 3 or integrating the calibrator into the JEPA head.",
        ),
        CouncilProposal(
            "Immediately design Tier 3",
            {"novelty": 0.48, "feasibility": 0.62, "identity": 0.92, "effect": 0.70, "falsifiability": 0.68, "leakage": 0.82, "compute": 0.42},
            "Defer because F081 has only same-seed Tier 1 evidence.",
        ),
        CouncilProposal(
            "Replace coarse program action descriptors",
            {"novelty": 0.84, "feasibility": 0.70, "identity": 0.86, "effect": 0.64, "falsifiability": 0.78, "leakage": 0.68, "compute": 0.62},
            "Defer because the immediate risk is seed stability of the current positive result, not action descriptor expressivity.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "111", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f082_delta_calibrated_tier2(args.output_root, "111", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "111", trigger, council_path, amendment_path, selected.next_action)
    return run_f082_delta_calibrated_tier2_validation(args)


def _write_f082_report(path: Path, payload: dict[str, Any], frame: pd.DataFrame, trace: pd.DataFrame) -> None:
    frame_tsv = frame.to_csv(sep="\t", index=False) if not frame.empty else "No per-seed rows.\n"
    trace_tsv = trace.to_csv(sep="\t", index=False) if not trace.empty else "No train trace.\n"
    key_tsv = pd.DataFrame([payload]).to_csv(sep="\t", index=False)
    path.write_text(
        f"""# F082 Delta-Calibrated JEPA Tier 2 Validation

## Decision
`{payload['diagnostic_label']}`

## Purpose
F081 passed a same-seed Tier 1 diagnostic. F082 reruns the same real JEPA plus train-only delta calibrator on fresh seeds to test stability before any Tier 3 design.

## Key Results
- seeds: `{payload['seeds']}`
- mean calibrated transition improvement: `{payload['mean_calibrated_transition_improvement']:.6f}`
- std calibrated transition improvement: `{payload['std_calibrated_transition_improvement']:.6f}`
- min calibrated transition improvement: `{payload['min_calibrated_transition_improvement']:.6f}`
- mean calibrated delta cosine: `{payload['mean_calibrated_delta_cosine']:.6f}`
- min calibrated delta cosine: `{payload['min_calibrated_delta_cosine']:.6f}`
- mean calibrated recall@1: `{payload['mean_calibrated_recall_at_1']:.6f}`
- min calibrated recall@1: `{payload['min_calibrated_recall_at_1']:.6f}`
- mean calibrated delta rank: `{payload['mean_calibrated_delta_rank']:.6f}`
- mean calibrated magnitude ratio: `{payload['mean_calibrated_magnitude_ratio']:.6f}`
- mean RNA->image recall@1: `{payload['mean_rna_to_image_recall_at_1']:.6f}`
- mean image->RNA recall@1: `{payload['mean_image_to_rna_recall_at_1']:.6f}`

## Leakage Controls
{payload['leakage_controls']}

## Summary Row
```tsv
{key_tsv}
```

## Per-Seed Rows
```tsv
{frame_tsv}
```

## Train Trace
```tsv
{trace_tsv}
```

## Promotion Status
No model is promoted. F082 is Tier 2-style validation only and can at most justify a future Tier 3 plan.
""",
        encoding="utf-8",
    )


def write_amendment_f082_delta_calibrated_tier2(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Fresh-Seed Delta-Calibrated JEPA Validation

## Trigger
`{trigger}`

## Evidence
F081 passed a Tier 1 diagnostic by showing that F080's JEPA predicted deltas contain train-only linearly recoverable heldout delta direction. Because Tier 1 cannot promote, the next autonomous step is fresh-seed validation under the same no-leakage rules.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it. F082 is Tier 2-style validation and cannot promote.

## New Branch
`F082_DELTA_CALIBRATED_TIER2_VALIDATION`

## Implementation Tasks
- Rerun the F081 real JEPA plus train-only delta calibrator on fresh seeds 37-42.
- Keep the same three split policies.
- Report mean/std/min transition, delta cosine, recall, rank, magnitude, cross-modal retrieval, and action-negative gap.
- Treat any seed/policy collapse as a pivot event.
- Do not use `condition_key`, `biological_key`, exact heldout action one-hot, eval target means, or pooled train+test statistics.
- Do not promote.

## Decision Use
If F082 is stable, write a Tier 3 design amendment with no-regression validators and a locked candidate code path. If it is unstable, localize the failing policy/seed before changing architecture.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def _f083_decision_from_summary(summary: dict[str, Any]) -> str:
    if float(summary.get("max_identity_violation", 1.0)) > 0.0 or float(summary.get("max_leakage_flag", 1.0)) > 0.0:
        return "F083_TIER3_PREFLIGHT_IDENTITY_OR_LEAKAGE_FAIL"
    transition_ok = bool(summary.get("transition_floor_pass", False))
    delta_ok = bool(summary.get("delta_floor_pass", False))
    recall_ok = bool(summary.get("recall_floor_pass", False))
    rank_ok = bool(summary.get("rank_floor_pass", False))
    magnitude_ok = bool(summary.get("magnitude_floor_pass", False))
    cross_modal_ok = bool(summary.get("cross_modal_gate_pass", False))
    external_ok = bool(summary.get("paired_external_validator_available", False))
    if transition_ok and delta_ok and recall_ok and rank_ok and magnitude_ok and cross_modal_ok and external_ok:
        return "F083_TIER3_PREFLIGHT_APPROVED_FOR_LOCKED_TIER3_RUN"
    if transition_ok and delta_ok and recall_ok and cross_modal_ok and not rank_ok and not external_ok:
        return "F083_TIER3_PREFLIGHT_BLOCKED_BY_RANK_AND_VALIDATOR_GAPS"
    if transition_ok and delta_ok and recall_ok and cross_modal_ok and not rank_ok:
        return "F083_TIER3_PREFLIGHT_BLOCKED_BY_DELTA_RANK_NO_REGRESSION"
    if transition_ok and delta_ok and recall_ok and rank_ok and not external_ok:
        return "F083_TIER3_PREFLIGHT_NEEDS_PAIRED_EXTERNAL_VALIDATOR"
    return "F083_TIER3_PREFLIGHT_DOES_NOT_MEET_CORE_GATES"


def run_f083_tier3_preflight(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F083_tier3_preflight"
    out.mkdir(parents=True, exist_ok=True)
    f082 = _load_metric_json(args.output_root / "experiments/F082_delta_calibrated_tier2_validation/metrics_eval.json")
    norman_path = Path("data/raw/gears_norman/norman/perturb_processed.h5ad")
    paired_external_validator_available = False
    summary = {
        "source_experiment": "F082",
        "candidate_code_path": "scripts/run_bioguard_wm_total_autonomy.py::_run_delta_calibrated_jepa_seed_grid + perturb_jepa.models.program_bootstrap_jepa.ProgramBootstrapJEPA",
        "protected_model_of_record": "rank-3 train-split-only PLS raw-linear readout",
        "transition_floor": FLOOR["transition_source_cosine_improvement"],
        "delta_cosine_floor": FLOOR["delta_cosine"],
        "recall_floor": FLOOR["transition_to_target_recall@1"],
        "delta_rank_floor": FLOOR["delta_prediction_effective_rank"],
        "magnitude_ratio_floor": FLOOR["delta_magnitude_ratio"],
        "mean_transition": float(f082.get("mean_calibrated_transition_improvement", 0.0)),
        "min_transition": float(f082.get("min_calibrated_transition_improvement", 0.0)),
        "mean_delta_cosine": float(f082.get("mean_calibrated_delta_cosine", 0.0)),
        "min_delta_cosine": float(f082.get("min_calibrated_delta_cosine", 0.0)),
        "mean_recall_at_1": float(f082.get("mean_calibrated_recall_at_1", 0.0)),
        "min_recall_at_1": float(f082.get("min_calibrated_recall_at_1", 0.0)),
        "mean_delta_rank": float(f082.get("mean_calibrated_delta_rank", 0.0)),
        "min_delta_rank": float(f082.get("min_calibrated_delta_rank", 0.0)),
        "mean_magnitude_ratio": float(f082.get("mean_calibrated_magnitude_ratio", 0.0)),
        "mean_rna_to_image_recall_at_1": float(f082.get("mean_rna_to_image_recall_at_1", 0.0)),
        "mean_image_to_rna_recall_at_1": float(f082.get("mean_image_to_rna_recall_at_1", 0.0)),
        "max_identity_violation": float(f082.get("max_identity_violation", 1.0)),
        "max_leakage_flag": float(f082.get("max_leakage_flag", 1.0)),
        "paired_external_validator_available": paired_external_validator_available,
        "norman_rna_only_path_exists": norman_path.exists(),
        "norman_validator_status": "RNA-only diagnostic possible; not a paired scRNA+imaging Tier 3 validator.",
        "model_promoted": False,
    }
    summary["transition_floor_pass"] = summary["mean_transition"] >= summary["transition_floor"] and summary["min_transition"] >= 0.0
    summary["delta_floor_pass"] = summary["mean_delta_cosine"] >= summary["delta_cosine_floor"] and summary["min_delta_cosine"] >= summary["delta_cosine_floor"]
    summary["recall_floor_pass"] = summary["mean_recall_at_1"] >= summary["recall_floor"] and summary["min_recall_at_1"] >= summary["recall_floor"]
    summary["rank_floor_pass"] = summary["mean_delta_rank"] >= summary["delta_rank_floor"] and summary["min_delta_rank"] >= 0.80 * summary["delta_rank_floor"]
    summary["magnitude_floor_pass"] = summary["mean_magnitude_ratio"] >= summary["magnitude_ratio_floor"]
    summary["cross_modal_gate_pass"] = summary["mean_rna_to_image_recall_at_1"] >= 0.70 and summary["mean_image_to_rna_recall_at_1"] >= 0.70
    summary["transition_floor_gap"] = summary["mean_transition"] - summary["transition_floor"]
    summary["delta_floor_gap"] = summary["mean_delta_cosine"] - summary["delta_cosine_floor"]
    summary["recall_floor_gap"] = summary["mean_recall_at_1"] - summary["recall_floor"]
    summary["rank_floor_gap"] = summary["mean_delta_rank"] - summary["delta_rank_floor"]
    summary["magnitude_floor_gap"] = summary["mean_magnitude_ratio"] - summary["magnitude_ratio_floor"]
    summary["required_next_branch"] = (
        "rank_preserving_delta_calibrator_or_rank_ladder_before_Tier3"
        if not summary["rank_floor_pass"]
        else "paired_external_validator_discovery_before_Tier3"
    )
    summary["diagnostic_label"] = _f083_decision_from_summary(summary)
    write_json(out / "metrics_eval.json", summary)
    _write_f083_report(out / "F083_TIER3_PREFLIGHT.md", summary)
    _write_f083_tier3_design(out / "TIER3_DESIGN.md", summary)
    append_journal(
        args.output_root,
        "F083_TIER3_PREFLIGHT",
        "Tier 3 no-regression preflight for delta-calibrated JEPA",
        (
            f"Decision={summary['diagnostic_label']}; transition_gap={summary['transition_floor_gap']:.4f}; "
            f"delta_gap={summary['delta_floor_gap']:.4f}; rank_gap={summary['rank_floor_gap']:.4f}; "
            f"paired_external_validator={summary['paired_external_validator_available']}."
        ),
    )
    return {
        "experiment_id": "F083",
        "phase": "PostPhase8Council",
        "family": "Tier3 design",
        "tier": "Tier3Preflight",
        "seed": str(f082.get("seeds", "37,38,39,40,41,42")),
        "dataset": "synth_program_aligned_*_holdout_lite",
        "eval_split": args.eval_split,
        "mode": "tier3_preflight",
        "status_label": summary["diagnostic_label"],
        "transition_improvement": f"{summary['mean_transition']:.6f}",
        "delta_cosine": f"{summary['mean_delta_cosine']:.6f}",
        "recall_at_1": f"{summary['mean_recall_at_1']:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{summary['mean_delta_rank']:.6f}",
        "magnitude_ratio": f"{summary['mean_magnitude_ratio']:.6f}",
        "rna_to_image_recall_at_1": f"{summary['mean_rna_to_image_recall_at_1']:.6f}",
        "image_to_rna_recall_at_1": f"{summary['mean_image_to_rna_recall_at_1']:.6f}",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{summary['mean_delta_rank']:.6f}",
        "effective_rank_target": f"{summary['delta_rank_floor']:.6f}",
        "collapse_flag": str(not summary["rank_floor_pass"]),
        "leakage_flag": str(summary["max_leakage_flag"] > 0.0),
        "floor_gap_transition": f"{summary['transition_floor_gap']:.6f}",
        "floor_gap_recall": f"{summary['recall_floor_gap']:.6f}",
        "floor_gap_delta_cosine": f"{summary['delta_floor_gap']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{summary['min_transition']:.6f}",
        "calibration_lcb_recall_gap": f"{summary['min_delta_cosine']:.6f}",
        "action_negative_gap": f"{float(f082.get('mean_calibrated_action_negative_gap', 0.0)):.6f}",
        "context_contract_pass": "True",
        "jepa_identity_pass": str(summary["max_identity_violation"] == 0.0),
        "notes": "Tier 3 preflight only; no model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f082_to_f083(args: argparse.Namespace) -> dict[str, Any]:
    f082 = _load_metric_json(args.output_root / "experiments/F082_delta_calibrated_tier2_validation/metrics_eval.json")
    trigger = str(f082.get("diagnostic_label", "F082_DELTA_CALIBRATED_TIER2_READY_FOR_TIER3_DESIGN"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F081", "F082"])].to_dict("records")
    write_phase_closure(args.output_root, "112", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F083 Tier 3 no-regression preflight",
            {"novelty": 0.50, "feasibility": 0.98, "identity": 0.98, "effect": 0.90, "falsifiability": 1.00, "leakage": 0.96, "compute": 0.98},
            "Convert the F082 pass into explicit Tier 3 gates, including locked rank floor, cross-modal gates, external-validator availability, and candidate code lock.",
        ),
        CouncilProposal(
            "Launch Tier 3 immediately",
            {"novelty": 0.42, "feasibility": 0.56, "identity": 0.92, "effect": 0.72, "falsifiability": 0.62, "leakage": 0.72, "compute": 0.40},
            "Reject until all no-regression gates and external validator requirements are explicit.",
        ),
        CouncilProposal(
            "Rank repair before preflight",
            {"novelty": 0.74, "feasibility": 0.72, "identity": 0.90, "effect": 0.70, "falsifiability": 0.82, "leakage": 0.86, "compute": 0.70},
            "Defer until the preflight confirms whether locked rank is a Tier 3 blocker.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "112", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f083_tier3_preflight(args.output_root, "112", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "112", trigger, council_path, amendment_path, selected.next_action)
    return run_f083_tier3_preflight(args)


