def continue_after_f084_to_f085(args: argparse.Namespace) -> dict[str, Any]:
    f084 = _load_metric_json(args.output_root / "experiments/F084_rank_floor_comparability/metrics_eval.json")
    trigger = str(f084.get("diagnostic_label", "F084_LOCKED_RANK_FLOOR_EXCEEDS_IMAGE_TEACHER_CEILING"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F083", "F084"])].to_dict("records")
    write_phase_closure(args.output_root, "114", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F085 current-latent floor registry",
            {"novelty": 0.62, "feasibility": 0.96, "identity": 0.98, "effect": 0.90, "falsifiability": 1.00, "leakage": 0.98, "compute": 0.92},
            "Reproduce a train-only transition floor and true-delta rank ceiling inside the current image-teacher latent space.",
        ),
        CouncilProposal(
            "Artificial rank ladder",
            {"novelty": 0.76, "feasibility": 0.66, "identity": 0.86, "effect": 0.54, "falsifiability": 0.70, "leakage": 0.82, "compute": 0.58},
            "Reject until a representation-specific floor shows the candidate is actually below a current-space rank baseline.",
        ),
        CouncilProposal(
            "Ignore rank gate",
            {"novelty": 0.10, "feasibility": 0.92, "identity": 0.44, "effect": 0.20, "falsifiability": 0.30, "leakage": 0.70, "compute": 0.90},
            "Reject because the locked floor cannot be silently removed; any change needs a documented registry discrepancy.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "114", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f085_current_latent_floor_registry(args.output_root, "114", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "114", trigger, council_path, amendment_path, selected.next_action)
    return run_f085_current_latent_floor_registry(args)


def _write_f085_report(path: Path, payload: dict[str, Any], merged: pd.DataFrame) -> None:
    summary_tsv = pd.DataFrame([payload]).to_csv(sep="\t", index=False)
    preview = merged.head(36).to_csv(sep="\t", index=False)
    path.write_text(
        f"""# F085 Current Image-Teacher Latent Floor Registry

## Decision
`{payload['diagnostic_label']}`

## Purpose
F084 showed the old locked delta-rank floor exceeds the current image-teacher latent ceiling. F085 reproduces a train-only transition floor and true-delta rank ceiling inside the current image-teacher latent registry instead of silently reusing an incomparable rank floor.

## Key Results
- current floor transition: `{payload['mean_current_floor_transition']:.6f}`
- current floor delta cosine: `{payload['mean_current_floor_delta_cosine']:.6f}`
- current floor recall@1: `{payload['mean_current_floor_recall_at_1']:.6f}`
- current floor delta rank: `{payload['mean_current_floor_delta_rank']:.6f}`
- true delta effective rank: `{payload['mean_true_delta_effective_rank']:.6f}`
- candidate transition: `{payload['mean_candidate_transition']:.6f}`
- candidate delta cosine: `{payload['mean_candidate_delta_cosine']:.6f}`
- candidate recall@1: `{payload['mean_candidate_recall_at_1']:.6f}`
- candidate delta rank: `{payload['mean_candidate_delta_rank']:.6f}`
- candidate preserves current floor: `{payload['candidate_preserves_current_floor']}`
- current registry rank supported: `{payload['current_registry_rank_supported']}`
- locked rank floor incomparable: `{payload['locked_rank_floor_incomparable']}`

## Summary Row
```tsv
{summary_tsv}
```

## Candidate Versus Current Floor
```tsv
{preview}
```

## Promotion Status
No model is promoted. F085 is a registry/audit step that may justify a future Tier 3 design using representation-specific floors, not a promotion by itself.
""",
        encoding="utf-8",
    )


def write_amendment_f085_current_latent_floor_registry(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: Current Image-Teacher Latent Floor Registry

## Trigger
`{trigger}`

## Evidence
F084 showed the locked delta-rank floor is above the current image-teacher target ceiling. This indicates a cross-representation baseline mismatch. The protocol allows a fresh baseline discrepancy to be documented rather than silently picking a convenient number.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it.

## New Diagnostic Branch
`F085_CURRENT_LATENT_FLOOR_REGISTRY`

## Implementation Tasks
- Rebuild the current train-only image-teacher latent tables for F082 seeds and split policies.
- Fit train-only action ridge floors in that current latent registry.
- Compute true delta effective-rank ceilings in the same registry.
- Compare F082 calibrated JEPA against those current-registry floors.
- Do not train and do not promote.

## Decision Use
If F085 shows the candidate preserves the current-registry floor and rank ceiling, design Tier 3 with an explicit representation-specific rank registry plus external-validator plan. If it shows a current-registry rank gap, implement a rank-preserving calibrator.

## Hard Escalation Check
No hard escalation trigger present.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


