def _f086_decision_from_summary(summary: dict[str, Any]) -> str:
    if bool(summary.get("identity_or_leakage_fail", False)):
        return "F086_CURRENT_REGISTRY_TIER3_IDENTITY_OR_LEAKAGE_FAIL"
    if not bool(summary.get("synthetic_current_registry_gates_pass", False)):
        return "F086_CURRENT_REGISTRY_TIER3_SYNTHETIC_GATES_FAIL"
    if bool(summary.get("local_paired_validator_available", False)):
        return "F086_CURRENT_REGISTRY_TIER3_PREFLIGHT_APPROVED_FOR_LOCKED_RUN"
    if bool(summary.get("future_paired_validator_candidate_found", False)):
        return "F086_CURRENT_REGISTRY_TIER3_READY_EXTERNAL_INGEST_NEEDED"
    return "F086_CURRENT_REGISTRY_TIER3_VALIDATOR_GAP_REMAINS"


def run_f086_current_registry_tier3_design(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F086_current_registry_tier3_design"
    out.mkdir(parents=True, exist_ok=True)
    f082 = _load_metric_json(args.output_root / "experiments/F082_delta_calibrated_tier2_validation/metrics_eval.json")
    f085 = _load_metric_json(args.output_root / "experiments/F085_current_latent_floor_registry/metrics_eval.json")
    validator_frame = _f086_external_validator_candidates()
    validator_frame.to_csv(out / "external_validator_shortlist.tsv", sep="\t", index=False)

    local_paired_validator = bool(validator_frame["locally_usable_tier3_validator_now"].any())
    future_paired_validator = bool(validator_frame["future_paired_validator_candidate"].any())
    summary = {
        "source_experiments": "F082,F085",
        "current_registry_transition_floor": float(f085["mean_current_floor_transition"]),
        "current_registry_delta_cosine_floor": float(f085["mean_current_floor_delta_cosine"]),
        "current_registry_recall_floor": float(f085["mean_current_floor_recall_at_1"]),
        "current_registry_true_delta_rank_ceiling": float(f085["mean_true_delta_effective_rank"]),
        "candidate_transition": float(f085["mean_candidate_transition"]),
        "candidate_delta_cosine": float(f085["mean_candidate_delta_cosine"]),
        "candidate_recall_at_1": float(f085["mean_candidate_recall_at_1"]),
        "candidate_delta_rank": float(f085["mean_candidate_delta_rank"]),
        "min_candidate_minus_current_floor_transition": float(f085["min_candidate_minus_current_floor_transition"]),
        "min_candidate_minus_current_floor_delta_cosine": float(f085["min_candidate_minus_current_floor_delta_cosine"]),
        "min_candidate_minus_current_floor_recall": float(f085["min_candidate_minus_current_floor_recall"]),
        "mean_rna_to_image_recall_at_1": float(f082["mean_rna_to_image_recall_at_1"]),
        "mean_image_to_rna_recall_at_1": float(f082["mean_image_to_rna_recall_at_1"]),
        "min_calibrated_transition_improvement": float(f082["min_calibrated_transition_improvement"]),
        "min_calibrated_delta_cosine": float(f082["min_calibrated_delta_cosine"]),
        "max_identity_violation": float(f082["max_identity_violation"]),
        "max_leakage_flag": float(f082["max_leakage_flag"]),
        "candidate_preserves_current_floor": bool(f085["candidate_preserves_current_floor"]),
        "current_registry_rank_supported": bool(f085["current_registry_rank_supported"]),
        "locked_rank_floor_incomparable": bool(f085["locked_rank_floor_incomparable"]),
        "local_paired_validator_available": local_paired_validator,
        "future_paired_validator_candidate_found": future_paired_validator,
        "model_promoted": False,
    }
    summary["identity_or_leakage_fail"] = bool(summary["max_identity_violation"] > 0.0 or summary["max_leakage_flag"] > 0.0)
    summary["cross_modal_gate_pass"] = bool(
        summary["mean_rna_to_image_recall_at_1"] >= 0.50
        and summary["mean_image_to_rna_recall_at_1"] >= 0.50
    )
    summary["synthetic_current_registry_gates_pass"] = bool(
        not summary["identity_or_leakage_fail"]
        and summary["candidate_preserves_current_floor"]
        and summary["current_registry_rank_supported"]
        and summary["cross_modal_gate_pass"]
        and summary["min_calibrated_transition_improvement"] > 0.0
        and summary["min_calibrated_delta_cosine"] >= 0.85
    )
    summary["diagnostic_label"] = _f086_decision_from_summary(summary)
    write_json(out / "metrics_eval.json", summary)
    _write_f086_report(out / "F086_CURRENT_REGISTRY_TIER3_DESIGN.md", summary, validator_frame)
    _append_f086_external_resources(args.output_root, out / "external_validator_shortlist.tsv")
    append_journal(
        args.output_root,
        "F086_CURRENT_REGISTRY_TIER3_DESIGN",
        "Current-registry Tier 3 design and validator preflight",
        (
            f"Decision={summary['diagnostic_label']}; synthetic_current_registry_gates_pass="
            f"{summary['synthetic_current_registry_gates_pass']}; local_paired_validator_available="
            f"{summary['local_paired_validator_available']}; future_paired_validator_candidate_found="
            f"{summary['future_paired_validator_candidate_found']}."
        ),
    )
    return {
        "experiment_id": "F086",
        "phase": "PostPhase8Council",
        "family": "Tier3 design",
        "tier": "Tier3Preflight",
        "seed": "37,38,39,40,41,42",
        "dataset": "synth_program_aligned_*_holdout_lite",
        "eval_split": args.eval_split,
        "mode": "current_registry_tier3_design",
        "status_label": summary["diagnostic_label"],
        "transition_improvement": f"{summary['candidate_transition']:.6f}",
        "delta_cosine": f"{summary['candidate_delta_cosine']:.6f}",
        "recall_at_1": f"{summary['candidate_recall_at_1']:.6f}",
        "median_rank": "0.000000",
        "delta_rank": f"{summary['candidate_delta_rank']:.6f}",
        "magnitude_ratio": "0.000000",
        "rna_to_image_recall_at_1": f"{summary['mean_rna_to_image_recall_at_1']:.6f}",
        "image_to_rna_recall_at_1": f"{summary['mean_image_to_rna_recall_at_1']:.6f}",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": f"{summary['current_registry_true_delta_rank_ceiling']:.6f}",
        "effective_rank_target": f"{summary['current_registry_transition_floor']:.6f}",
        "collapse_flag": str(not summary["current_registry_rank_supported"]),
        "leakage_flag": str(summary["identity_or_leakage_fail"]),
        "floor_gap_transition": f"{summary['min_candidate_minus_current_floor_transition']:.6f}",
        "floor_gap_recall": f"{summary['min_candidate_minus_current_floor_recall']:.6f}",
        "floor_gap_delta_cosine": f"{summary['min_candidate_minus_current_floor_delta_cosine']:.6f}",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": f"{summary['current_registry_transition_floor']:.6f}",
        "calibration_lcb_recall_gap": f"{summary['current_registry_delta_cosine_floor']:.6f}",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": str(not summary["identity_or_leakage_fail"]),
        "notes": "Current-registry Tier 3 design and validator preflight; no model promotion.",
        "artifact_dir": str(out),
    }


def continue_after_f085_to_f086(args: argparse.Namespace) -> dict[str, Any]:
    f085 = _load_metric_json(args.output_root / "experiments/F085_current_latent_floor_registry/metrics_eval.json")
    trigger = str(f085.get("diagnostic_label", "F085_CURRENT_LATENT_FLOOR_REGISTRY_SUPPORTS_TIER3_WITH_UPDATED_RANK_GATE"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F083", "F084", "F085"])].to_dict("records")
    write_phase_closure(args.output_root, "115", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F086 current-registry Tier 3 design",
            {"novelty": 0.58, "feasibility": 0.98, "identity": 1.00, "effect": 0.88, "falsifiability": 0.96, "leakage": 0.98, "compute": 0.96},
            "Lock representation-specific gates and audit paired validator readiness before any Tier 3 launch.",
        ),
        CouncilProposal(
            "Launch Tier 3 immediately",
            {"novelty": 0.35, "feasibility": 0.55, "identity": 0.72, "effect": 0.45, "falsifiability": 0.60, "leakage": 0.62, "compute": 0.35},
            "Reject because a paired external validator is not locally ingested and rank gates have just been redefined.",
        ),
        CouncilProposal(
            "Train F082 longer",
            {"novelty": 0.18, "feasibility": 0.70, "identity": 0.60, "effect": 0.28, "falsifiability": 0.45, "leakage": 0.78, "compute": 0.22},
            "Reject because F085 identified a validation/gate issue, not an optimization issue.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "115", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f086_current_registry_tier3_design(args.output_root, "115", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "115", trigger, council_path, amendment_path, selected.next_action)
    return run_f086_current_registry_tier3_design(args)


