def continue_after_f086_to_f087(args: argparse.Namespace) -> dict[str, Any]:
    f086 = _load_metric_json(args.output_root / "experiments/F086_current_registry_tier3_design/metrics_eval.json")
    trigger = str(f086.get("diagnostic_label", "F086_CURRENT_REGISTRY_TIER3_READY_EXTERNAL_INGEST_NEEDED"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F085", "F086"])].to_dict("records")
    write_phase_closure(args.output_root, "116", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F087 scGeneScope metadata adapter preflight",
            {"novelty": 0.64, "feasibility": 0.96, "identity": 1.00, "effect": 0.88, "falsifiability": 0.94, "leakage": 0.98, "compute": 0.98},
            "Build a metadata-only adapter contract and local manifest audit for the paired scRNA plus Cell Painting validator.",
        ),
        CouncilProposal(
            "Download full scGeneScope immediately",
            {"novelty": 0.42, "feasibility": 0.20, "identity": 0.72, "effect": 0.82, "falsifiability": 0.60, "leakage": 0.65, "compute": 0.05},
            "Reject because the public listing is hundreds of GB and the protocol requires low compute/storage safety.",
        ),
        CouncilProposal(
            "Use Norman as Tier 3 validator",
            {"novelty": 0.30, "feasibility": 0.92, "identity": 0.48, "effect": 0.40, "falsifiability": 0.70, "leakage": 0.82, "compute": 0.88},
            "Reject as Tier 3 cross-modal validation because Norman is RNA-only in the local processed h5ad.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "116", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f087_scgenescope_adapter_preflight(args.output_root, "116", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "116", trigger, council_path, amendment_path, selected.next_action)
    return run_f087_scgenescope_adapter_preflight(args)


