def _f088_decision_from_summary(summary: dict[str, Any]) -> str:
    if not bool(summary.get("remote_api_accessible", False)):
        return "F088_SCGENESCOPE_REMOTE_API_UNAVAILABLE"
    if bool(summary.get("light_manifest_candidate_found", False)):
        return "F088_SCGENESCOPE_LIGHT_METADATA_FOUND_READY_FOR_MANIFEST_BUILD"
    if bool(summary.get("paired_feature_payloads_found", False)):
        return "F088_SCGENESCOPE_REMOTE_FEATURES_FOUND_BUT_TOO_LARGE_FOR_LOW_COMPUTE"
    return "F088_SCGENESCOPE_REMOTE_TREE_NO_USABLE_VALIDATOR_METADATA"


def run_f088_scgenescope_remote_discovery(args: argparse.Namespace) -> dict[str, Any]:
    out = args.output_root / "experiments/F088_scgenescope_remote_discovery"
    out.mkdir(parents=True, exist_ok=True)
    rows: list[dict[str, Any]] = []
    errors: list[dict[str, str]] = []
    for probe_path in _f088_probe_paths():
        try:
            entries = fetch_huggingface_dataset_tree(path=probe_path, recursive=False, timeout_seconds=30.0)
        except Exception as exc:
            errors.append({"probe_path": probe_path or ".", "error": f"{type(exc).__name__}: {exc}"})
            continue
        for entry in entries:
            entry_row = dict(entry)
            entry_row["probe_path"] = probe_path or "."
            rows.append(entry_row)
    raw_frame = pd.DataFrame(rows)
    if raw_frame.empty:
        summary_frame = pd.DataFrame()
    else:
        summary_frame = summarize_scgenescope_remote_entries(raw_frame.to_dict("records"))
        summary_frame.insert(0, "probe_path", raw_frame["probe_path"].astype(str).to_numpy())
    raw_frame.to_csv(out / "hf_tree_raw.tsv", sep="\t", index=False)
    summary_frame.to_csv(out / "hf_tree_summary.tsv", sep="\t", index=False)
    pd.DataFrame(errors).to_csv(out / "hf_tree_errors.tsv", sep="\t", index=False)

    if summary_frame.empty:
        smallest_rna_feature = 0
        smallest_image_feature = 0
        feature_family_pairs = 0
        light_metadata_count = 0
        large_payload_count = 0
        file_count = 0
        dir_count = 0
    else:
        files = summary_frame[summary_frame["type"] == "file"].copy()
        rna_features = files[(files["modality"] == "rna") & (files["is_feature_h5ad"])]
        image_features = files[(files["modality"] == "image") & (files["is_feature_h5ad"])]
        smallest_rna_feature = int(rna_features["size_bytes"].min()) if not rna_features.empty else 0
        smallest_image_feature = int(image_features["size_bytes"].min()) if not image_features.empty else 0
        feature_family_pairs = int(bool(smallest_rna_feature) and bool(smallest_image_feature))
        light_metadata_count = int(summary_frame["is_light_metadata_candidate"].sum())
        large_payload_count = int(summary_frame["is_large_payload"].sum())
        file_count = int((summary_frame["type"] == "file").sum())
        dir_count = int((summary_frame["type"] == "directory").sum())
    paired_feature_payloads_found = bool(smallest_rna_feature > 0 and smallest_image_feature > 0)
    smallest_paired_feature_bytes = int(smallest_rna_feature + smallest_image_feature) if paired_feature_payloads_found else 0
    summary = {
        "remote_api_accessible": bool(len(rows) > 0),
        "probe_path_count": len(_f088_probe_paths()),
        "remote_entry_count": int(len(rows)),
        "remote_error_count": int(len(errors)),
        "remote_file_count": file_count,
        "remote_directory_count": dir_count,
        "light_manifest_candidate_count": light_metadata_count,
        "light_manifest_candidate_found": bool(light_metadata_count > 0),
        "large_payload_count": large_payload_count,
        "smallest_rna_feature_bytes": smallest_rna_feature,
        "smallest_image_feature_bytes": smallest_image_feature,
        "smallest_paired_feature_bytes": smallest_paired_feature_bytes,
        "smallest_paired_feature_gb": float(smallest_paired_feature_bytes / 1_000_000_000.0),
        "paired_feature_payloads_found": paired_feature_payloads_found,
        "paired_feature_family_pair_count": feature_family_pairs,
        "download_attempted": False,
        "model_promoted": False,
    }
    summary["diagnostic_label"] = _f088_decision_from_summary(summary)
    write_json(out / "metrics_eval.json", summary)
    _write_f088_report(out / "F088_SCGENESCOPE_REMOTE_DISCOVERY.md", summary, summary_frame, pd.DataFrame(errors))
    append_journal(
        args.output_root,
        "F088_SCGENESCOPE_REMOTE_DISCOVERY",
        "Remote scGeneScope metadata discovery",
        (
            f"Decision={summary['diagnostic_label']}; entries={summary['remote_entry_count']}; "
            f"light_metadata={summary['light_manifest_candidate_count']}; "
            f"smallest_paired_feature_gb={summary['smallest_paired_feature_gb']:.3f}; download_attempted=False."
        ),
    )
    return {
        "experiment_id": "F088",
        "phase": "PostPhase8Council",
        "family": "External validator",
        "tier": "RemoteMetadataDiscovery",
        "seed": "NA",
        "dataset": "scGeneScope",
        "eval_split": "heldout_experiment_pending_manifest",
        "mode": "scgenescope_remote_discovery",
        "status_label": summary["diagnostic_label"],
        "transition_improvement": "0.000000",
        "delta_cosine": "0.000000",
        "recall_at_1": "0.000000",
        "median_rank": "0.000000",
        "delta_rank": "0.000000",
        "magnitude_ratio": "0.000000",
        "rna_to_image_recall_at_1": "0.000000",
        "image_to_rna_recall_at_1": "0.000000",
        "z_bio_batch_probe": "0.000000",
        "z_tech_batch_probe": "0.000000",
        "batch_allocation_gap": "0.000000",
        "effective_rank_z_bio": "0.000000",
        "effective_rank_target": "0.000000",
        "collapse_flag": "False",
        "leakage_flag": "False",
        "floor_gap_transition": "0.000000",
        "floor_gap_recall": "0.000000",
        "floor_gap_delta_cosine": "0.000000",
        "selected_residual_scale": "0.000000",
        "calibration_lcb_transition_gap": "0.000000",
        "calibration_lcb_recall_gap": "0.000000",
        "action_negative_gap": "0.000000",
        "context_contract_pass": "True",
        "jepa_identity_pass": "True",
        "notes": "Remote scGeneScope file-tree discovery only; no payload download and no model promotion.",
        "artifact_dir": str(out),
    }


