def continue_after_f091_to_f092(args: argparse.Namespace) -> dict[str, Any]:
    f091 = _load_metric_json(args.output_root / "experiments/F091_scgenescope_feature_preflight/metrics_eval.json")
    trigger = str(f091.get("diagnostic_label", "F091_SCGENESCOPE_FEATURE_PREFLIGHT_APPROVES_BACKED_OBS_ONLY_DRY_RUN"))
    prior_rows: list[dict[str, Any]] = []
    results_path = args.output_root / "results.tsv"
    if results_path.exists():
        results = pd.read_csv(results_path, sep="\t")
        prior_rows = results[results["experiment_id"].astype(str).isin(["F089", "F090", "F091"])].to_dict("records")
    write_phase_closure(args.output_root, "121", trigger, prior_rows)
    proposals = [
        CouncilProposal(
            "F092 scGeneScope obs-only backed dry run",
            {"novelty": 0.58, "feasibility": 0.76, "identity": 1.00, "effect": 0.90, "falsifiability": 0.96, "leakage": 0.96, "compute": 0.58},
            "Download only the F091-approved smallest paired feature files under byte caps, open H5AD obs in backed mode, and verify metadata contracts without fitting or training.",
        ),
        CouncilProposal(
            "Train Tier 3 immediately on scGeneScope",
            {"novelty": 0.42, "feasibility": 0.38, "identity": 0.60, "effect": 0.86, "falsifiability": 0.64, "leakage": 0.54, "compute": 0.20},
            "Reject because no real feature file has been opened and no split/obs contract has been validated on payload metadata.",
        ),
        CouncilProposal(
            "Stay metadata-only forever",
            {"novelty": 0.18, "feasibility": 0.98, "identity": 0.90, "effect": 0.26, "falsifiability": 0.56, "leakage": 0.98, "compute": 1.00},
            "Reject because F091 gates passed and Tier 3 requires a real paired validator preflight.",
        ),
    ]
    decision, selected = council_decision(proposals)
    council_path = write_debate_council(args.output_root, "121", trigger, proposals, decision, selected)
    amendment_path = write_amendment_f092_obs_only_dry_run(args.output_root, "121", trigger, selected)
    append_amendment_to_autoresearch(args.output_root / "autoresearch.md", amendment_path)
    append_autonomy_ledger(args.output_root, "121", trigger, council_path, amendment_path, selected.next_action)
    return run_f092_scgenescope_obs_only_dry_run(args)


def _write_f092_report(path: Path, payload: dict[str, Any], file_frame: pd.DataFrame, obs_summary: pd.DataFrame) -> None:
    summary_tsv = pd.DataFrame([payload]).to_csv(sep="\t", index=False)
    file_tsv = file_frame.to_csv(sep="\t", index=False) if not file_frame.empty else "No file rows.\n"
    obs_tsv = obs_summary.to_csv(sep="\t", index=False) if not obs_summary.empty else "No backed obs summary.\n"
    path.write_text(
        f"""# F092 scGeneScope Obs-Only Backed Dry Run

## Decision
`{payload['diagnostic_label']}`

## Purpose
F091 approved a smallest paired feature dry run under storage/RAM/backed-IO gates. F092 downloads only those two approved feature files if needed, opens them in backed mode, and inspects obs metadata only. It does not train, fit, whiten, calibrate, or promote.

## Key Results
- F091 preflight approved: `{payload['f091_preflight_approved']}`
- Expected paired bytes: `{payload['expected_paired_bytes']}`
- Low-compute cap bytes: `{payload['low_compute_pair_cap_bytes']}`
- Payload cap violation: `{payload['payload_cap_violation']}`
- Status-write reserve OK: `{payload['status_write_reserve_ok']}`
- Payload download attempted: `{payload['payload_download_attempted']}`
- Download/access error: `{payload['download_error']}`
- All expected files present: `{payload['all_expected_files_present']}`
- Backed open error: `{payload['backed_open_error']}`
- Obs contract pass: `{payload['obs_contract_pass']}`
- Shared obs columns: `{payload['shared_obs_columns']}`

## File Status
```tsv
{file_tsv}
```

## Backed Obs Summary
```tsv
{obs_tsv}
```

## Summary Row
```tsv
{summary_tsv}
```

## Decision Use
No model is promoted. A pass only permits the next shape/split audit over backed feature metadata; it does not permit fitting JEPA encoders, transition heads, residual gates, whitening, or target statistics on scGeneScope.
""",
        encoding="utf-8",
    )


def _append_f092_external_resources(root: Path, payload: dict[str, Any], file_frame: pd.DataFrame) -> None:
    path = root / "external_resources.md"
    existing = path.read_text(encoding="utf-8") if path.exists() else "# External Resources\n"
    marker = "## F092 scGeneScope Obs-Only Dry Run"
    if marker in existing:
        return
    file_tsv = file_frame.to_csv(sep="\t", index=False) if not file_frame.empty else "No file rows."
    with path.open("a", encoding="utf-8") as handle:
        handle.write(
            f"""

{marker}

F092 attempted only the F091-approved smallest paired feature dry run under byte caps. It inspected H5AD `obs` metadata in backed mode only and did not train or fit any model.

- decision: `{payload['diagnostic_label']}`
- payload download attempted: `{payload['payload_download_attempted']}`
- all expected files present: `{payload['all_expected_files_present']}`
- obs contract pass: `{payload['obs_contract_pass']}`

```tsv
{file_tsv}
```
"""
        )


def write_amendment_f092_obs_only_dry_run(root: Path, number: str, trigger: str, selected: CouncilProposal) -> Path:
    path = root / f"amendments/SESSION_AMENDMENT_{number}.md"
    text = f"""# Session Amendment {number}: scGeneScope Obs-Only Backed Dry Run

## Trigger
`{trigger}`

## Evidence
F091 found the smallest paired scGeneScope feature footprint is within the registered low-compute cap and the current workspace has enough disk/RAM with `anndata` and `h5py` available. The next step is to prove the actual files can be opened safely in backed mode before any model code touches them.

## Active Model Of Record
Protected rank-3 train-split-only PLS raw-linear readout unless Tier 3 supersedes it.

## New Diagnostic Branch
`F092_SCGENESCOPE_OBS_ONLY_DRY_RUN`

## Implementation Tasks
- Download only the F091-approved smallest RNA and image feature H5AD files if not already local.
- Enforce the F091 byte cap before attempting download.
- Open each H5AD with `backed="r"` and inspect obs metadata only.
- Verify required Croissant-derived obs columns are present in both modalities.
- Do not train, fit encoders, fit calibrators, compute target means, whiten, score JEPA metrics, or promote.

## Decision Use
If F092 passes, run a shape/split/pairing audit on backed feature metadata next. If download/access fails because of license or auth gating, write a hard escalation report. If obs contract fails, return to adapter repair or smaller manifest construction.

## Hard Escalation Check
No hard escalation trigger present before launch.

## Continuation Rule
Ordinary failure triggers another Debate Council. Do not wait for the user.

Council-selected proposal: {selected.name}
"""
    path.write_text(text, encoding="utf-8")
    return path


def default_council_proposals(trigger: str) -> list[CouncilProposal]:
    del trigger
    return [
        CouncilProposal(
            "Family F: bootstrap floor/noise audit",
            {"novelty": 0.70, "feasibility": 0.95, "identity": 0.95, "effect": 0.55, "falsifiability": 0.90, "leakage": 0.90, "compute": 0.95},
            "Run F001_BOOTSTRAP_FLOOR_NOISE_AUDIT before more residual architecture.",
        ),
        CouncilProposal(
            "Family B: stricter abstention gate",
            {"novelty": 0.55, "feasibility": 0.80, "identity": 0.90, "effect": 0.45, "falsifiability": 0.80, "leakage": 0.85, "compute": 0.80},
            "Implement per-action abstention only after noise audit identifies enough signal.",
        ),
        CouncilProposal(
            "Family D: population transport JEPA",
            {"novelty": 0.85, "feasibility": 0.50, "identity": 0.75, "effect": 0.65, "falsifiability": 0.70, "leakage": 0.70, "compute": 0.55},
            "Defer until benchmark noise and prototype coverage are audited.",
        ),
    ]


def council_decision(proposals: list[CouncilProposal]) -> tuple[str, CouncilProposal]:
    selected = max(proposals, key=lambda proposal: proposal.average)
    if selected.average >= 0.65 and selected.minimum >= 0.40:
        return "COUNCIL_EXECUTE", selected
    return "COUNCIL_EXECUTE_METRIC_OR_INTERNAL_AUDIT", selected


def write_debate_council(root: Path, number: str, trigger: str, proposals: list[CouncilProposal], decision: str, selected: CouncilProposal) -> Path:
    path = root / f"councils/debate_council_{number}.md"
    score_rows = "\n".join(
        f"| {proposal.name} | {proposal.average:.3f} | {proposal.minimum:.3f} | {proposal.next_action} |" for proposal in proposals
    )
    text = f"""# Debate Council {number}

## Trigger
`{trigger}`

## Evidence Summary
The current trigger is an ordinary scientific pivot event, not a hard escalation. The protected model of record and protected full-ridge transition floor remain active while the council selects the smallest falsifiable next step.

## Independent Proposals
- Architect: try population-level or safer gated residual mechanisms rather than forcing residual magnitude.
- Skeptic: repeated residual failures suggest benchmark noise or representation/floor saturation, not only predictor weakness.
- Methodologist: audit evaluation variance and held-out perturbation difficulty before spending more training compute.
- Biologist: inspect whether perturbation effects are too small or mean-like in current synthetic anchors.
- Monitor: no hard escalation trigger is present; continue through documented amendment.

## Steelman Of Opposing Proposals
- A stronger predictor could still help if the residual target is learnable but calibration is too conservative.
- Population transport could address mean-like deterministic endpoints, but it is premature before noise/difficulty auditing.

## Three-Round Debate Summary
Round 1 favored predictor repair; Round 2 noted repeated residual overfit; Round 3 selected metric/data redesign as the smallest falsifiable next step.

## Scoring Table
| proposal | average | minimum | next action |
| --- | ---: | ---: | --- |
{score_rows}

## Monitor Decision
`{decision}`

## Exact Next Amendment
Execute `{selected.name}`.

## Next Experiment Command Or Target
`{selected.next_action}`
"""
    path.write_text(text, encoding="utf-8")
    return path


