def append_amendment_to_autoresearch(autoresearch_path: Path, amendment_path: Path) -> None:
    content = amendment_path.read_text(encoding="utf-8")
    first_line = content.splitlines()[0] if content.splitlines() else ""
    if first_line and first_line in autoresearch_path.read_text(encoding="utf-8"):
        return
    with autoresearch_path.open("a", encoding="utf-8") as handle:
        handle.write("\n\n" + content + "\n")


