def ordinary_stop_requires_council(label: str) -> bool:
    ordinary = ("CLOSE", "DISCARD", "FAIL", "NO_SAFE_RESIDUAL", "BELOW_FLOOR")
    hard = label.startswith("HARD_ESCALATE")
    return any(token in label for token in ordinary) and not hard


def write_hard_escalation(root: Path, label: str, reason: str) -> None:
    (root / "HARD_ESCALATION_REPORT.md").write_text(f"# Hard Escalation Report\n\n- label: `{label}`\n- reason: {reason}\n", encoding="utf-8")


def write_json(path: Path, payload: Any) -> None:
    path.write_text(json.dumps(_jsonable(payload), indent=2, sort_keys=True) + "\n", encoding="utf-8")


def _jsonable(value: Any) -> Any:
    if isinstance(value, dict):
        return {str(key): _jsonable(item) for key, item in value.items()}
    if isinstance(value, (list, tuple)):
        return [_jsonable(item) for item in value]
    if isinstance(value, Path):
        return str(value)
    if isinstance(value, np.bool_):
        return bool(value)
    if isinstance(value, (np.floating, np.integer)):
        return value.item()
    if isinstance(value, np.ndarray):
        return value.tolist()
    return value


def _write_if_missing(path: Path, text: str) -> None:
    if not path.exists():
        path.write_text(text, encoding="utf-8")


